const questions = {
insanhak:[
  {q:"İnsan Hakları Evrensel Beyannamesi kaç maddeден oluşur?",opts:["25","28","30","32"],ans:2,exp:"İHEB 10 Aralık 1948'de BM Genel Kurulu'nca Paris'te kabul edilmiş ve 30 maddeden oluşmaktadır. Bağlayıcı değil, tavsiye niteliğinde bir bildirge olup uluslararası insan hakları hukukunun temel kaynağıdır."},
  {q:"Avrupa İnsan Hakları Sözleşmesi hangi yılda yürürlüğe girmiştir?",opts:["1948","1950","1953","1959"],ans:2,exp:"AİHS 4 Kasım 1950'de imzalanmış, 3 Eylül 1953'te yürürlüğe girmiştir. Türkiye Sözleşme'yi 1954'te onaylamıştır."},
  {q:"AİHM'e bireysel başvuru hakkı Türkiye tarafından hangi yılda tanınmıştır?",opts:["1982","1987","1990","1999"],ans:1,exp:"Türkiye bireysel başvuru hakkını 28 Ocak 1987'de tanımıştır. Bu tarihten itibaren Türk vatandaşları Avrupa İnsan Hakları Mahkemesi'ne başvurabilmektedir."},
  {q:"AİHS'e göre hangi hak olağanüstü hallerde dahi askıya alınamaz?",opts:["Mülkiyet hakkı","Adil yargılanma hakkı","İşkence yasağı","Dernek kurma özgürlüğü"],ans:2,exp:"AİHS m.3'te düzenlenen işkence ve insanlık dışı muamele yasağı mutlak bir haktır; savaş ya da olağanüstü hal dahil hiçbir koşulda askıya alınamaz veya sınırlandırılamaz."},
  {q:"'Sivil ve Siyasal Haklar Uluslararası Sözleşmesi' hangi yılda kabul edilmiştir?",opts:["1948","1953","1966","1976"],ans:2,exp:"BM Genel Kurulu tarafından 16 Aralık 1966'da kabul edilmiş, 1976'da yürürlüğe girmiştir. Türkiye bu sözleşmeyi 2003 yılında onaylamıştır."},
  {q:"Avrupa İnsan Hakları Mahkemesi hangi şehirde bulunmaktadır?",opts:["Brüksel","Cenevre","Lahey","Strazburg"],ans:3,exp:"AİHM, Avrupa Konseyi bünyesinde 1959 yılında kurulmuş olup Fransa'nın Strazburg şehrinde faaliyet göstermektedir."},
  {q:"BM İnsan Hakları Yüksek Komiserliği merkezi hangi şehirdedir?",opts:["New York","Viyana","Cenevre","Paris"],ans:2,exp:"BM İnsan Hakları Yüksek Komiserliği merkezi İsviçre'nin Cenevre şehrindedir. 1993'te Viyana Konferansı'nda kurulması kararlaştırılmış, 1994'te faaliyete geçmiştir."},
  {q:"AİHS'te düzenlenen 'adil yargılanma hakkı' hangi maddede yer alır?",opts:["m.3","m.5","m.6","m.8"],ans:2,exp:"Adil yargılanma hakkı AİHS m.6'da düzenlenmiştir. Bağımsız-tarafsız mahkeme, makul süre, aleniyet, masumiyet karinesi ve savunma hakkı bu maddenin güvence altına aldığı başlıca unsurlar arasındadır."},
  {q:"Kişi özgürlüğü ve güvenliği hakkı AİHS'in hangi maddesinde güvence altına alınmıştır?",opts:["m.2","m.3","m.4","m.5"],ans:3,exp:"AİHS m.5 kişi özgürlüğü ve güvenliği hakkını düzenlemektedir. Bu madde, keyfi tutuklamayı yasaklar ve özgürlüğünden yoksun bırakılan kişinin hâkim önüne çıkarılma hakkını güvence altına alır."},
  {q:"Avrupa Konseyi'nin kuruluş yılı ve Türkiye'nin üyelik tarihi nedir?",opts:["1945 – 1945","1949 – 1949","1949 – 1952","1950 – 1953"],ans:1,exp:"Avrupa Konseyi 5 Mayıs 1949'da kurulmuş, Türkiye kurucu üyeler arasında yer alarak aynı yıl üye olmuştur. Konsey merkezi Strazburg'dadır ve 46 üye devleti kapsamaktadır."},
  {q:"Avrupa Konseyi'nin 'Tâcının Mücevheri' olarak nitelendirdiği sözleşme hangisidir? (2025 PAEM)",opts:["Medeni ve Siyasi Haklara Dair Sözleşme","Avrupa İnsan Hakları Sözleşmesi","Avrupa Sosyal Şartı","İşkence Önleme Sözleşmesi"],ans:1,exp:"AİHS, bireysel başvuru mekanizmasıyla Avrupa Konseyi'nin en önemli belgesidir."},
  {q:"John Locke'a göre devletin asıl kuruluş amacı nedir? (2025 PAEM)",opts:["Sınırsız iktidarı pekiştirmek","Hayat, hürriyet ve mülkiyeti korumak","Toplumu savaş düzeninde tutmak","Aristokrasinin ayrıcalıklarını sürdürmek"],ans:1,exp:"Locke: Devlet insanların doğal haklarını korumak için kurulur."},
  {q:"10 Aralık 1948'de ilan edilen bağlayıcı olmayan belge hangisidir? (2025 PAEM)",opts:["Medeni ve Siyasi Haklar Sözleşmesi","AİHS","BM Şartı","İnsan Hakları Evrensel Bildirgesi"],ans:3,exp:"İHEB bağlayıcı değil, tavsiye niteliğindedir."},
  {q:"Mülkiyet hakkı ile ilgili hangisi YANLIŞTIR? (2025 PAEM)",opts:["Kanunla sınırlandırılabilir","Kullanımı toplum yararına aykırı olamaz","Reşit olmayanlar mülkiyet hakkına sahip olamaz","Kamu yararı amacıyla sınırlandırılabilir"],ans:2,exp:"Mülkiyet hakkı herkese aittir; reşit olmama bu hakkı ortadan kaldırmaz."},
  {q:"AİHS m.2 yaşam hakkına göre hangi durum bu hakkın ihlali sayılmaz?",opts:["Devletin kasıtlı öldürmesi","Meşru müdafaa sonucu ölüm","Tutuklu kişinin ihmalen ölümü","İşkence sonucu ölüm"],ans:1,exp:"AİHS m.2: Yaşam hakkı mutlak değildir; meşru müdafaa, kaçışı önleme (orantılı güç) ve isyan bastırma gibi zorunlu ve orantılı güç kullanımı sonucu ölüm hak ihlali sayılmaz. Ancak devletin kasıtlı ya da orantısız güç kullanımı ihlal oluşturur."},
  {q:"AİHS m.8 hangi hakları güvence altına alır?",opts:["İfade ve basın özgürlüğü","Özel hayat, aile hayatı, konut ve haberleşme","Toplanma ve örgütlenme","Din ve vicdan özgürlüğü"],ans:1,exp:"AİHS m.8 özel hayata, aile hayatına, konuta ve haberleşmeye saygı hakkını düzenler. Devlet bu haklara müdahale edemez; müdahale ancak kanunla öngörülmüş, meşru amaç güden ve demokratik toplumda gerekli olan kısıtlamalarla mümkündür."},
  {q:"AİHS m.10 ifade özgürlüğüne getirilebilecek kısıtlamalar için hangisi şart DEĞİLDİR?",opts:["Kanunla öngörülmüş olması","Meşru bir amaç gütmesi","Demokratik toplumda gerekli olması","Mahkeme kararına dayanması"],ans:3,exp:"AİHS m.10/2: İfade özgürlüğü; (1) kanunla öngörülmüş, (2) meşru amaç güden ve (3) demokratik toplumda gerekli olan kısıtlamalarla sınırlandırılabilir. Ayrıca mahkeme kararı zorunlu koşul değildir; idari kararla da sınırlandırılabilir."},
  {q:"Toplanma ve örgütlenme özgürlüğü AİHS'in hangi maddesinde düzenlenmiştir?",opts:["m.9","m.10","m.11","m.12"],ans:2,exp:"AİHS m.11 toplanma özgürlüğü ile sendika ve dernek kurma hakkını güvence altına alır. Silahlı kuvvetler, polis ve devlet idaresi mensuplarına bu hakka kısıtlama getirilebileceği aynı maddede öngörülmüştür."},
  {q:"BM Çocuk Hakları Sözleşmesi hangi yılda kabul edilmiş ve çocuğu kaç yaş altı olarak tanımlar?",opts:["1979 – 15 yaş altı","1989 – 18 yaş altı","1995 – 16 yaş altı","2000 – 18 yaş altı"],ans:1,exp:"BM Çocuk Hakları Sözleşmesi 20 Kasım 1989'da kabul edilmiş, 1990'da yürürlüğe girmiştir. Sözleşme çocuğu '18 yaşından küçük insan' olarak tanımlar. Türkiye 1994'te onaylamıştır."},
  {q:"Kadınlara Karşı Her Türlü Ayrımcılığın Önlenmesi Sözleşmesi'nin (CEDAW) kabul yılı nedir?",opts:["İstanbul Sözleşmesi – 2011","CEDAW – 1979","Pekin Deklarasyonu – 1995","Kahire Programı – 1994"],ans:1,exp:"CEDAW 1979'da BM Genel Kurulu tarafından kabul edilmiştir. Türkiye 1985'te onaylamıştır. 'Kadın anayasası' olarak da anılmakta; ayrımcılığı önlemeye yönelik olumlu tedbirleri de kapsamaktadır."},
  {q:"AİHM'e bireysel başvuruda nihai iç hukuk kararından itibaren başvuru süresi kaçtır?",opts:["3 ay","4 ay","6 ay","1 yıl"],ans:1,exp:"Protokol 15 ile değiştirilen AİHS m.35: AİHM'e bireysel başvuru süresi nihai iç hukuk kararından itibaren 4 aydır (1 Ağustos 2022'den itibaren geçerli; önceki kural 6 aydı). İç hukuk yollarının tüketilmesi de ayrıca zorunludur."},
  {q:"AİHS'e ek 1 No'lu Protokol hangi üç hakkı güvence altına almaktadır?",opts:["Seçim, eğitim, konut","Mülkiyet, eğitim, serbest seçim","Mülkiyet, çalışma, eğitim","Seyahat, mülkiyet, seçim"],ans:1,exp:"AİHS 1 No'lu Protokol (1952): Mülkiyetin korunması (m.1), eğitim hakkı (m.2) ve serbest seçim hakkı (m.3) olmak üzere üç temel hakkı düzenlemektedir. Bu haklar asıl sözleşmede yer almayıp protokolle eklenmiştir."},
  {q:"İşkenceye Karşı BM Sözleşmesi (CAT) hangi yıl yürürlüğe girmiş ve hangi temel ilkeyi içerir?",opts:["1975 – Evrensel cezasızlık","1987 – Non-refoulement (geri göndermeme)","1998 – Diplomatik dokunulmazlık","2000 – Sığınma hakkı"],ans:1,exp:"CAT (Convention Against Torture) 26 Haziran 1987'de yürürlüğe girmiştir. Temel ilkelerinden biri 'non-refoulement' (geri göndermeme): İşkence ya da insanlık dışı muamele göreceği kuvvetle muhtemel bir ülkeye kişi iade edilemez veya sınır dışı edilemez."},
  {q:"AİHM kararlarının icrası hangi organ tarafından denetlenir?",opts:["Avrupa Parlamentosu","AB Adalet Divanı","Avrupa Konseyi Bakanlar Komitesi","BM İnsan Hakları Konseyi"],ans:2,exp:"AİHM kararlarının uygulanması Avrupa Konseyi Bakanlar Komitesi tarafından denetlenir (AİHS m.46/2). Devletler kararı uygulamazsa Komite aleyhine tekrar mahkemeye başvurabilir."},
  {q:"Medeni ve Siyasi Haklar Uluslararası Sözleşmesi Türkiye tarafından hangi yılda onaylanmıştır?",opts:["1976","1989","2003","2010"],ans:2,exp:"Türkiye 'Medeni ve Siyasi Haklar Uluslararası Sözleşmesi'ni 2003 yılında onaylamıştır. Sözleşme BM tarafından 1966'da kabul edilmiş, 1976'da yürürlüğe girmiştir. Türkiye geç onaylayan ülkeler arasındadır."}

  // --- 25 yeni insan hakları sorusu ---
  ,{q:"Avrupa İnsan Hakları Sözleşmesi hangi uluslararası örgütün bünyesinde yer almaktadır?",opts:["Avrupa Birliği","Avrupa Konseyi","NATO","BM"],ans:1,exp:"AİHS, Avrupa Birliği'nin değil, 1949'da kurulan Avrupa Konseyi'nin temel sözleşmesidir. İki örgütün karıştırılmaması kritik önem taşır: AB merkezi Brüksel, Avrupa Konseyi merkezi ise Strazburg'dadır."}
  ,{q:"AİHS m.4'e göre kölelik ve esaret yasağı ne tür bir haktır?",opts:["Sınırlandırılabilen hak","Olağanüstü halde askıya alınabilen hak","Mutlak hak","Protokolle ek güvence altına alınan hak"],ans:2,exp:"AİHS m.4/1: Kölelik ve esaret yasağı mutlak bir haktır; olağanüstü hal dahil hiçbir koşulda askıya alınamaz veya sınırlandırılamaz. Zorunlu çalışma yasağı ise (m.4/2) askerlik, mahkûmiyet ve olağanüstü hal gibi istisnalar içerdiğinden mutlak değildir."}
  ,{q:"AİHS m.7 'kanunsuz ceza olmaz' ilkesi hangi nitelikte bir haktır?",opts:["Sınırlandırılabilen hak","Olağanüstü halde askıya alınabilen hak","Mutlak hak","Yarı-mutlak hak"],ans:2,exp:"AİHS m.7: Kanunsuz suç ve ceza olmaz (nullum crimen, nulla poena sine lege) ilkesi mutlak bir haktır; savaş veya olağanüstü halde dahi askıya alınamaz. Sözleşmenin m.15/2 hükmü m.7'yi askıya alınamayacak mutlak haklar arasında sayar."}
  ,{q:"AİHS m.9 din ve vicdan özgürlüğünün 'iç boyutu' hakkında hangisi doğrudur?",opts:["Devlet tarafından sınırlandırılabilir","Olağanüstü hallerde askıya alınabilir","Mutlak biçimde korunur; hiçbir kısıtlamaya tabi tutulamaz","Yalnızca dinî azınlıklara tanınmıştır"],ans:2,exp:"AİHS m.9: Din ve vicdan özgürlüğü iki boyutludur. İç boyut (forum internum) — yani bir dine inanma veya inanmama — mutlak koruma altındadır; devlet bu alana müdahale edemez. Dini uygulamaları kapsayan dış boyut (forum externum) ise belirli koşullarla sınırlandırılabilir."}
  ,{q:"AİHM Büyük Dairesi kaç hâkimden oluşur?",opts:["7","9","15","17"],ans:3,exp:"AİHM'in yargı oluşumları: Tek hâkim (manifestly inadmissible başvurular), Komite (3 hâkim), Daire (7 hâkim) ve Büyük Daire (17 hâkim). Büyük Daire, emsal niteliğindeki ve Daire kararlarına yönlendirilen davalara bakar. Mahkeme başkanı ve ilgili ülkenin millî hâkimi Büyük Dairede yer alır."}
  ,{q:"Avrupa Konseyi'nin 2024 itibarıyla üye sayısı kaçtır?",opts:["27","40","46","47"],ans:2,exp:"Avrupa Konseyi 2024 itibarıyla 46 üye devletten oluşmaktadır. Rusya, Ukrayna'yı işgali nedeniyle Mart 2022'de Konsey'den ihraç edilmiş; bu nedenle önceki 47 üye sayısı 46'ya düşmüştür. Türkiye 1949'dan bu yana kurucu üyedir."}
  ,{q:"BM İnsan Hakları Konseyi'nin üye sayısı kaçtır ve hangi organ tarafından seçilir?",opts:["54 üye; Güvenlik Konseyi","47 üye; BM Genel Kurulu","35 üye; Ekonomik ve Sosyal Konsey","60 üye; BM Genel Kurulu"],ans:1,exp:"BM İnsan Hakları Konseyi 47 üyeden oluşur ve üyeler BM Genel Kurulu tarafından gizli oyla seçilir. 2006'da eski İnsan Hakları Komisyonu'nun yerini almıştır. Görev süresi 3 yıl olup arka arkaya iki dönemden fazla seçilme yasağı vardır."}
  ,{q:"AİHS m.13 'etkili başvuru hakkı' ne anlama gelir?",opts:["Doğrudan AİHM'e başvurma hakkı","Sözleşmede tanınan hakkın ihlali durumunda ulusal makam önünde etkili başvuru hakkı","Bireysel başvuruyu reddetme hakkı","Yalnızca ceza davalarında geçerli olan savunma hakkı"],ans:1,exp:"AİHS m.13: Sözleşmede güvence altına alınan bir hakkın ihlali halinde ihlali tespit eden ve giderim sağlayan ulusal bir makam önünde etkili başvuru hakkını düzenler. Bu hak, AİHM'e değil, önce ulusal iç hukuk yollarına başvurmayı güvence altına alır."}
  ,{q:"AİHS m.14 ayrımcılık yasağı hakkında hangisi doğrudur?",opts:["Bağımsız bir hak olup tek başına ihlal oluşturabilir","Sözleşmedeki başka bir hakkın kullanımıyla bağlantılı olmalıdır","Yalnızca ırk ayrımcılığını kapsar","Ekonomik ve sosyal haklara uygulanmaz"],ans:1,exp:"AİHS m.14: Ayrımcılık yasağı bağımsız (autonome) bir hak değildir; sözleşmede güvence altına alınan başka bir hakkın kullanımıyla bağlantılı biçimde ihlal oluşturabilir. Protokol 12 ise bağımsız bir ayrımcılık yasağı getirmiştir; ancak Türkiye onu henüz onaylamamıştır."}
  ,{q:"AİHS m.15 uyarınca olağanüstü hallerde bile askıya alınamayacak haklar hangileridir?",opts:["m.2, m.3, m.4/1, m.7","m.3, m.4, m.5, m.6","m.2, m.4, m.6, m.8","m.3, m.5, m.7, m.9"],ans:0,exp:"AİHS m.15/2: Olağanüstü hallerde bile askıya alınamayacak dört mutlak hak: m.2 (yaşam hakkı – ölüm cezasına ilişkin hüküm hariç), m.3 (işkence yasağı), m.4/1 (kölelik yasağı) ve m.7 (kanunsuz ceza olmaz). Diğer haklar savaş veya kamusal tehlike durumunda kısmen askıya alınabilir."}
  ,{q:"AİHS'e Ek 6 No'lu Protokol hangi konuyu düzenler?",opts:["Her koşulda ölüm cezasının kaldırılması","Barış zamanında ölüm cezasının kaldırılması","Çifte yargılanmama ilkesi","Serbest dolaşım hakkı"],ans:1,exp:"AİHS'e Ek 6 No'lu Protokol barış zamanında ölüm cezasını kaldırmaktadır. Savaş veya yakın savaş tehlikesi hâlinde ölüm cezasına istisnaya izin verilmiştir. Ölüm cezasını her koşulda (savaş dahil) kaldıran belge ise 13 No'lu Protokoldür."}
  ,{q:"AİHS'e Ek 13 No'lu Protokol ile 6 No'lu Protokol arasındaki temel fark nedir?",opts:["13 No'lu ölüm cezasını yalnızca barışta kaldırır; 6 No'lu her koşulda","6 No'lu barışta kaldırır; 13 No'lu savaş dahil her koşulda kaldırır","İkisi aynı içeriğe sahiptir","6 No'lu protokol onaylanmamıştır"],ans:1,exp:"6 No'lu Protokol barış zamanı ölüm cezasını kaldırır; savaş ya da yakın savaş tehlikesinde istisna tanır. 13 No'lu Protokol ise savaş durumu da dahil olmak üzere her koşulda ölüm cezasını yasaklar — bu nedenle daha güçlü bir koruma sağlar."}
  ,{q:"AİHS'e Ek 7 No'lu Protokol'de düzenlenen 'ne bis in idem' ilkesi ne anlama gelir?",opts:["Suçsuzluk karinesi","Aynı suçtan iki kez yargılanmama ve cezalandırılmama","Kanunsuz suç ve ceza olmaz","Geri göndermeme ilkesi"],ans:1,exp:"7 No'lu Protokol m.4: Ne bis in idem — aynı devlet yargılamasında, kesinleşmiş bir mahkûmiyet veya beraat kararından sonra aynı kişinin aynı suçtan tekrar yargılanması ya da cezalandırılması yasaktır. Çifte tehlike (double jeopardy) yasağı olarak da bilinir."}
  ,{q:"AİHS m.6 adil yargılanma hakkı kapsamında 'masumiyet karinesi' hangi fıkrada yer alır?",opts:["m.6/1","m.6/2","m.6/3","m.6/4"],ans:1,exp:"AİHS m.6/2: 'Her sanık, suçluluğu yasal olarak ispat edilinceye kadar masum sayılır.' Masumiyet karinesi bu fıkrada güvence altına alınmıştır. m.6/1 genel adil yargılanma ilkesini, m.6/3 ise sanığın asgari savunma haklarını düzenler."}
  ,{q:"AİHM'e bireysel başvuru öncesinde iç hukuk yollarını tüketme yükümlülüğü bakımından hangisi doğrudur?",opts:["Kısmi tüketim yeterlidir","İç hukuk yolları tamamen ve etkin biçimde tüketilmelidir","Başvurulabilecek tek iç yol mahkemeyse tüketme şartı aranmaz","İç hukuk yolları tüketilmeksizin başvurulabilir"],ans:1,exp:"AİHS m.35/1: AİHM'e başvurabilmek için iç hukuk yollarının uluslararası hukukta yerleşik kurallara göre tamamen tüketilmesi zorunludur. Tüketim beklentisinin yeterli bir iç yol sunulmadığı istisnai hallerde bu şart aranmayabilir."}
  ,{q:"Ekonomik, Sosyal ve Kültürel Haklar Uluslararası Sözleşmesi hangi yılda kabul edilmiştir?",opts:["1948","1953","1966","1976"],ans:2,exp:"BM Genel Kurulu tarafından 16 Aralık 1966'da kabul edilen bu sözleşme; çalışma, sosyal güvenlik, eğitim ve kültürel yaşama katılım gibi ekonomik ve sosyal hakları düzenler. Medeni ve Siyasi Haklar Sözleşmesi ile birlikte 'BM İkiz Sözleşmeleri' olarak anılır."}
  ,{q:"AİHS m.4/2'ye göre 'zorunlu çalışma' sayılmayan durumlar arasında hangisi yer alır?",opts:["Grevleri kırmak amacıyla çalıştırma","Olağan vatandaşlık yükümlülükleri","Özel bir kişi lehine zorla çalışma","Borç nedeniyle çalışma"],ans:1,exp:"AİHS m.4/2–3: Mahkûmiyet veya şartlı tahliyede çalıştırma, zorunlu askerlik, olağanüstü hâl/afette alınan tedbirler ve olağan vatandaşlık yükümlülükleri zorunlu çalışma sayılmaz. Grev kırıcı olarak zorlama ve özel kişi lehine çalıştırma bu istisnalar kapsamında değildir."}
  ,{q:"İnsan hakları hukukundaki 'üçüncü kuşak haklar' olarak bilinen kategoriye hangisi girer?",opts:["Medeni ve siyasi haklar","Ekonomik, sosyal ve kültürel haklar","Dayanışma/kolektif haklar (çevre, barış, kalkınma)","Kişisel dokunulmazlık hakları"],ans:2,exp:"Üç kuşak teori: 1. Kuşak — medeni ve siyasi haklar (negatif haklar, devletin çekilmesini gerektirir). 2. Kuşak — ekonomik, sosyal ve kültürel haklar (pozitif yükümlülükler). 3. Kuşak — dayanışma/kolektif haklar: sağlıklı çevreye hak, barış hakkı, kalkınma hakkı. PAEM sınavında kuşak örnekleri sorulmaktadır."}
  ,{q:"'İstanbul Sözleşmesi'nin tam adı ve kabul yılı nedir?",opts:["Kadına Yönelik Şiddetin Önlenmesi ve Ev İçi Şiddetle Mücadele Sözleşmesi – 2011","Kadın ve Çocuk Haklarına İlişkin Avrupa Sözleşmesi – 2010","İstanbul'da imzalanan Aile Koruma Sözleşmesi – 2013","Ev İçi Şiddete Karşı BM Sözleşmesi – 2011"],ans:0,exp:"Kadına Yönelik Şiddetin Önlenmesi ve Ev İçi Şiddetle Mücadele Hakkında Avrupa Konseyi Sözleşmesi, 11 Mayıs 2011'de İstanbul'da imzaya açılmıştır. Türkiye imzacı devletlerin başında yer alarak ilk onaylayan ülkeydi; ancak 2021'de sözleşmeden çekilmiştir."}
  ,{q:"AİHS m.12 evlenme hakkına göre evlenme yaşı kimin tarafından belirlenir?",opts:["Doğrudan AİHS ile 18 yaş olarak belirlenir","Avrupa Konseyi Bakanlar Komitesi tarafından","Her devletin ulusal hukukuna bırakılmıştır","AİHM içtihadıyla 16 yaş olarak belirlenmiştir"],ans:2,exp:"AİHS m.12: Evlenme çağına gelen erkek ve kadınların evlenme ve aile kurma hakkı ulusal yasaların öngördüğü koşullar çerçevesinde güvence altına alınmıştır. Evlenme yaşı sözleşmeyle sabitlenmemiş olup ulusal hukuka bırakılmıştır; bu nedenle ülkeden ülkeye farklılık göstermektedir."}
  ,{q:"'Non-refoulement' (geri göndermeme) ilkesi ağırlıklı olarak hangi sözleşmede düzenlenmiştir?",opts:["AİHS m.3","1951 tarihli Mülteci Statüsüne İlişkin Cenevre Sözleşmesi","BM Çocuk Hakları Sözleşmesi","Medeni ve Siyasi Haklar Sözleşmesi"],ans:1,exp:"Non-refoulement (geri göndermeme) ilkesi esas olarak 1951 tarihli Cenevre Mülteci Sözleşmesi m.33'te düzenlenmiştir: Devletler mülteci veya sığınmacıyı hayatının veya özgürlüğünün tehdit altında olduğu bir ülkeye geri gönderemez. AİHM bu ilkeyi ayrıca m.3 işkence yasağı kapsamında da uygulamaktadır."}
  ,{q:"BM çerçevesinde 'evrensel periyodik inceleme' (Universal Periodic Review) hangi organ tarafından yürütülür?",opts:["Uluslararası Adalet Divanı","BM İnsan Hakları Konseyi","BM Genel Kurulu","BM Güvenlik Konseyi"],ans:1,exp:"Evrensel Periyodik İnceleme (UPR), BM İnsan Hakları Konseyi bünyesinde yürütülen ve tüm BM üyesi devletlerin insan hakları sicilini düzenli aralıklarla (4,5 yılda bir) değerlendiren benzersiz bir mekanizmadır. 2006'da İnsan Hakları Konseyi'nin kurulmasıyla birlikte oluşturulmuştur."}
  ,{q:"Avrupa İnsan Hakları Mahkemesi'nde Türkiye aleyhine en fazla ihlal kararı verilen hak kategorisi hangisidir?",opts:["İşkence yasağı (m.3)","Adil yargılanma hakkı (m.6) ve kişi özgürlüğü (m.5)","Mülkiyet hakkı","Seçim hakkı"],ans:1,exp:"Türkiye, tarihsel olarak AİHM'de en fazla ihlal kararı alan ülkeler arasında yer almaktadır. İhlallerin büyük bölümü adil yargılanma hakkı (m.6) ve kişi özgürlüğü (m.5) alanında yoğunlaşmaktadır. Türkiye bu kararlar nedeniyle milyonlarca Euro tazminat ödemek zorunda kalmıştır."}
  ,{q:"İnsan haklarının felsefi temelini 'kategorik imperatif' kavramıyla açıklayan düşünür kimdir?",opts:["John Locke","Jean-Jacques Rousseau","Immanuel Kant","Thomas Hobbes"],ans:2,exp:"Immanuel Kant, 'kategorik imperatif' ilkesiyle (insanı hiçbir zaman yalnızca araç olarak değil, amaç olarak da gör) insan onurunu ahlâk felsefesinin merkezine oturtmuştur. Bu anlayış modern insan hakları hukukunun temel felsefî dayanağını oluşturmaktadır. Locke ise doğal haklar teorisiyle öne çıkar."}
  ,{q:"AİHS'e Ek 1 No'lu Protokol'de yer alan 'serbest seçim hakkı' devlete ne tür yükümlülük getirir?",opts:["Devletin belirli aralıklarla serbest seçim yapmasını sağlama yükümlülüğü","Vatandaşlara zorunlu oy kullandırma yükümlülüğü","Seçimlerde yüzde elli barajı uygulama yükümlülüğü","Tüm vatandaşlara aday olma hakkı tanıma yükümlülüğü"],ans:0,exp:"AİHS 1 No'lu Protokol m.3: Devletler makul aralıklarla, gizli oyla ve serbest koşullarda yasama organı seçimleri yapmakla yükümlüdür. Bu hak bireysel bir hak olarak seçme ve seçilme haklarını güvence altına alır. Zorunlu oy kullandırma ve belirli baraj yükümlülüğü protokolde yer almaz."}
],
anayasa:[
  {q:"Türkiye Cumhuriyeti Anayasası'na göre devletin temel nitelikleri nelerdir?",opts:["Demokratik, laik, sosyal hukuk devleti","Monarşik, laik, federal devlet","Demokratik, dini, üniter devlet","Cumhuriyetçi, laik, oligarşik devlet"],ans:0,exp:"Anayasa m.2: Türkiye Cumhuriyeti demokratik, lâik ve sosyal bir hukuk devletidir. Bu nitelikler ile Cumhuriyet'in değiştirilemez hükümleri m.4 gereğince teklif dahi edilemez."},
  {q:"Anayasa değişikliği için TBMM'de asgari kaç oy gereklidir?",opts:["251 (salt çoğunluk)","301","360 (beşte üç)","400 (üçte iki)"],ans:2,exp:"Anayasa m.175: Değişiklik teklifi en az beşte üç (360) milletvekili oyuyla kabul edilirse Cumhurbaşkanı'na sunulur. 400 (2/3) oya ulaşılırsa Cumhurbaşkanı referanduma götürmeyebilir."},
  {q:"Temel hak ve özgürlüklerin sınırlandırılmasında aranan koşullar hangi maddede düzenlenmiştir?",opts:["m.10","m.11","m.13","m.17"],ans:2,exp:"Anayasa m.13: Temel hak ve özgürlükler, özlerine dokunulmaksızın yalnızca Anayasa'nın ilgili maddelerinde belirtilen sebeplere bağlı olarak ve ancak kanunla sınırlanabilir."},
  {q:"TBMM kaç milletvekilinden oluşmaktadır?",opts:["450","500","550","600"],ans:3,exp:"2017 anayasa referandumuyla milletvekili sayısı 550'den 600'e çıkarılmış ve 24 Haziran 2018 seçimlerinde ilk kez bu sayıyla seçim yapılmıştır."},
  {q:"Anayasa Mahkemesi bireysel başvuruları ne zaman kabul etmeye başlamıştır?",opts:["2003","2008","2010","2012"],ans:3,exp:"2010 anayasa değişikliğiyle bireysel başvuru yolu açılmış; Anayasa Mahkemesi bireysel başvuruları 23 Eylül 2012 tarihinden itibaren kabul etmeye başlamıştır."},
  {q:"Cumhurbaşkanlığı makamının görev süresi ve dönem sınırı nedir?",opts:["4 yıl, 2 dönem","5 yıl, 2 dönem","6 yıl, 1 dönem","7 yıl, sınırsız"],ans:1,exp:"2017 anayasa değişikliğine göre Cumhurbaşkanı doğrudan halk tarafından seçilir. Görev süresi 5 yıl olup en fazla iki dönem görev yapılabilir."},
  {q:"Anayasa'ya göre temel haklar hangi durumlarda tamamen durdurulabilir?",opts:["Herhangi bir kanun hükmüyle","Sadece savaş halinde","Olağanüstü hal ve savaş hallerinde","Cumhurbaşkanı kararnamesiyle"],ans:2,exp:"Anayasa m.15: Savaş, seferberlik veya olağanüstü hallerde temel haklar kısmen ya da tamamen askıya alınabilir; ancak işkence yasağı, kanunsuz suç olmaz ilkesi gibi mutlak haklar bu hükmün dışındadır."},
  {q:"Anayasa'ya göre 'hukuk devleti' ilkesinin temel gerekliliklerinden biri nedir?",opts:["İdarenin yargı denetimine tabi olmaması","Kanun önünde eşitlik ve idarenin yargısal denetimi","Kanunların yürütme organınca yapılması","Yargı kararlarının bağlayıcı olmaması"],ans:1,exp:"Hukuk devleti ilkesi; idarenin yargısal denetimine tabi olmasını, kanun önünde eşitliği, temel hakların güvence altında bulunmasını ve hukuki güvenliği kapsar."},
  {q:"Türkiye Büyük Millet Meclisi hangi tarihte kurulmuştur?",opts:["19 Mayıs 1919","23 Nisan 1920","29 Ekim 1923","3 Mart 1924"],ans:1,exp:"Türkiye Büyük Millet Meclisi 23 Nisan 1920'de Ankara'da açılmıştır. Bu tarih her yıl Ulusal Egemenlik ve Çocuk Bayramı olarak kutlanmaktadır."},
  {q:"Anayasa m.10 hangi ilkeyi düzenlemektedir?",opts:["Kişi dokunulmazlığı","Eşitlik ilkesi","Özel hayatın gizliliği","Düşünce özgürlüğü"],ans:1,exp:"Anayasa m.10: 'Herkes dil, ırk, renk, cinsiyet, siyasi düşünce… farkı gözetilmeksizin kanun önünde eşittir.' Devlet organları ve idare makamları bu ilkeye uymakla yükümlüdür."},
  {q:"TBMM kaç milletvekilinden oluşmaktadır? (2025 PAEM)",opts:["450","500","550","600"],ans:3,exp:"Anayasa m.75: TBMM 600 milletvekilinden oluşur (2017 değişikliği)."},
  {q:"Cumhuriyetin niteliklerinden biri DEĞİLDİR? (2025 PAEM)",opts:["Federal Devlet","Demokratik Devlet","Sosyal Devlet","Hukuk Devleti"],ans:0,exp:"Türkiye üniter devlettir; federal devlet niteliği yoktur."},
  {q:"Kanuna aykırı elde edilen deliller kullanılabilir mi? (2025 PAEM)",opts:["Savcılık kararıyla evet","Sadece ağır cezalık suçlarda","Mağdurun onayıyla","Hiçbir şekilde kullanılamaz"],ans:3,exp:"Anayasa m.38/6: Kanuna aykırı elde edilen deliller kullanılamaz."},
  {q:"Cumhurbaşkanı salgın hastalıkta olağanüstü hal ilan edebilir, süre en fazla kaçtır? (2025 PAEM)",opts:["15 gün","3 ay","6 ay","1 yıl"],ans:2,exp:"Anayasa m.119: Olağanüstü hal en fazla 6 aydır."}

  ,
  // --- Video'dan eklenen sorular ---
  {q:"Anayasa'nın kaçıncı kısmında sosyal ve ekonomik haklar düzenlenmektedir?",opts:["2. Kısım, 2. Bölüm","2. Kısım, 3. Bölüm","3. Kısım, 3. Bölüm","4. Kısım, 1. Bölüm"],ans:1,exp:"Temel hak ve ödevler Anayasa'nın 2. Kısmında; bu kısım 4 bölümden oluşur. Sosyal ve ekonomik haklar 3. Bölümde, siyasi haklar 4. Bölümde, kişinin hakları 2. Bölümde yer alır."},
  {q:"Anayasa'da inkılap kanunları hangi kısımda düzenlenmektedir?",opts:["3. Kısım","4. Kısım","5. Kısım","7. Kısım"],ans:2,exp:"İnkılap kanunlarına ilişkin hükümler Anayasa'nın 5. Kısım 'Çeşitli Hükümler' bölümünde yer alır. Anayasanın değiştirilme yöntemi ise 7. Kısım 'Son Hükümler'de düzenlenir."},
  {q:"TBMM'de bir kanun teklifinin görüşülebilmesi için gereken toplantı yeter sayısı kaçtır?",opts:["151","200","251","301"],ans:1,exp:"Anayasa m.96: TBMM'de toplantı yeter sayısı üye tam sayısının 1/3'ü olan 200 milletvekilidir. Karar yeter sayısı ise toplantıya katılanların salt çoğunluğu, ancak 151'den az olamaz."},
  {q:"TBMM'de geri gönderilen kanunun Cumhurbaşkanı tarafından yayımlanmak zorunda kalınması için kaç oy gerekir?",opts:["251","276","301","360"],ans:2,exp:"Anayasa m.89: Cumhurbaşkanı tarafından geri gönderilen kanun, TBMM tarafından üye tam sayısının salt çoğunluğu olan 301 oy ile aynen kabul edilirse Cumhurbaşkanı o kanunu yayımlamak zorundadır."},
  {q:"Reddedilen bir kanun teklifi en az ne kadar süre geçmeden yeniden verilemez?",opts:["3 ay","6 ay","1 yasama yılı","1 tam yıl"],ans:3,exp:"Anayasa m.88: Türkiye Büyük Millet Meclisi'nde reddedilmiş olan bir kanun teklifi, red tarihinden itibaren bir tam yıl geçmedikçe aynı yasama döneminde yeniden verilemez. 'Bir yasama yılı' değil 'bir tam yıl' dır."},
  {q:"Aşağıdakilerden hangisi oy kullanamaz?",opts:["Kasıtlı suçtan ceza evinde bulunan hükümlü","Taksirli suçtan hüküm giymiş kişi","Tutuklu kişi","Yurt dışında yaşayan Türk vatandaşı"],ans:0,exp:"Anayasa m.67: Kasıtlı suçlardan hüküm giyip ceza infaz kurumunda bulunanlar oy kullanamaz. Ancak taksirli suçtan hüküm giyenler ve tutuklular oy kullanabilir (tutuklu henüz hüküm giymemiş, masum sayılır)."},
  {q:"Yüksek Seçim Kurulu kaç üyeden oluşur ve üyeleri kimler tarafından seçilir?",opts:["9 asıl 5 yedek; Cumhurbaşkanı tarafından","7 asıl 4 yedek; Yargıtay ve Danıştay tarafından","7 asıl 4 yedek; Cumhurbaşkanı tarafından","11 asıl; TBMM tarafından"],ans:1,exp:"YSK 7 asıl 4 yedek üyeden oluşur (toplam 11, tek sayı). 6 üye Yargıtay'dan, 5 üye Danıştay'dan seçilir. Cumhurbaşkanı YSK'ya üye seçemez; adil seçim ilkesi gereği."},
  {q:"Kamu Başdenetçisi (Ombudsman) kim tarafından seçilir ve görev süresi kaç yıldır?",opts:["Cumhurbaşkanı, 5 yıl","TBMM, 4 yıl","Danıştay, 4 yıl","Anayasa Mahkemesi, 3 yıl"],ans:1,exp:"Anayasa m.74: Kamu Başdenetçisi TBMM tarafından gizli oyla 4 yıllığına seçilir. Seçim usulü TBMM Başkanı seçimiyle aynıdır: 1. ve 2. turda üye tam sayısının 2/3'ü (400), 3. turda salt çoğunluk (301), 4. turda en çok oy alan kazanır."},
  {q:"İşçiler toplu iş sözleşmesinde uyuşmazlık çıkarsa hangi kurula başvurulur?",opts:["Kamu Görevlileri Hakem Kurulu","Yüksek Hakem Kurulu","Danıştay","Anayasa Mahkemesi"],ans:1,exp:"İşçi-işveren uyuşmazlıklarında Yüksek Hakem Kurulu'na başvurulur. Memur ve diğer kamu görevlilerinin toplu sözleşme uyuşmazlıklarında ise Kamu Görevlileri Hakem Kurulu yetkilidir."},
  {q:"Aşağıdakilerden hangisi hem hak hem de ödev niteliğini taşımaz?",opts:["Eğitim ve öğretim","Seçme hakkı","Vergi verme","Vatan hizmeti"],ans:2,exp:"Vergi ödevdir, hak değildir. Eğitim, seçme hakkı (seçilme değil), vatan hizmeti ve çevre hem hak hem ödevdir. Vergi toplama hakkı vatandaşa değil devlete aittir."},
  {q:"Kamulaştırmada bedelin taksitle ödenmesine izin verilen haller için azami taksit süresi kaçtır?",opts:["2 yıl","3 yıl","5 yıl","10 yıl"],ans:2,exp:"Anayasa m.46: Tarım reformu, büyük enerji projeleri, iskan, orman, kıyı ve turizm amaçlı kamulaştırmalarda taksitle ödeme mümkündür; ancak taksit süresi 5 yılı geçemez. Küçük çiftçi kamulaştırılıyorsa yine peşin ödeme zorunludur."},
  {q:"Temel hakları sınırlandıran bir Cumhurbaşkanlığı Kararnamesi hakkında hangisi doğrudur?",opts:["Olağanüstü hallerde çıkarılabilir","Anayasa'ya uygun olması şartıyla geçerlidir","Temel haklar CBK ile sınırlandırılamaz","TBMM onayıyla geçerli hale gelir"],ans:2,exp:"Anayasa m.13: Temel hak ve özgürlükler yalnızca KANUNLA sınırlandırılabilir. Cumhurbaşkanlığı Kararnamesi temel hakları doğrudan sınırlandıramaz; bu sınırlandırma iptal davasına konu olur."}
  ,
  // --- Video 2'den eklenen sorular ---
  {q:"Milletvekili seçilebilmek için en az hangi eğitim düzeyi gereklidir?",opts:["Üniversite mezunu","Lise mezunu","Ortaokul mezunu","İlkokul mezunu"],ans:3,exp:"Anayasa m.76: Milletvekili seçilebilmek için en az ilkokul mezunu olmak yeterlidir. Cumhurbaşkanı için ise üniversite mezuniyeti zorunludur — bu temel bir fark olarak sınavlarda sıkça sorulur."},
  {q:"Milletvekilliğinden seçilmesine rağmen eski görevine kesinlikle geri dönemeyecek olanlar hangileridir?",opts:["Öğretmenler ve akademisyenler","Hakimler, savcılar ve silahlı kuvvet mensupları","Belediye başkanları","Devlet memurları"],ans:1,exp:"Anayasa m.82: Hakimler, savcılar, yüksek yargı organı mensupları ve silahlı kuvvet mensupları milletvekili adayı olabilmek için görevden çekilmek zorundadır. Bu kişiler milletvekilliği sona erse de eski görevlerine dönemezler. Tarafsızlık ilkesi gereği bu kural koyulmuştur."},
  {q:"Boşalan milletvekili koltuk sayısı üye tam sayısının yüzde kaçına ulaşırsa ara seçim zorunlu hale gelir?",opts:["%3","%5","%10","%15"],ans:1,exp:"Anayasa m.82: Boşalan üyeliklerin sayısı üye tam sayısının (600) %5'ini bulduğunda, yani 30 koltuk boşaldığında, üç ay içinde ara seçim kararı alınır. Ara seçim her seçim döneminde yalnızca bir kez yapılabilir."},
  {q:"Genel seçimlere bir yıl kala bir ilin tüm milletvekilleri boşaldıysa ne olur?",opts:["Ara seçim yapılamaz, boş kalır","O il için 1 yıl kuralı uygulanmaz, 90 günden sonraki ilk pazar seçim yapılır","Salt çoğunlukla ara seçim kararı alınır","Cumhurbaşkanı karar verir"],ans:1,exp:"Anayasa m.82: Bir ilin veya seçim çevresinin TBMM'de hiç temsilcisi kalmadıysa, boşalmayı takip eden 90 günden sonraki ilk pazar günü seçim yapılır. Bu durumda genel seçime 1 yıl kalma yasağı uygulanmaz."},
  {q:"Yasama sorumsuzluğu ile yasama dokunulmazlığı arasındaki temel fark nedir?",opts:["Yasama sorumsuzluğu sadece ceza davalarına, dokunulmazlık sadece hukuk davalarına karşı korur","Yasama sorumsuzluğu mutlak ve süreklidir; dokunulmazlık görev süresiyle sınırlıdır ve meclis kaldırabilir","Yasama sorumsuzluğu cumhurbaşkanına ait, dokunulmazlık milletvekillerine aittir","İkisi arasında hukuki fark yoktur"],ans:1,exp:"Yasama sorumsuzluğu (mutlak dokunulmazlık): Kürsüde söylenen sözler için geçerlidir, milletvekilliği bittikten sonra da dava açılamaz, meclis kaldıramaz. Yasama dokunulmazlığı (nisbi dokunulmazlık): Fiiller için geçerlidir, milletvekilliği bitince davalar başlar, meclis basit çoğunlukla kaldırabilir."},
  {q:"Milletvekili dokunulmazlığının kaldırılmasına itiraz için süre ve mercii nedir?",opts:["15 gün, Danıştay","7 gün, Anayasa Mahkemesi","30 gün, Yargıtay","3 gün, Meclis Başkanlığı"],ans:1,exp:"Dokunulmazlığı kaldırılan milletvekili veya başka bir milletvekili 7 gün içinde Anayasa Mahkemesi'ne itirazda bulunabilir. AYM bu itirazı 15 gün içinde kesin olarak karara bağlar. Bu 7+15 günlük süre sınavlarda çok sık sorulur."},
  {q:"Milletvekilinin istifası ne zaman kesinleşir?",opts:["İstifa dilekçesini verdiği anda","Meclis Başkanlığı'na ulaştığı anda","TBMM Genel Kurulu basit çoğunlukla kararı aldığı anda","15 gün içinde itiraz yapılmazsa"],ans:2,exp:"Anayasa m.84: Milletvekili istifa ettiğini beyan etse de milletvekilliği hemen sona ermez. TBMM Genel Kurulu'nun basit çoğunlukla istifayı kabul kararı aldığı anda milletvekilliği sona erer."},
  {q:"Milletvekilinin kesin hüküm giymesi durumunda milletvekilliği nasıl düşer?",opts:["Meclis salt çoğunlukla karar alır","Meclis gizli oyla karar alır","Meclis kararı aranmaz; kesin mahkeme kararı Genel Kurul'a bildirilmesiyle düşer","Cumhurbaşkanı onayıyla düşer"],ans:2,exp:"Anayasa m.84: Kesin hüküm giyme ve kısıtlanma hallerinde milletvekilliği, mahkeme kararının TBMM Genel Kurulu'na bildirilmesiyle kendiliğinden düşer. Meclisin ayrıca oylama yapmasına gerek yoktur. Bu nedenle bu iki halde AYM'ye 7 günlük itiraz yolu da açık değildir."},
  {q:"Cumhurbaşkanı seçilebilmek için gerekli oy oranı nedir?",opts:["Seçmenlerin yarısından fazlası","Kullanılan oyların yarısından fazlası","Geçerli oyların yarısından fazlası","TBMM üye tam sayısının salt çoğunluğu"],ans:2,exp:"Cumhurbaşkanı seçilmek için geçerli oyların salt çoğunluğu (yarısından bir fazlası) aranır. Seçmen sayısı veya kullanılan oy sayısı değil, geçerli oy sayısı esas alınır. Bu ayrım sınavlarda kelime oyunuyla sorulur."},
  {q:"Cumhurbaşkanının geçici yokluğunda (yurt dışı seyahat gibi) yerine kim vekalet eder?",opts:["En yaşlı Cumhurbaşkanı Yardımcısı","Meclis Başkanı","Cumhurbaşkanının görevlendireceği Cumhurbaşkanı Yardımcısı","Başbakan"],ans:2,exp:"Cumhurbaşkanı yokluğunun türü kritik öneme sahiptir: Geçici yokluk (yurt dışı, hastalık) halinde Cumhurbaşkanının görevlendirdiği CB Yardımcısı vekalet eder. Ani/kalıcı boşalma halinde ise en yaşlı CB Yardımcısı görevi devralır."},
  {q:"Bir bakanın Yüce Divan'a sevk edilmesi bakanlık görevini sona erdirir mi?",opts:["Evet, sevk kararı yeterlidir","Hayır, ancak Yüce Divan'da kesin hüküm giymesi gerekir","Soruşturma açılması yeterlidir","TBMM kararıyla görev sona erer"],ans:1,exp:"Anayasa m.106: Yüce Divan'a sevk kararı bakanlığı sona erdirmez; masumiyet karinesi gereği adam hüküm giymeden suçlu sayılamaz. Ancak seçilmeye engel bir suçtan dolayı Yüce Divan'da kesin hüküm giyilirse bakanlık görevi sona erer."},
  {q:"TBMM'de siyasi parti grubu kurabilmek için kaç milletvekili gerekir?",opts:["10","15","20","25"],ans:2,exp:"Anayasa m.95 ve İçtüzük: TBMM'de siyasi parti grubu kurabilmek için en az 20 milletvekili gerekir. Grup kurulabilmesi, Cumhurbaşkanı adayı gösterebilmek için de ayrıca önem taşır."},
  {q:"Cumhurbaşkanlığı Kararnamesiyle 2. Kısmın hangi bölümleri düzenlenebilir?",opts:["1. ve 2. bölümler","Sadece 3. bölüm (sosyal ve ekonomik haklar)","4. bölüm","Tüm bölümler"],ans:1,exp:"Anayasa m.104: 2. Kısmın 1. bölümü (genel hükümler), 2. bölümü (kişinin hakları ve ödevleri) ve 4. bölümü (siyasi haklar) CBK ile düzenlenemez. Yalnızca 3. bölüm olan sosyal ve ekonomik haklar CBK ile düzenlenebilir."},
  {q:"Devlet Denetleme Kurulu (DDK) hangi organları denetleyemez?",opts:["Belediyeleri","Kamu iktisadi teşebbüslerini","Yargı organlarını","Üniversiteleri"],ans:2,exp:"DDK yargı organları dışında tüm kamu kurum ve kuruluşlarını, kamu kurumu niteliğindeki meslek kuruluşlarını ve işçi/işveren kuruluşlarını denetler. Yargı organları DDK'nın denetim alanının dışındadır."},
  {q:"Seçim kanununda yapılan bir değişiklik yürürlüğe girmesinden ne kadar süre sonra seçimlere uygulanabilir?",opts:["3 ay","6 ay","1 yıl","2 yıl"],ans:2,exp:"Anayasa m.67: Seçim kanunlarında yapılan değişiklikler, yürürlüğe girdiği tarihten itibaren 1 yıl geçmedikçe o dönemde yapılacak seçimlere uygulanamaz. Bu kural seçim güvenliğini sağlamak amacıyla konulmuştur."}

  ,
  // --- Video 3'ten eklenen sorular ---
  {q:"Türkiye'deki yüksek mahkemeler aşağıdakilerden hangisidir?",opts:["AYM, Yargıtay, Danıştay, Sayıştay","AYM, Yargıtay, Danıştay, Uyuşmazlık Mahkemesi","AYM, Yargıtay, Danıştay, HSK","AYM, Yargıtay, Danıştay, YSK"],ans:1,exp:"Türkiye'de 4 yüksek mahkeme vardır: Anayasa Mahkemesi, Yargıtay, Danıştay ve Uyuşmazlık Mahkemesi. Sayıştay ve HSK yüksek mahkeme değildir. Askeri Yargıtay ve AYİM 2017 değişikliğiyle kaldırılmıştır."},
  {q:"Kanunların esas bakımından iptali için Anayasa Mahkemesi'ne başvuru süresi kaç gündür ve kimler başvurabilir?",opts:["10 gün — Cumhurbaşkanı ve 1/5 çoğunluk","60 gün — Cumhurbaşkanı, 1/5 çoğunluk ve en fazla üyeli 2 siyasi parti grubu","30 gün — Cumhurbaşkanı ve TBMM başkanı","60 gün — Yalnızca Cumhurbaşkanı"],ans:1,exp:"Kanunların esas bakımından iptali için: Cumhurbaşkanı, TBMM üye tam sayısının 1/5'i (120 MV) ve TBMM'de en fazla üyeye sahip 2 siyasi parti grubu, kararın Resmi Gazete'de yayımlanmasından itibaren 60 gün içinde AYM'ye başvurabilir. Şekil bakımından ise 10 gün ve yalnızca CB ile 1/5 çoğunluk yetkilidir."},
  {q:"Bir mahkeme önüne gelen davada uygulanacak kanunu anayasaya aykırı bulursa ne olur?",opts:["Davayı reddeder","Kanunu kendisi iptal eder","AYM'ye başvurur ve dava 5 ay dondurulur","Savcıya bildirir"],ans:2,exp:"Somut norm denetimi (itiraz yolu/defi): Mahkeme uygulanacak kanun veya CBK'nın anayasaya aykırı olduğunu kendi görürse ya da tarafların talebiyle ciddiye alırsa dosyayı AYM'ye gönderir. AYM 5 ay içinde karar verir; cevap gelmezse red sayılır. Red kararı verilirse aynı madde için 10 yıl tekrar başvurulamaz."},
  {q:"AYM'nin iptal kararları ne zaman yürürlüğe girer?",opts:["Geçmişe yürür, önceki işlemler de geçersiz olur","Resmi Gazete'de yayımlandığı tarihten itibaren","Karar tarihinden 1 yıl sonra","TBMM kararıyla belirlenir"],ans:1,exp:"AYM iptal kararları geçmişe yürümez; Resmi Gazete'de yayımlandığı tarihten itibaren yürürlükten kaldırır. Önceki dönemde bu kanuna dayanarak yapılan işlemler geçerliliğini korur. AYM ayrıca oluşacak hukuki boşluğu önlemek amacıyla iptal hükmünün yürürlüğe girmesini 1 yıla kadar erteleyebilir."},
  {q:"Olağan dönem CBK'ya karşı AYM'de iptal davası açılabilir mi? OHAL CBK için durum nedir?",opts:["Her ikisi için de açılabilir","Her ikisi için de açılamaz","Olağan dönem CBK için açılabilir; OHAL CBK için açılamaz","OHAL CBK için açılabilir; olağan dönem CBK için açılamaz"],ans:2,exp:"Olağan dönemde çıkarılan CBK'ya karşı AYM'de iptal davası açılabilir. Ancak olağanüstü hallerde çıkarılan CBK'ya karşı AYM'de iptal davası açılamaz. Bu temel fark sınavlarda sıkça sorulur."},
  {q:"Anayasa Mahkemesi iptal hükmünü ne kadar süreyle erteleyebilir?",opts:["3 ay","6 ay","1 yıl","2 yıl"],ans:2,exp:"Anayasa m.153: AYM, bir kanun veya CBK'yı iptal ederken, yürürlüğü kaldırmanın doğuracağı hukuki boşluğu önlemek amacıyla iptal hükmünün yürürlüğe girmesini 1 yıla kadar erteleyebilir. Bu süre sınavlarda çok sık sorulmaktadır."},
  {q:"OHAL döneminde çıkarılan CBK'lar TBMM'de görüşülmezse ne olur?",opts:["Cumhurbaşkanı onayıyla geçerliliğini korur","3 ay içinde görüşülmezse kendiliğinden yürürlükten kalkar","6 ay içinde görüşülmezse geçersiz olur","Resmi Gazete'de yeniden yayımlanması gerekir"],ans:1,exp:"OHAL döneminde çıkarılan CBK'lar 3 ay içinde TBMM'de görüşülüp karara bağlanmazsa kendiliğinden yürürlükten kalkar. 1 ay içinde komisyonda görüşülmezse Meclis Başkanlığı doğrudan Genel Kurul gündemine alır."},
  {q:"OHAL döneminde CBK ile hangi haklar düzenlenemez?",opts:["Sosyal ve ekonomik haklar","Siyasi haklar","Sadece kişinin temel özgürlükleri","Çekirdek haklar (yaşam hakkı, masumiyet karinesi, geçmişe yürümeme, düşünceyi açıklamaya zorlanmama)"],ans:3,exp:"Olağan dönemde CBK ile yalnızca 2. Kısım 3. Bölüm (sosyal-ekonomik haklar) düzenlenebilirken, OHAL döneminde çekirdek haklar dışında tüm temel hak ve ödevler düzenlenebilir. Çekirdek haklar: yaşam hakkı, masumiyet karinesi, suç-cezaların geçmişe yürümemesi ve düşünceyi açıklamaya zorlanmama."},
  {q:"Kamu tüzel kişiliği hangi yollarla kurulabilir?",opts:["Yalnızca kanunla","Yalnızca CBK ile","Kanunla veya CBK ile","Cumhurbaşkanlığı kararnameleri dışında kanunla"],ans:2,exp:"Anayasa m.123: Kamu tüzel kişileri kanunla veya Cumhurbaşkanlığı kararnamesiyle kurulabilir. 'Yalnızca kanunla' veya 'yalnızca CBK ile' şeklindeki ifadeler yanlıştır. Her iki yol da mevcuttur."},
  {q:"Aşağıdakilerden hangisinin yönetmelik çıkarma yetkisi vardır?",opts:["Dekan","İl emniyet müdürü","Köy muhtarı","Üniversite rektör yardımcısı"],ans:2,exp:"Yönetmelik çıkarma yetkisi: Cumhurbaşkanı, bakanlıklar ve kamu tüzel kişileri. Köy, kamu tüzel kişiliğine sahiptir; dolayısıyla köy muhtarının yönetmelik çıkarma yetkisi vardır. Dekan üniversiteye bağlıdır; ayrı kamu tüzel kişiliği yoktur. İl emniyet müdürlüğünün de ayrı kamu tüzel kişiliği yoktur."},
  {q:"HSK'nın toplam üye sayısı kaçtır ve yapısı nasıldır?",opts:["11 üye; CB atar","13 üye; 2 doğal üye + 4 CB ataması + 7 TBMM seçimi","15 üye; tamamı CB atar","7 üye; tamamı TBMM seçer"],ans:1,exp:"HSK 13 üyeden oluşur: Adalet Bakanı (başkan) ve Müsteşar (2 doğal üye) + Cumhurbaşkanının atadığı 4 üye + TBMM tarafından seçilen 7 üye (Yargıtay'dan 3, Danıştay'dan 2, YÖK'ten 2). HSK yüksek mahkeme değildir."},
  {q:"Hakimler ve savcılar kaç yaşında emekliye ayrılır?",opts:["60","62","65","70"],ans:2,exp:"Anayasa m.140: Hâkim ve savcılar 65 yaşını doldurunca emekliye ayrılırlar. Ayrıca kendileri istemedikçe bu yaştan önce emekliye ayrılamazlar. Mahkeme kapatılsa bile aylık ve ödeneklerinden yoksun bırakılamazlar (hâkimlik teminatı)."},
  {q:"Sayıştay'ın düzenlilik denetimi hangi iki alt türü kapsar?",opts:["Mali denetim ve performans denetimi","Uygunluk denetimi ve performans denetimi","Mali denetim ve uygunluk denetimi","Etkinlik denetimi ve uygunluk denetimi"],ans:2,exp:"Sayıştay'ın denetim türleri: Düzenlilik denetimi (mali denetim + uygunluk denetimi) ve performans denetimi. Bu ikisi birbirinden farklı denetim türleridir. Ayrıca Sayıştay, siyasi partilerin mali denetimini Anayasa Mahkemesi adına yapar."},
  {q:"MGK gündemini kim belirler?",opts:["Genelkurmay Başkanı","Milli Savunma Bakanı","CB Yardımcısı ve Genelkurmay Başkanının önerileri dikkate alınarak Cumhurbaşkanı","TBMM Milli Güvenlik Komisyonu"],ans:2,exp:"MGK gündemini Cumhurbaşkanı Yardımcısı ve Genelkurmay Başkanının önerileri dikkate alınarak Cumhurbaşkanı belirler. Cumhurbaşkanının katılamadığı toplantılarda MGK, Cumhurbaşkanı Yardımcısının başkanlığında toplanır. MGK teşkilatı CBK ile düzenlenir."},
  {q:"Anayasa değişikliği teklifi için TBMM'de en az kaç milletvekili imzası gerekir?",opts:["100","150","200","300"],ans:2,exp:"Anayasa m.175: Anayasa değişikliği teklifinde bulunabilmek için en az üye tam sayısının 1/3'ü olan 200 milletvekilinin imzası gerekir. Kanun değişikliği için ise tek bir milletvekilinin teklifi yeterlidir."},
  {q:"TBMM'de 375 oyla kabul edilen anayasa değişikliği için Cumhurbaşkanı ne yapabilir?",opts:["Doğrudan onaylar ve yayımlar","Geri gönderir veya zorunlu referanduma sunar (onaylama yetkisi yok)","Sadece AYM'ye dava açabilir","İsteğe bağlı referanduma sunabilir veya onaylar"],ans:1,exp:"360-399 arası (3/5 ile 2/3 arasında) kabul: Cumhurbaşkanının onaylama yetkisi yoktur. Ya geri gönderir ya da referanduma sunar (zorunlu referandum). 400 ve üzeri (2/3): CB onaylayabilir, geri gönderebilir veya ihtiyari referanduma sunabilir."},
  // --- Anayasa Ek Sorular ---
  {q:"Milli Güvenlik Kurulu'nda (MGK) hangi bakanlar yer alır?",opts:["Yalnızca Milli Savunma Bakanı","Adalet, Milli Savunma, İçişleri ve Dışişleri Bakanları","Tüm kabine üyeleri","Yalnızca güvenlikle ilgili bakanlar"],ans:1,exp:"Anayasa m.118: MGK; Cumhurbaşkanı başkanlığında, CB Yardımcıları, Adalet Bakanı, Milli Savunma Bakanı, İçişleri Bakanı, Dışişleri Bakanı ile Genelkurmay Başkanı, Kara, Deniz, Hava Kuvvetleri ve Jandarma Genel Komutanlarından oluşur. MGK'nın kararları Cumhurbaşkanı'na tavsiye niteliğindedir."},
  {q:"TBMM'nin kendi kararıyla seçimlerin yenilenmesine karar verebilmesi için gereken oy sayısı nedir?",opts:["251 (salt çoğunluk)","301","360 (beşte üç)","400 (üçte iki)"],ans:2,exp:"Anayasa m.77: TBMM, üye tam sayısının 3/5'i olan 360 oyla seçimlerin yenilenmesine karar verebilir. Bu durumda CB seçimi de aynı günde yenilenir. Cumhurbaşkanı da tek taraflı olarak TBMM seçimini yenileyebilir; ancak CB bu yetkiyi kullanırsa kendi görevi de sona erer."},
  {q:"Seçim kararının Resmî Gazete'de yayımlanmasından sonra seçimler en erken ne zaman yapılır?",opts:["30. günden sonraki ilk pazar","45. günden sonraki ilk pazar","60. günden sonraki ilk pazar","90. günden sonraki ilk pazar"],ans:2,exp:"Anayasa m.77: Seçim kararının Resmî Gazete'de yayımlandığı tarihten itibaren 60. günden sonraki ilk Pazar günü seçim yapılır. '60. günden sonraki ilk pazar' formülü sınavda sıkça sorulur; sadece '60. gün' değil, 60. günden sonraki ilk pazardır."},
  {q:"Olağanüstü hal ilan edildikten sonra TBMM tarafından uzatılabilecek azami süre her defasında kaçtır?",opts:["1 ay","2 ay","4 ay","6 ay"],ans:2,exp:"Anayasa m.119: Cumhurbaşkanı OHAL'i en fazla 6 ay süreyle ilan edebilir. TBMM ise bu süreyi her defasında 4 ayı geçmemek üzere uzatabilir. 'CB ilanı max 6 ay — TBMM uzatması her defasında max 4 ay' kuralı sınavlarda çok sık sorulmaktadır."},
  {q:"Milletlerarası antlaşmaların onaylanması için hangi usul izlenir?",opts:["Cumhurbaşkanlığı kararnamesiyle onaylanır","TBMM uygun bulma kanunu çıkarır; ardından Cumhurbaşkanı onaylar","Yalnızca Cumhurbaşkanı imzasıyla yürürlüğe girer","Danıştay onayıyla yürürlüğe girer"],ans:1,exp:"Anayasa m.90: Milletlerarası antlaşmaların onaylanması TBMM'nin uygun bulmasına bağlıdır. TBMM uygun bulma kanunu çıkarır, ardından Cumhurbaşkanı antlaşmayı onaylar. Usulüne göre yürürlüğe giren antlaşmalar kanun hükmündedir ve Anayasa'ya aykırılık iddiasıyla AYM'ye götürülemez."},
  {q:"Usulüne göre onaylanmış bir milletlerarası antlaşma ile iç hukuktaki kanun çelişirse temel haklara ilişkin ise ne uygulanır?",opts:["Kanun uygulanır, kanun sonraki tarihli ise","Antlaşma uygulanır","Cumhurbaşkanı hangisini seçerse o uygulanır","Danıştay karar verir"],ans:1,exp:"Anayasa m.90/son fıkra (2004 değişikliği): Temel hak ve özgürlüklere ilişkin milletlerarası antlaşmalar ile kanunların aynı konuyu farklı düzenlemesi hâlinde antlaşma hükümleri esas alınır. Bu son fıkra sonradan kanunla değiştirme ihtimaline karşı ek güvence sağlar."},
  // --- Anayasa Ek Sorular ---
  {q:"Anayasa m.74/4 kapsamında kurulan ve TBMM'ye bağlı faaliyet gösteren bağımsız denetim organı hangisidir?",opts:["Sayıştay","Kamu Denetçiliği Kurumu (Ombudsman)","Danıştay","Radyo ve Televizyon Üst Kurulu"],ans:1,exp:"Kamu Denetçiliği Kurumu (Ombudsman), TBMM'ye bağlı bağımsız bir kurumdur. İdarenin eylem, işlem ve tutumlarını başvuru üzerine insan hakları açısından inceler. Kararları bağlayıcı değil tavsiye niteliğindedir; 2012 yılında faaliyete geçmiştir."},
  {q:"Anayasa m.160'a göre Sayıştay'ın temel görevi nedir?",opts:["İdari uyuşmazlıklara bakmak","Merkezi yönetim bütçesi kapsamındaki kamu idarelerinin gelir, gider ve mallarını TBMM adına denetleyerek hesap yargılaması yapmak","Kamu görevlilerini ceza yargılamasında yargılamak","Kanunların Anayasa'ya uygunluğunu denetlemek"],ans:1,exp:"Anayasa m.160: Sayıştay, merkezi yönetim bütçesi kapsamındaki kamu idareleri ile sosyal güvenlik kurumlarının bütün gelir ve giderleri ile mallarını TBMM adına denetler; kesin hesap kanun teklifini inceler. Kararları idare mahkemesi sıfatıyla kesindir."},
  {q:"Anayasa m.69'a göre siyasi partinin temelli kapatılmasına karar verebilmek için Anayasa Mahkemesi'nde gereken çoğunluk nedir?",opts:["Salt çoğunluk (8/15)","Beşte üç (9/15)","Üçte iki (10/15)","Oybirliği (15/15)"],ans:2,exp:"Anayasa m.69/5: Siyasi partinin temelli kapatılmasına AYM üye tam sayısının 2/3'ü (10/15) ile karar verilir. Bu eşiğe ulaşılamazsa salt çoğunluk (8/15) ile devlet yardımından yoksun bırakma kararı verilebilir. Dava Yargıtay Cumhuriyet Başsavcısı tarafından açılır."},
  {q:"Anayasa m.104/17'ye göre Cumhurbaşkanlığı kararnamesiyle hangi alanda düzenleme yapılamaz?",opts:["Cumhurbaşkanlığına bağlı kurul ve ofisler","Bakanlıkların kurulması ve kaldırılması","Temel haklar, kişi hakları ve siyasi haklar","Millî güvenlik politikaları"],ans:2,exp:"Anayasa m.104/17: CB kararnameleriyle Anayasa'da münhasıran kanunla düzenlenmesi öngörülen konular ile temel haklar, kişi hakları ve ödevler ile siyasi haklar ve ödevler alanında düzenleme yapılamaz. Ayrıca kanunla açıkça düzenlenen konularda CB kararnamesi çıkarılamaz."},
  {q:"2017 Anayasa değişikliğiyle milletvekili seçilme yaşı kaça indirilmiştir?",opts:["21","23","25'ten 18'e","30'dan 25'e"],ans:2,exp:"2017 yılında referandumla kabul edilen anayasa değişikliğiyle milletvekili seçilme yaşı 25'ten 18'e indirilmiştir. Oy kullanma (seçme) yaşı ise 1987'den bu yana 18'de sabit olup değiştirilmemiştir."},
  {q:"Anayasa Mahkemesi'ne kanun iptali için dava açma süresi ne kadardır?",opts:["30 gün","60 gün","90 gün","6 ay"],ans:1,exp:"Anayasa m.151: İptal davası, kanunun Resmî Gazete'de yayımlanmasından itibaren 60 gün içinde açılmalıdır. Bu süre geçtikten sonra iptal davası açılamaz; ancak belirli koşullarda somut norm denetimiyle AYM önüne getirilebilir."},
  {q:"Anayasa m.53'e göre kamu görevlilerinin toplu sözleşme hakkıyla ilgili aşağıdakilerden hangisi doğrudur?",opts:["Kamu görevlilerine grev hakkı tanınmıştır","Toplu sözleşme anlaşmazlığı Kamu Görevlileri Hakem Kurulu'nca kesin olarak karara bağlanır","Toplu sözleşme sonuçları Bakanlar Kurulu onayına tabidir","Kamu görevlileri toplu sözleşme yapamaz"],ans:1,exp:"Anayasa m.53: Kamu görevlileri toplu sözleşme yapabilir. Anlaşmazlık hâlinde uyuşmazlık Kamu Görevlileri Hakem Kurulu'na taşınır ve bu kurulun kararı kesindir. Anayasa kamu görevlilerine grev hakkı tanımamaktadır."},
  {q:"Anayasa m.83/2'ye göre yasama dokunulmazlığının kaldırılması için TBMM'de gereken çoğunluk nedir?",opts:["Üçte iki (400 oy)","Beşte üç (360 oy)","Salt çoğunluk (301 oy)","Oy birliği (600 oy)"],ans:2,exp:"Anayasa m.83/2: Bir milletvekilinin yasama dokunulmazlığının kaldırılmasına TBMM salt çoğunluğuyla (301 oy) karar verilebilir. Kaldırılan dokunulmazlık nedeniyle yargılanan ve mahkûm olan milletvekilinin üyeliği kendiliğinden sona ermez; ancak bu durum seçilmeye engel olabilir."},
  {q:"Anayasa m.13'e göre temel hak sınırlamalarında 'özüne dokunma yasağı' ne anlama gelir?",opts:["Temel haklar hiçbir koşulda sınırlandırılamaz","Sınırlama hakkı kullanılamaz kılacak ölçüde olamaz; hakkın özü her zaman korunmalıdır","Yalnızca mülkiyet hakkının özüne dokunulamaz","Sınırlama yalnızca kanun hükmünde kararname ile yapılabilir"],ans:1,exp:"Anayasa m.13: Temel hak ve özgürlükler ancak kanunla ve Anayasa'da öngörülen nedenlere dayanılarak sınırlandırılabilir. Bu sınırlamalar hakkın özüne dokunamaz, ölçülülük ilkesine ve demokratik toplum düzeninin gereklerine aykırı olamaz."},
  {q:"TBMM Başkanı seçimiyle ilgili aşağıdakilerden hangisi doğrudur?",opts:["TBMM Başkanı 5 yıllık yasama dönemi için bir kez seçilir","TBMM Başkanı 2 yıllık dönemler için seçilir ve bir yasama döneminde en fazla 2 kez seçilebilir","TBMM Başkanı Cumhurbaşkanı tarafından atanır","TBMM Başkanı seçimi salt çoğunlukla ilk turda yapılabilir"],ans:1,exp:"Anayasa m.94: TBMM Başkanı yasama döneminin başında 2 yıllık dönemler halinde gizli oyla seçilir; bir yasama döneminde en fazla iki kez seçilebilir. İlk iki turda üçte iki, üçüncü turda salt çoğunluk, dördüncü turda ise en çok oy alan iki aday arasında seçim yapılır."},
  {q:"Anayasa m.67'ye göre seçim kanunları düzenlenirken hangi iki ilkenin gözetilmesi zorunludur?",opts:["Eşitlik ve laiklik","Temsilde adalet ve yönetimde istikrar","Katılımcılık ve çoğulculuk","Orantılılık ve ölçülülük"],ans:1,exp:"Anayasa m.67/6: Seçim kanunları, temsilde adalet ve yönetimde istikrar ilkelerini bağdaştıracak biçimde düzenlenir. Seçim barajı ve seçim çevresine ilişkin kurallar bu iki ilkenin dengelenmesi doğrultusunda kanun koyucunun takdir yetkisindedir."},
  {q:"Anayasa m.159'a göre Hâkimler ve Savcılar Kurulu'nun (HSK) yapısı nasıldır?",opts:["7 üyeden oluşur; Adalet Bakanı başkandır","13 üyeden oluşur; Adalet Bakanı tabii başkan, 4 üye Cumhurbaşkanı, 7 üye TBMM tarafından seçilir","15 üyeden oluşur; tamamı yargı kökenlidir","10 üyeden oluşur; Adalet Bakanlığı tarafından belirlenir"],ans:1,exp:"Anayasa m.159: HSK 13 üyeden oluşur. Adalet Bakanı kurulun tabii başkanıdır. 4 üye Cumhurbaşkanı, 7 üye ise TBMM tarafından seçilir. Kurul, hâkim ve savcıların mesleğe kabul, atama, nakil, terfi ve disiplin işlemlerini yürütür."}
],
inkılap:[
  {q:"Türkiye Cumhuriyeti hangi tarihte ilan edilmiştir?",opts:["23 Nisan 1920","1 Kasım 1922","29 Ekim 1923","3 Mart 1924"],ans:2,exp:"Türkiye Cumhuriyeti 29 Ekim 1923 tarihinde ilan edilmiş ve Mustafa Kemal Atatürk ilk Cumhurbaşkanı seçilmiştir."},
  {q:"Halifeliğin kaldırılmasına ilişkin kanun kaç sayılıdır ve hangi tarihte çıkarılmıştır?",opts:["308 sayılı – 1922","431 sayılı – 3 Mart 1924","677 sayılı – 1925","743 sayılı – 1926"],ans:1,exp:"Halifelik 3 Mart 1924 tarihli ve 431 sayılı Kanun ile kaldırılmıştır. Aynı gün Şeriye ve Evkaf Vekâleti de lağvedilmiştir."},
  {q:"Harf İnkılabı hangi tarihte resmi olarak yürürlüğe girmiştir?",opts:["29 Ekim 1927","1 Kasım 1928","3 Mart 1928","23 Nisan 1929"],ans:1,exp:"Latin harflerine geçişi öngören kanun 1 Kasım 1928'de kabul edilmiş; yeni Türk harfleri 3 Kasım 1928'de Resmî Gazete'de yayımlanarak yürürlüğe girmiştir."},
  {q:"Türk Medeni Kanunu hangi yılda yürürlüğe girmiştir?",opts:["1924","1926","1928","1930"],ans:1,exp:"4 Ekim 1926'da yürürlüğe giren Türk Medeni Kanunu İsviçre Medeni Kanunu esas alınarak hazırlanmıştır. Tek eşli evlilik, miras eşitliği ve laikleşme sürecinin temel yasal dayanağı olmuştur."},
  {q:"Kadınlara milletvekili seçme ve seçilme hakkı hangi yılda verilmiştir?",opts:["1930","1932","1934","1938"],ans:2,exp:"Türk kadınları 1930'da belediye seçimlerinde, 5 Aralık 1934'te ise milletvekili seçme ve seçilme hakkı kazanmıştır. Türkiye bu alanda pek çok Avrupa ülkesinden önde yer almaktadır."},
  {q:"Lozan Antlaşması hangi tarihte imzalanmıştır?",opts:["30 Ekim 1918","11 Ekim 1922","24 Temmuz 1923","29 Ekim 1923"],ans:2,exp:"Lozan Barış Antlaşması 24 Temmuz 1923'te imzalanmış; Türkiye'nin bağımsızlığı ve sınırları uluslararası alanda tanınmıştır. Kapitülasyonlar kaldırılmış, nüfus mübadelesi hükümleri düzenlenmiştir."},
  {q:"Atatürk'ün 'Altı Ok' olarak bilinen ilkeleri Anayasa'ya hangi yılda girmiştir?",opts:["1924","1930","1937","1945"],ans:2,exp:"Cumhuriyetçilik, Milliyetçilik, Halkçılık, Devletçilik, Laiklik ve Devrimcilik ilkeleri 1937 yılında Anayasa'ya eklenmiştir. Bu ilkeler 'Kemalizm' veya 'Atatürkçülük' olarak da bilinmektedir."},
  {q:"Türkiye'de çok partili siyasi hayata geçiş hangi seçimle fiilen gerçekleşmiştir?",opts:["1923","1938","1946","1950"],ans:3,exp:"1950 seçimlerinde Demokrat Parti iktidarı kazanmış; bu seçim Türk siyasi tarihinde ilk gerçek iktidar değişimi olarak kabul edilmektedir. Çok partili deneme 1946'da başlamış olsa da gerçek rekabetli ortam 1950'de sağlanmıştır."},
  {q:"Mondros Mütarekesi hangi tarihte imzalanmıştır?",opts:["18 Mart 1915","30 Ekim 1918","10 Ağustos 1920","24 Temmuz 1923"],ans:1,exp:"Mondros Mütarekesi 30 Ekim 1918'de Osmanlı Devleti ile İtilaf Devletleri arasında imzalanmıştır. Bu mütareke ile Osmanlı'nın I. Dünya Savaşı'ndaki yenilgisi resmen kabul edilmiş ve İşgal dönemi başlamıştır."},
  {q:"İstiklal Marşı hangi tarihte kabul edilmiştir?",opts:["23 Nisan 1920","12 Mart 1921","29 Ekim 1923","1 Kasım 1928"],ans:1,exp:"İstiklal Marşı Mehmet Akif Ersoy tarafından kaleme alınmış ve 12 Mart 1921'de TBMM tarafından Türkiye Cumhuriyeti'nin millî marşı olarak kabul edilmiştir."},
  {q:"I-Soyadı K., II-Harf İnkılabı, III-Şapka K., IV-Medeni K. doğru kronoloji nedir? (2025 PAEM)",opts:["I-II-IV-III","I-III-II-IV","III-I-IV-II","III-IV-II-I"],ans:3,exp:"Doğru sıra: Şapka Kanunu (25 Kasım 1925) → Medeni Kanun (4 Ekim 1926) → Harf Devrimi (1 Kasım 1928) → Soyadı Kanunu (21 Haziran 1934). '25-26-28-34' şeklinde ezberlemek kolaylaştırır."},
  {q:"Millî cemiyetlerin 'Anadolu ve Rumeli Müdafaa-i Hukuk Cemiyeti' olarak birleştiği kongre? (2025 PAEM)",opts:["Nazilli Kongresi","Alaşehir Kongresi","Balıkesir Kongresi","Sivas Kongresi"],ans:3,exp:"Sivas Kongresi (4-11 Eylül 1919): Tüm millî cemiyetler 'Anadolu ve Rumeli Müdafaa-i Hukuk Cemiyeti' adıyla tek çatı altında birleştirildi. Mustafa Kemal başkan seçildi; manda ve himaye kesinlikle reddedildi. Erzurum Kongresi ise yalnızca doğu illerini kapsıyordu."},
  {q:"Kurtuluş Savaşı'nın amacını ilk ortaya koyan belge hangisidir? (2025 PAEM)",opts:["Samsun Raporu","Erzurum Kongresi Kararları","Amasya Genelgesi","Sivas Kongresi Kararları"],ans:2,exp:"Amasya Genelgesi (22 Haziran 1919): Kurtuluş Savaşı'nın ilk yazılı bildirisi ve plan belgesidir. 'Vatanın bütünlüğü, milletin istiklali tehlikededir' cümlesiyle tehlikeyi ilan etti ve Sivas'ta kongre toplanması çağrısında bulundu. Samsun Raporu resmi bir planlama belgesi değil, durum tespitiydi."},
  {q:"TBMM Başkomutanlık yetkisini hangi muharebeden sonra Atatürk'e verdi? (2025 PAEM)",opts:["Kütahya-Eskişehir","Birinci İnönü","Sakarya","İkinci İnönü"],ans:0,exp:"Kütahya-Eskişehir Muharebeleri (Temmuz 1921) sonrasında Türk kuvvetleri geriledi. TBMM 5 Ağustos 1921'de Başkomutanlık yetkisini 3 aylığına Mustafa Kemal'e devretti. Akabinde Sakarya Meydan Muharebesi (23 Ağustos – 13 Eylül 1921) kazanıldı; Mustafa Kemal'e 'Gazi' unvanı ve 'Mareşal' rütbesi verildi."}

  ,
  {q:"Kurtuluş Savaşı'nın hukuki dayanağını oluşturan 'Misak-ı Millî' ne zaman kabul edildi?",opts:["28 Ocak 1920","19 Mayıs 1919","23 Nisan 1920","10 Ağustos 1920"],ans:0,exp:"Misak-ı Millî (Millî Ant) 28 Ocak 1920'de son Osmanlı Meclis-i Mebusanı tarafından kabul edildi. Türk milletinin kendi kaderini belirleme hakkını ve vazgeçilmez toprak taleplerini ortaya koydu."},
  {q:"Türkiye Büyük Millet Meclisi hangi tarihte açıldı?",opts:["19 Mayıs 1919","23 Nisan 1920","30 Ağustos 1922","29 Ekim 1923"],ans:1,exp:"TBMM 23 Nisan 1920'de Ankara'da açıldı. Bu tarih millî egemenliğin sembolü olarak her yıl Ulusal Egemenlik ve Çocuk Bayramı olarak kutlanır."},
  {q:"Mudanya Ateşkes Antlaşması hangi tarihte imzalandı ve ne anlama gelir?",opts:["30 Ağustos 1922 — Büyük Taarruz zaferi","11 Ekim 1922 — Kurtuluş Savaşı'nda ateşkes","24 Temmuz 1923 — Barış antlaşması","1 Kasım 1922 — Saltanatın kaldırılması"],ans:1,exp:"Mudanya Ateşkes Antlaşması 11 Ekim 1922'de imzalandı. Yunanistan, İngiltere, Fransa ve İtalya ile yapılan bu antlaşmayla Doğu Trakya ve İstanbul Türkiye'ye bırakıldı. Lozan görüşmelerinin önünü açtı."},
  {q:"Lozan Barış Antlaşması hangi tarihte imzalandı?",opts:["11 Ekim 1922","29 Ekim 1923","24 Temmuz 1923","3 Mart 1924"],ans:2,exp:"Lozan Barış Antlaşması 24 Temmuz 1923'te imzalandı. Türkiye Cumhuriyeti'nin uluslararası arenada tanınmasını sağladı. Kapitülasyonlar kaldırıldı, sınırlar belirlendi, Yunanistan ile nüfus mübadelesi öngörüldü."},
  {q:"Cumhuriyet hangi tarihte ilan edildi ve ilk Cumhurbaşkanı kimdir?",opts:["23 Nisan 1920 — Mustafa Kemal","29 Ekim 1923 — Mustafa Kemal","3 Mart 1924 — İsmet İnönü","1 Kasım 1922 — Mustafa Kemal"],ans:1,exp:"Türkiye Cumhuriyeti 29 Ekim 1923'te ilan edildi. Mustafa Kemal Atatürk TBMM tarafından oybirliğiyle ilk Cumhurbaşkanı seçildi. Bu tarih her yıl Cumhuriyet Bayramı olarak kutlanır."},
  {q:"Saltanat hangi tarihte kaldırıldı?",opts:["29 Ekim 1923","3 Mart 1924","1 Kasım 1922","24 Temmuz 1923"],ans:2,exp:"Saltanat 1 Kasım 1922'de kaldırıldı. TBMM bu kararla hilafeti saltanattan ayırdı ve Osmanlı padişahlığına son verdi. Son padişah VI. Mehmed Vahideddin ülkeyi terk etti."},
  {q:"Halifelik hangi tarihte kaldırıldı?",opts:["1 Kasım 1922","29 Ekim 1923","3 Mart 1924","30 Ağustos 1922"],ans:2,exp:"Halifelik 3 Mart 1924'te kaldırıldı. Aynı tarihte Şer'iye Mahkemeleri ve Erkan-ı Harbiye-i Umumiye Vekâleti de kaldırıldı. Bu tarih laikleşme sürecinin önemli adımlarından biridir."},
  {q:"Atatürk'ün 6 ilkesi (CHP'nin 1935 programına giren) hangileridir?",opts:["Cumhuriyetçilik, milliyetçilik, halkçılık, devletçilik, laiklik, inkılâpçılık","Cumhuriyetçilik, milliyetçilik, halkçılık, sosyalizm, laiklik, modernleşme","Milliyetçilik, laiklik, sosyalizm, halkçılık, cumhuriyetçilik, barışçılık","Cumhuriyetçilik, laiklik, halkçılık, liberalizm, milliyetçilik, kalkınmacılık"],ans:0,exp:"Atatürk'ün 6 ilkesi (Altı Ok): Cumhuriyetçilik, Milliyetçilik, Halkçılık, Devletçilik, Laiklik ve İnkılâpçılık'tır. 1937'de Anayasa'ya girdi. Türk Bayrağı'ndaki 6 okla simgelenir."},
  {q:"Tekke ve zaviyelerin kapatılması hangi yılda gerçekleşti?",opts:["1922","1924","1925","1928"],ans:2,exp:"Tekke, zaviye ve türbeler 30 Kasım 1925'te çıkarılan kanunla kapatıldı. Aynı yıl kıyafet devrimi (şapka kanunu) da hayata geçirildi. Bu adımlar laikleşme sürecinin temel taşlarıdır."},
  {q:"Medeni Kanun hangi yılda yürürlüğe girdi ve hangi ülkenin kanunundan uyarlandı?",opts:["1924 — Fransız Medeni Kanunu","1926 — İsviçre Medeni Kanunu","1928 — Alman Medeni Kanunu","1930 — İtalyan Medeni Kanunu"],ans:1,exp:"Türk Medeni Kanunu 1926'da yürürlüğe girdi ve İsviçre Medeni Kanunu esas alınarak hazırlandı. Tek eşlilik, kadın-erkek eşitliği, tapu sicili gibi temel düzenlemeleri getirdi. Türk hukuk devriminin en köklü adımlarından biridir."},
  {q:"Harf devrimi ne zaman yapıldı ve ne getirildi?",opts:["1925 — Arap harfleri modernleştirildi","1928 — Latin alfabesi kabul edildi","1926 — Osmanlı alfabesi sadeleştirildi","1932 — Yeni Türkçe alfabesi oluşturuldu"],ans:1,exp:"Harf Devrimi 1 Kasım 1928'de gerçekleşti; Arap harfleri yerine Latin alfabesi esaslı yeni Türk alfabesi kabul edildi. Bu devrim okur-yazarlığı artırmayı ve modernleşmeyi hedefledi."},
  {q:"Kadınlara milletvekili seçme ve seçilme hakkı hangi yılda tanındı?",opts:["1930","1932","1934","1938"],ans:2,exp:"Kadınlara belediye seçimlerinde oy hakkı 1930'da, milletvekili seçme ve seçilme hakkı ise 5 Aralık 1934'te tanındı. Türkiye bu hakkı pek çok Avrupa ülkesinden önce kadınlara tanımıştır."},
  {q:"İzmir İktisat Kongresi ne zaman toplandı ve önemi nedir?",opts:["1919 — Kurtuluş Savaşı ekonomisi","1923 — Ulusal ekonomi politikalarının belirlenmesi","1929 — Dünya ekonomik krizi kararları","1932 — Devletçilik ilkesinin ilanı"],ans:1,exp:"İzmir İktisat Kongresi Şubat-Mart 1923'te toplandı. Lozan görüşmeleri devam ederken gerçekleşen kongrede ulusal ekonomi politikaları belirlendi; tam bağımsızlık için ekonomik bağımsızlığın şart olduğu vurgulandı."},
  {q:"Atatürk'ün Nutuk'u hangi yılda yayımlandı?",opts:["1923","1925","1927","1930"],ans:2,exp:"Nutuk (Söylev) 1927'de yayımlandı. Atatürk'ün 1919-1927 yılları arasındaki millî mücadele ve inkılap sürecini anlattığı bu büyük eser, tarihsel bir belge niteliği taşır."},
  {q:"Soyadı Kanunu hangi yılda çıkarıldı?",opts:["1928","1932","1934","1936"],ans:2,exp:"Soyadı Kanunu 1934'te çıkarıldı. Kanunun yürürlüğe girmesiyle Mustafa Kemal, TBMM tarafından 'Atatürk' soyadını aldı. Tüm Türk vatandaşlarının soyadı edinmesi zorunlu hale getirildi."},
  {q:"Birinci Dünya Savaşı'ndan sonra Osmanlı İmparatorluğu'na dayatılan antlaşma hangisidir?",opts:["Lozan Antlaşması","Mudanya Ateşkesi","Sevr Antlaşması","Mondros Mütarekesi"],ans:2,exp:"Sevr Antlaşması 10 Ağustos 1920'de imzalandı. Osmanlı İmparatorluğu'nu parçalayan bu antlaşmayı TBMM tanımadı ve Kurtuluş Savaşı'nı kazanarak yerine 1923'te Lozan Antlaşması'nı imzalattı."},
  {q:"Mondros Mütarekesi hangi tarihte imzalandı?",opts:["28 Ocak 1920","30 Ekim 1918","10 Ağustos 1920","19 Mayıs 1919"],ans:1,exp:"Mondros Mütarekesi 30 Ekim 1918'de imzalandı. Birinci Dünya Savaşı'nı Osmanlı İmparatorluğu açısından sona erdiren bu ateşkes, İtilaf devletlerinin Anadolu'yu işgal etmesinin önünü açtı."},
  {q:"Atatürk Samsun'a hangi tarihte çıktı ve bu tarihin önemi nedir?",opts:["23 Nisan 1919 — TBMM'nin açılışı","19 Mayıs 1919 — Millî Mücadele'nin başlangıcı","30 Ağustos 1922 — Büyük Taarruz","29 Ekim 1923 — Cumhuriyetin ilanı"],ans:1,exp:"Mustafa Kemal 19 Mayıs 1919'da Samsun'a çıktı. Bu tarih Millî Mücadele'nin fiilen başladığı tarih olarak kabul edilir ve her yıl Atatürk'ü Anma, Gençlik ve Spor Bayramı olarak kutlanır."},
  {q:"Devletçilik ilkesi çerçevesinde kurulan ilk büyük devlet işletmesi hangisidir?",opts:["Türkiye İş Bankası","Türkiye Cumhuriyet Merkez Bankası","Sümerbank","Türk Hava Yolları"],ans:2,exp:"Sümerbank 1933'te kuruldu ve Türkiye'nin sanayileşme hamlelerinin simgesi oldu. Devletçilik ilkesi kapsamında tekstil, demir-çelik gibi temel sanayi kollarında devlet yatırımları yapıldı."},
  {q:"Türk-Yunan Nüfus Mübadelesi hangi antlaşmayla düzenlendi ve kaç yılında yapıldı?",opts:["Sevr Antlaşması — 1920","Lozan Antlaşması — 1923","Lausanne Protokolü — 1924","Ankara Antlaşması — 1925"],ans:1,exp:"Türk-Yunan nüfus mübadelesi 1923 Lozan Antlaşması çerçevesinde düzenlendi. Yaklaşık 1,2 milyon Rum Ortodoks Yunanistan'a, yaklaşık 500 bin Müslüman Türk ise Türkiye'ye göç etti. Din esas alındı, Karamanlılar ve İstanbul Rumları kapsam dışı tutuldu."},
  // --- İnkılap Tarihi Ek Sorular (21.03.2026) ---
  {q:"Erzurum Kongresi hangi tarihler arasında toplandı ve temel kararı neydi?",opts:["19 Mayıs – 10 Haziran 1919; Samsun'da bağımsızlık ilanı","23 Temmuz – 7 Ağustos 1919; Millî sınırlar içinde bütünlük ve manda-himaye reddedildi","4-11 Eylül 1919; Tüm cemiyetlerin birleştirilmesi","28 Ocak 1920; Misak-ı Millî kararı"],ans:1,exp:"Erzurum Kongresi 23 Temmuz – 7 Ağustos 1919 tarihleri arasında toplandı. Başlangıçta doğu illerini kapsayan bölgesel bir kongre olmasına rağmen millî nitelik taşıyan kararlar aldı: Millî sınırlar içinde vatan bütünlüğü savunulacak; manda ve himaye kabul edilmeyecektir."},
  {q:"Birinci İnönü Muharebesi hangi tarihte kazanıldı ve önemi nedir?",opts:["Eylül 1920 — İlk Yunan çıkarması geri püskürtüldü","Ocak 1921 — Yunan kuvvetleri durduruldu; TBMM'nin ilk büyük askerî zaferi","Mart 1921 — Fransızlarla ateşkes sağlandı","Ağustos 1921 — Başkomutanlık yetkisi devredildi"],ans:1,exp:"Birinci İnönü Muharebesi Ocak 1921'de kazanıldı. TBMM ordusunun Yunan kuvvetlerine karşı elde ettiği bu ilk önemli askerî zafer, Londra Konferansı'na güçlü gidilmesini sağladı. Komutan İsmet Paşa, bu zafer nedeniyle 'İnönü' soyadını almıştır."},
  {q:"Sakarya Meydan Muharebesi hangi tarihler arasında yapıldı ve bu savaşla ilgili önemli gelişme neydi?",opts:["Ocak 1921 — İsmet Paşa komutasında savunma","Temmuz 1921 — Kütahya-Eskişehir kaybedildi","23 Ağustos – 13 Eylül 1921 — Başkomutanlık yetkisi Mustafa Kemal'e verildi","26 Ağustos 1922 — Büyük Taarruz ile eş zamanlı"],ans:2,exp:"Sakarya Meydan Muharebesi 23 Ağustos – 13 Eylül 1921 tarihleri arasında yapıldı. Savaş öncesinde TBMM, 5 Ağustos 1921'de Başkomutanlık yetkisini Mustafa Kemal'e devretmişti. Savunma muharebesi Yunan ilerleyişini durdurdu; Mustafa Kemal'e 'Gazi' unvanı ve 'Mareşal' rütbesi verildi."},
  {q:"Büyük Taarruz ne zaman başladı ve hangi muharebe ile zafere ulaştı?",opts:["30 Ağustos 1921 — Sakarya","26 Ağustos 1922 — Dumlupınar Meydan Muharebesi ile tamamlandı","9 Eylül 1922 — İzmir'in kurtuluşu","11 Ekim 1922 — Mudanya Ateşkesi"],ans:1,exp:"Büyük Taarruz 26 Ağustos 1922'de başladı; 30 Ağustos 1922'de Dumlupınar Meydan Muharebesi ile kesin zafere ulaştı. 9 Eylül 1922'de İzmir Yunan kuvvetlerinden kurtarıldı. 30 Ağustos bu zafere atfen her yıl Zafer Bayramı olarak kutlanmaktadır."},
  {q:"Türk Tarih Kurumu ve Türk Dil Kurumu hangi yıllarda kurulmuştur?",opts:["TTK 1928 – TDK 1930","TTK 1931 – TDK 1932","TTK 1932 – TDK 1931","TTK 1929 – TDK 1934"],ans:1,exp:"Türk Tarih Kurumu 1931'de, Türk Dil Kurumu 12 Temmuz 1932'de kuruldu. TTK Türk tarihini araştırma ve Türk Tarih Tezi'ni geliştirme; TDK ise Türk dilini araştırma, yabancı sözcüklere Türkçe karşılık bulma amacıyla faaliyete geçmiştir. İkisi de Atatürk'ün doğrudan yönlendirdiği kurumlardır."},
  {q:"İnkılap kanunları kronolojisinde hangisi diğerlerinden ÖNCE gerçekleşmiştir?",opts:["Harf Devrimi — 1928","Soyadı Kanunu — 1934","Halifeliğin kaldırılması — 1924","Medeni Kanun — 1926"],ans:2,exp:"Kronoloji: Halifeliğin kaldırılması (3 Mart 1924) → Tekke/Zaviye kapatma ve Şapka Kanunu (1925) → Medeni Kanun (1926) → Harf Devrimi (1928) → Soyadı Kanunu (1934). 1924, tüm seçenekler arasında en erken tarihtir."}
  ,{q:"Ankara hangi tarihte Türkiye Cumhuriyeti'nin başkenti ilan edilmiştir?",opts:["23 Nisan 1920","13 Ekim 1923","29 Ekim 1923","3 Mart 1924"],ans:1,exp:"Ankara, 13 Ekim 1923'te Türkiye Cumhuriyeti'nin başkenti ilan edilmiştir. Cumhuriyet ise 29 Ekim 1923'te ilan edilmiştir. İki tarihin birbirine karıştırılmaması önemlidir: Ankara başkent → 13 Ekim, Cumhuriyet ilanı → 29 Ekim."}
  ,{q:"Lozan Barış Konferansı'nda Türk heyetinin başkanlığını kim yapmıştır?",opts:["Mustafa Kemal Paşa","Ali Fuat Paşa","İsmet Paşa","Kazım Karabekir Paşa"],ans:2,exp:"Lozan Barış Konferansı'nda (Kasım 1922 – Temmuz 1923) Türk heyetinin başkanlığını dönemin Dışişleri Bakanı İsmet Paşa (İnönü) yürütmüştür. Uzun ve zorlu müzakereler sonucunda 24 Temmuz 1923'te antlaşma imzalanmış; İsmet Paşa bu başarıyla siyasi kariyerinin zirvesine ulaşmıştır."}
  ,{q:"1921 tarihli Teşkilat-ı Esasiye Kanunu hakkında hangisi doğrudur?",opts:["Türkiye'nin ilk yazılı anayasasıdır","TBMM döneminde kabul edilen ilk anayasadır ve millî egemenliği esas alır","1924 Anayasası'nın aynısıdır","Saltanat döneminde Osmanlı tarafından hazırlanmıştır"],ans:1,exp:"1921 Anayasası (Teşkilat-ı Esasiye Kanunu), TBMM döneminde 20 Ocak 1921'de kabul edilen ilk anayasadır. 'Egemenlik kayıtsız şartsız milletindir' ilkesini esas alır. Türkiye'nin ilk yazılı anayasası değildir; 1876 tarihli Kanun-ı Esasî daha öncedir. 1924 Anayasası bu belgenin yerini almıştır."}
  ,{q:"Şapka Kanunu hangi yılda çıkarılmış, buna karşı çıkanlara hangi yaptırım uygulanmıştır?",opts:["1924 — sürgün","1925 — İstiklal Mahkemelerinde yargılama","1928 — hapis","1930 — idari para cezası"],ans:1,exp:"Şapka Kanunu (şapka iktisası hakkındaki kanun) 25 Kasım 1925'te yürürlüğe girdi. Fes yerine Batı tipi şapka zorunlu kılındı. Kanuna karşı çıkan ya da isyana teşvik edenlerin bir kısmı İstiklal Mahkemelerinde yargılandı; bazıları idam edildi (Giresun, Rize olayları)."}
  ,{q:"Türkiye Milletler Cemiyeti'ne (Cemiyet-i Akvam) hangi yılda üye olmuştur?",opts:["1923","1926","1932","1936"],ans:2,exp:"Türkiye, 18 Temmuz 1932'de Milletler Cemiyeti'ne (bugünkü BM'nin öncüsü) katılmıştır. Bu adım Türkiye'nin uluslararası arenada tanınırlığını pekiştirmiş ve Batı ile ilişkilerini güçlendirmiştir. İnönü dönemi dış politika başarıları arasında sayılmaktadır."}
  ,{q:"Balkan Antantı hangi tarihte imzalanmış ve hangi devletleri kapsamıştır?",opts:["1932 — Türkiye, Bulgaristan, Romanya, Yunanistan","1934 — Türkiye, Yunanistan, Romanya, Yugoslavya","1936 — Türkiye, Arnavutluk, Bulgaristan, Sırbistan","1937 — Türkiye, Yunanistan, Bulgaristan, Macaristan"],ans:1,exp:"Balkan Antantı 9 Şubat 1934'te Türkiye, Yunanistan, Romanya ve Yugoslavya arasında imzalanmıştır. Türkiye'nin bölgesel güvenlik ve barışı güçlendirme politikasının ürünüdür. Bulgaristan ve Arnavutluk antanta katılmamıştır."}
  ,{q:"Kabotaj Kanunu hangi tarihte yürürlüğe girmiş ve ne anlama gelmektedir?",opts:["24 Temmuz 1923 — Lozan ile birlikte","1 Temmuz 1926 — Türk karasularında ticaret Türk gemilerine bırakıldı","1 Kasım 1928 — Harf Devrimi ile aynı dönem","1934 — Soyadı Kanunu ile birlikte"],ans:1,exp:"Kabotaj Kanunu 1 Temmuz 1926'da yürürlüğe girmiştir. Bu kanunla Türk kara sularında yolcu ve yük taşımacılığı Türk gemi ve denizcilerine bırakılmıştır. 1 Temmuz her yıl Denizcilik ve Kabotaj Bayramı olarak kutlanmaktadır."}
  ,{q:"Türkiye'nin ilk Beş Yıllık Sanayi Planı hangi yılda hazırlanmış ve uygulamaya konulmuştur?",opts:["1929","1932","1934","1938"],ans:2,exp:"Birinci Beş Yıllık Sanayi Planı 1934'te hazırlanmış ve uygulamaya konulmuştur. Devletçilik ilkesi çerçevesinde tekstil, kâğıt, cam, kimya ve madencilik gibi temel sanayi kollarında devlet yatırımları öngörülmüştür. Sovyetler Birliği'nin teknik ve finansal desteğiyle hayata geçirilmiştir."}
  ,{q:"Hatay'ın Türkiye'ye katılması hangi tarihte gerçekleşmiştir?",opts:["1936","1938","1939","1941"],ans:2,exp:"Hatay, 29 Haziran 1939'da Türkiye'ye katılmıştır. Fransız mandası altındaki İskenderun Sancağı'nda 1938'de bağımsız Hatay Devleti kurulmuş; ardından halk oylaması ve TBMM kararıyla Türkiye'ye ilhak edilmiştir. Atatürk bu gelişmeyi göremeden 10 Kasım 1938'de vefat etmiştir."}
  ,{q:"Atatürk'ün vefatının ardından Türkiye Cumhuriyeti'nin ikinci Cumhurbaşkanı kim olmuştur ve hangi tarihte göreve başlamıştır?",opts:["Fevzi Çakmak — 10 Kasım 1938","İsmet İnönü — 11 Kasım 1938","Celal Bayar — 10 Kasım 1938","Kazım Özalp — 15 Kasım 1938"],ans:1,exp:"Atatürk'ün 10 Kasım 1938'deki vefatının ardından, 11 Kasım 1938'de İsmet İnönü TBMM tarafından Türkiye Cumhuriyeti'nin ikinci Cumhurbaşkanı seçilmiştir. İnönü, İkinci Dünya Savaşı yıllarında tarafsızlık politikası izleyerek Türkiye'yi savaşın dışında tutmayı başarmıştır."}
],
polismev:[
  {q:"PVSK m.4/A'ya göre durdurma süresi ne kadar olabilir?",opts:["15 dakika","30 dakika","1 saat","Süre belirlenmemiştir"],ans:1,exp:"PVSK m.4/A: Durdurma süresi 30 dakikayı geçemez. Bu süre içinde kimlik tespiti yapılamazsa kişi, gözaltı hükümlerine göre işleme tabi tutulabilir."},
  {q:"Gözaltı süresi CMK m.91'e göre toplu suçlarda en fazla kaç güne uzatılabilir?",opts:["1 gün","2 gün","3 gün","7 gün"],ans:2,exp:"CMK m.91: Kişi yakalandıktan sonra en geç 24 saat içinde hâkim önüne çıkarılır. Toplu suçlarda Cumhuriyet savcısının yazılı emriyle bu süre 3 güne kadar uzatılabilir."},
  {q:"5442 sayılı İl İdaresi Kanunu'na göre vali, il sınırları içindeki güvenlik kuvvetlerinin amiri midir?",opts:["Yalnızca polisin amiridir","Yalnızca jandarmanın amiridir","Tüm kolluk kuvvetlerinin en büyük amiridir","Sadece özel güvenliğin amiridir"],ans:2,exp:"5442 sayılı Kanun: Vali, il sınırları içindeki tüm güvenlik ve kolluk kuvvetlerinin (polis ve jandarma) en büyük amiridir. Kamu düzeni ve güvenliğinden sorumlu olarak tüm birimleri koordine eder."},
  {q:"Polis Vazife ve Salahiyet Kanunu'na göre silah kullanma yetkisinde doğru sıralama hangisidir?",opts:["Önce ateş aç, sonra uyar","Uyarı yap, uyarı ateşi aç, etkisiz kılmaya çalış","Sadece tehdit varsa ateş aç","Hukuki koşul aranmaz"],ans:1,exp:"PVSK m.16: Silah kullanma aşamalıdır. Sözlü uyarı → havaya uyarı ateşi → etkisiz kılmaya yönelik ateş. Zorunluluk, son çare olma ve orantılılık ilkelerine uygunluk şarttır."},
  {q:"Önleyici kolluk ile adli kolluğun temel farkı nedir?",opts:["Önleyici kolluk silahlı; adli kolluk silahsızdır","Önleyici kolluk suç işlenmeden önce; adli kolluk suç sonrasında görev yapar","Adli kolluk jandarma; önleyici kolluk polisten oluşur","Hiçbir fark yoktur"],ans:1,exp:"Önleyici (idari) kolluk kamu düzenini korumak amacıyla hareket eder ve idari amirine bağlıdır. Adli kolluk ise suç işlendikten sonra savcının emriyle soruşturma kapsamında görev yapar."},
  {q:"Yakalama ile gözaltı arasındaki fark nedir?",opts:["İkisi aynı kavramdır","Yakalama fiili ele geçirimdir; gözaltı savcı/hâkim kararıyla özgürlük kısıtlamasıdır","Gözaltı mahkeme kararı gerektirir; yakalama gerektirmez","Yakalama sadece jandarma yapabilir"],ans:1,exp:"Yakalama: Bir kişinin hareket özgürlüğüne fiziksel olarak müdahaledir; herkes veya kolluk yapabilir. Gözaltı: Savcının kararıyla kişinin belirli süre özgürlüğünden yoksun bırakılmasıdır. Farklı hukuki rejimlere tabidir."},
  {q:"Kimlik bildirme yükümlülüğüne uymayan kişi hakkında kolluk ne yapabilir?",opts:["Doğrudan tutuklar","Kimlik tespiti amacıyla en fazla 4 saat alıkoyabilir","En fazla 24 saat gözaltına alır","Herhangi bir işlem yapamaz"],ans:1,exp:"PVSK m.4/A: Kimliğini ispat edemeyen kişi, kimlik tespiti amacıyla kolluğa götürülebilir. Bu süre 4 saati geçemez; şüphe ortadan kalkarsa kişi serbest bırakılır."},
  {q:"Polis, konut araması yapabilmesi için kural olarak hangi belgeye ihtiyaç duyar?",opts:["Vali emri","Savcı talebi yeterlidir","Hâkim kararı","Bakan onayı"],ans:2,exp:"CMK m.119: Konut araması kural olarak hâkim kararıyla yapılır. Gecikmesinde sakınca bulunan hallerde savcı emriyle arama yapılabilir; ancak bu karar 24 saat içinde hâkim onayına sunulmalıdır."},
  {q:"Adli kolluk görevlisi savcının emrine aykırı hareket ederse ne olur?",opts:["Herhangi bir yaptırım uygulanmaz","Disiplin soruşturması açılır; suç teşkil ediyorsa cezai sorumluluk doğar","Sadece uyarı alır","Görevden ihraç edilir"],ans:1,exp:"CMK m.165: Adli kolluk görevlileri savcının emirlerini yerine getirmek zorundadır. Emre aykırı davranış disiplin hukuku kapsamında değerlendirilir; fiil suç teşkil ederse ayrıca cezai sorumluluk doğar."},
  {q:"2911 sayılı Toplantı ve Gösteri Yürüyüşleri Kanunu'na göre toplantı bildirimi kaç saat önceden yapılmalıdır?",opts:["24 saat","48 saat","72 saat","Bildirim zorunlu değildir"],ans:1,exp:"2911 sayılı Kanun: Toplantı ve gösteri yürüyüşleri en az 48 saat önce yazılı olarak ilgili makama bildirilmelidir. Acele hallerde bu süre kısaltılabilir; ancak izin alınması zorunlu değildir."},
  {q:"Emniyet Hizmetleri Sınıfı mensupları hangi tür derneklere üye olabilir? (2025 PAEM)",opts:["Sadece spor derneklerine","Her türlü derneğe","Sadece mesleki derneklere","Hiçbir derneğe"],ans:0,exp:"Emniyet Hizmetleri Sınıfı mensupları siyasi parti, sendika ve mesleki dernekler gibi örgütlere üye olamaz. Tarafsızlık ve siyasi bağımsızlık ilkesi gereğidir. Ancak spor derneklerine üye olmak bu yasağın dışındadır."},
  {q:"Silahlı saldırıya maruz kalan polis silahı nasıl kullanabilir? (2025 PAEM)",opts:["Amirinden izin alarak","Kesinlikle kullanamaz","Sadece yakalamak için","Saldırıyı etkisiz kılacak ölçüde"],ans:3,exp:"PVSK m.16: Silahlı saldırıya maruz kalan polis, saldırıyı etkisiz kılabilecek ölçüde silah kullanabilir. Orantılılık ilkesi gereği tehdidin boyutuyla orantılı güç kullanılır; fazlası disiplin ve cezai sorumluluk doğurur."},
  {q:"Kanuna aykırı emir bakımından hangisi doğrudur? (2025 PAEM)",opts:["Emir kendi inisiyatifiyle değiştirilir","Emir iade edilir","Emir derhal yerine getirilir","Konusu suç teşkil eden emir hiçbir suretle yerine getirilmez"],ans:3,exp:"Anayasa m.137: Kamu görevlileri, konusu suç teşkil eden emirleri yerine getirmez ve bu emirleri yerine getiren kişi sorumluluktan kurtulamaz. Emri veren ile yerine getiren birlikte sorumludur. Sadece 'emir aldım' savunması geçerli değildir."},
  {q:"Emniyet Teşkilat Kanunu'na göre ülkenin emniyet ve asayiş işlerinden kim sorumludur? (2025 PAEM)",opts:["İçişleri Bakanı","Başsavcı","Jandarma Genel Komutanı","Emniyet Genel Müdürü"],ans:0,exp:"Emniyet Teşkilat Kanunu (3201): Türkiye'nin genel emniyet ve asayiş işlerinden İçişleri Bakanı sorumludur. Emniyet Genel Müdürlüğü bu bakanlığa bağlıdır. Jandarma ve Sahil Güvenlik de 2017 itibarıyla İçişleri Bakanlığı bünyesine alınmıştır."}

  ,
  {q:"PVSK'ya göre polis 'durdurma' yetkisini hangi koşulda kullanabilir?",opts:["Her durumda istediği kişiyi durdurabilir","Yalnızca suçüstü halinde","Makul şüphe bulunması halinde","Amir emriyle her durumda"],ans:2,exp:"PVSK m.4/A: Polis, makul şüphe bulunması halinde kişileri ve araçları durdurabilir. Makul şüphe; soyut değil, somut ve nesnel verilere dayalı olmalıdır. Durdurma süresi 30 dakikayı geçemez."},
  {q:"Emniyet Teşkilatı hangi bakanlığa bağlıdır?",opts:["Adalet Bakanlığı","Millî Savunma Bakanlığı","İçişleri Bakanlığı","Cumhurbaşkanlığı"],ans:2,exp:"Emniyet Genel Müdürlüğü İçişleri Bakanlığı'na bağlıdır. Ülkenin genel emniyet ve asayiş işlerinden İçişleri Bakanı sorumludur."},
  {q:"PVSK'ya göre 'önleyici arama' ile 'adli arama' arasındaki temel fark nedir?",opts:["Önleyici aramada hâkim kararı şart, adli aramada değil","Önleyici arama idari nitelikte, adli arama suç şüphesiyle başlar","Önleyici arama yalnızca konutlarda yapılır","Aralarında hukuki fark yoktur"],ans:1,exp:"Önleyici arama idari nitelikte olup suç işlenmesini önlemek amacıyla yapılır, mülki amirin onayı gerekir. Adli arama ise suç şüphesiyle başlar ve CMK hükümlerine tabidir; hâkim kararı veya savcı emri gerekir."},
  {q:"Polisin 'kimlik sorma' yetkisi için aranan koşul nedir?",opts:["Makul şüphe yeterlidir","Kesin suç delili bulunmalıdır","Yalnızca gece denetimlerinde kullanılabilir","Amir emri gereklidir"],ans:0,exp:"PVSK m.4/A: Polis makul şüphe bulunması halinde kişilere kimliklerini sorabilir. Kişi kimliğini ispat edemezse kimlik tespiti için en yakın kolluğa götürülebilir; bu süre 4 saati geçemez."},
  {q:"Polis, yakalama yetkisini hangi hallerde kullanabilir?",opts:["Yalnızca hâkim kararıyla","Yalnızca savcı emriyle","Suçüstü ve gecikmesinde sakınca bulunan hallerde amir emriyle, savcı emriyle veya hâkim kararıyla","Yalnızca terör suçlarında"],ans:2,exp:"Yakalama; hâkim kararı veya Cumhuriyet savcısının yazılı emriyle yapılır. Gecikmesinde sakınca bulunan hallerde kolluk amiri yazılı emriyle de yakalama yapılabilir. Suçüstü halinde ise herkes yakalama yapabilir."},
  {q:"5442 sayılı İl İdaresi Kanunu'na göre ilin genel idaresinin başı kimdir?",opts:["Kaymakam","Vali","İçişleri Bakanı","Belediye Başkanı"],ans:1,exp:"5442 sayılı İl İdaresi Kanunu'na göre il genel idaresinin başı validir. Vali, İçişleri Bakanlığı'nın temsilcisi ve Cumhurbaşkanının vekilidir; ilde kanunların uygulanmasından sorumludur."},
  {q:"Kaymakam hangi kuruma karşı sorumludur?",opts:["Yalnızca valiye","Yalnızca İçişleri Bakanlığı'na","Valiye ve İçişleri Bakanlığı'na","Doğrudan Cumhurbaşkanlığına"],ans:2,exp:"Kaymakam, ilçenin genel idaresinin başıdır ve hem valiye hem de İçişleri Bakanlığı'na karşı sorumludur. Vali kaymakamın amiridir; kaymakam valinin emirlerini ve bakanlık talimatlarını uygular."},
  {q:"PVSK m.16'ya göre silah kullanma yetkisini düzenleyen temel ilke nedir?",opts:["Caydırıcılık ilkesi","Orantılılık ilkesi","Hiyerarşi ilkesi","Kanunilik ilkesi"],ans:1,exp:"Silah kullanmada orantılılık ilkesi esastır — kullanılan güç tehdidin boyutuyla orantılı olmalıdır. Ağırlaştırılmış müebbet gerektiren suçlarda kaçan şüpheliye son çare olarak ateş açılabilir."},
  {q:"Türk polisinin sembolik olarak bağlı olduğu şehir hangisidir ve neden önemlidir?",opts:["Ankara — cumhuriyetin başkenti","İstanbul — tarihi merkez","Edirne — sınır kenti","Çanakkale — zafer şehri"],ans:0,exp:"Emniyet Genel Müdürlüğü merkezi Ankara'dadır. 10 Nisan 1845'te kurulan Zaptiye Müşirliği, modern Türk polis teşkilatının öncüsüdür. Her yıl 10 Nisan Türk Polis Teşkilatının kuruluş yıldönümü olarak kutlanır."},
  {q:"Polis Vazife ve Salahiyet Kanunu'nun (PVSK) numarası nedir?",opts:["2559","2911","6136","5271"],ans:0,exp:"PVSK 2559 sayılı kanundur. Polisin görev, yetki ve sorumluluklarını düzenler. 2559 sayılı PVSK yanı sıra Emniyet Teşkilat Kanunu (3201) da temel mevzuattır."},
  {q:"Emniyet Teşkilat Kanunu'nun numarası nedir?",opts:["2559","3201","5271","2911"],ans:1,exp:"Emniyet Teşkilat Kanunu 3201 sayılı kanundur. Emniyet Genel Müdürlüğü'nün kuruluş, görev ve yetkilerini düzenler. PVSK (2559) ile birlikte polis hukukunun temel kaynaklarıdır."},
  {q:"Toplantı ve gösteri yürüyüşlerini düzenleyen temel kanun hangisidir?",opts:["PVSK (2559)","2911 sayılı Toplantı ve Gösteri Yürüyüşleri Kanunu","5326 sayılı Kabahatler Kanunu","3713 sayılı Terörle Mücadele Kanunu"],ans:1,exp:"Toplantı ve gösteri yürüyüşleri 2911 sayılı Toplantı ve Gösteri Yürüyüşleri Kanunu ile düzenlenir. Anayasa m.34 de bu hakkı güvence altına alır; önceden izin değil, bildirim usulü geçerlidir."},
  {q:"Polisin 'zor kullanma' yetkisi hangi sıraya göre uygulanır?",opts:["Beden gücü → Maddi güç → Silah","Silah → Beden gücü → Maddi güç","Maddi güç → Silah → Beden gücü","Sırası yoktur, orantılılığa göre karar verilir"],ans:0,exp:"PVSK m.16: Zor kullanma sırası — önce beden gücü, ardından maddi güç (cop, tazyikli su, tazyikli gaz vb.), son çare olarak silah kullanılır. Her aşamada orantılılık ilkesine uyulmalıdır."},
  {q:"Polis eğitim kurumları hangi bakanlığa bağlıdır?",opts:["Millî Eğitim Bakanlığı","Yükseköğretim Kurulu","İçişleri Bakanlığı","Cumhurbaşkanlığı"],ans:2,exp:"Polis Akademisi ve diğer polis eğitim kurumları İçişleri Bakanlığı'na bağlıdır. Polis Akademisi, lisans düzeyinde eğitim veren ve güvenlik bilimleri alanında araştırmalar yapan en üst polis eğitim kurumudur."},
  {q:"Suçüstü halinde herhangi bir kişi şüpheliyi yakalayabilir mi?",opts:["Hayır, yalnızca kolluk görevlileri yakalayabilir","Evet, ancak hemen kolluğa teslim etmek zorundadır","Evet, 24 saat kendi gözetiminde tutabilir","Hayır, yalnızca savcının emriyle yakalama yapılır"],ans:1,exp:"CMK m.90: Suçüstü halinde herkes şüpheliyi yakalayabilir. Ancak yakalayan kişi şüpheliyi derhal kolluğa teslim etmek zorundadır. Bu yetki gecikmesinde sakınca bulunan ve kolluğa bildirim yapılamayan durumlar için öngörülmüştür."},
  {q:"İl genel jandarma komutanı kime karşı sorumludur?",opts:["Yalnızca Genelkurmay Başkanlığı'na","Yalnızca valiye","Hem valiye (güvenlik hizmetleri) hem Kara Kuvvetleri Komutanlığı'na (askerî işler)","Doğrudan İçişleri Bakanlığı'na"],ans:2,exp:"İl Jandarma Komutanı güvenlik ve asayiş hizmetlerinde valiye, askerî eğitim ve disiplin konularında ise Kara Kuvvetleri Komutanlığı'na bağlıdır. Jandarma hem askerî hem de sivil idareye karşı sorumluluk taşır."},
  {q:"PVSK'ya göre polis önleyici tedbirler kapsamında hangi kısıtlamayı uygulayabilir?",opts:["Mahkeme kararı olmaksızın 7 güne kadar gözaltı","Belirli bölgelerde geçici güvenlik uygulaması","Seyahat yasağı","Mal varlığına el koyma"],ans:1,exp:"PVSK m.11: Polis, suç işlenmesini önlemek amacıyla belirli bölgeler veya mekânlarda geçici güvenlik uygulaması (nokta uygulama, devriye, kontrol noktası vb.) yapabilir. Bu tedbir idari niteliktedir."},
  {q:"Polis meslek ilkeleri arasında 'tarafsızlık' ne anlama gelir?",opts:["Yalnızca üst rütbelilerin emirlerini uygulamak","Kişi, grup veya siyasi görüş ayrımı yapmaksızın herkese eşit hizmet","Suç şüphelisini her koşulda korumak","Delil değerlendirmesinden uzak durmak"],ans:1,exp:"Tarafsızlık ilkesi, polisin görevini yerine getirirken dil, ırk, cinsiyet, siyasi düşünce, din gibi ayrımlar gözetmeksizin herkese eşit ve adil davranmasını ifade eder. Bu ilke Anayasa m.10'daki eşitlik ilkesiyle doğrudan bağlantılıdır."}

  // --- Polis Mevzuatı Soru Kampı Transkriptinden Eklenen Sorular ---
  ,{q:"ETK'ya göre komiser yardımcısı kadrosuna terfi için kaç yıl bekleme süresi öngörülmüştür?",opts:["2 yıl","3 yıl","4 yıl","5 yıl"],ans:2,exp:"Emniyet Teşkilat Kanunu: Komiser yardımcısı, 9. dereceden başlar ve terfi için 4 yıl bekleme süresi vardır. Terfi kurulları Mayıs ayında toplanır, terfiler Haziran ayında gerçekleşir."}
  ,{q:"ETK'ya göre terfi kurulları hangi ayda toplanır?",opts:["Mart","Nisan","Mayıs","Haziran"],ans:2,exp:"ETK: Terfi kurulları Mayıs ayında toplanır. Buna göre terfiler Haziran ayında kesinleşir. Yetersiz performans gösterenlerin terfisi 1 yıl geciktirilir."}
  ,{q:"ETK'ya göre istifa eden personel kaç yıl içinde göreve dönmezse bir daha alınamaz?",opts:["1 yıl","2 yıl","3 yıl","5 yıl"],ans:2,exp:"ETK: İstifa eden emniyet personeli, istifa tarihinden itibaren 3 yıl içinde göreve dönmezse bir daha teşkilata alınamaz."}
  ,{q:"PVSK m.5'e göre parmak izi bilgileri genel kural olarak kaç yıl saklanır?",opts:["5 yıl","10 yıl","20 yıl","80 yıl"],ans:1,exp:"PVSK m.5: Parmak izi ve diğer biyometrik veriler genel kural olarak 10 yıl saklanır. Ağır suçlarda bu süre 80 yıla çıkar. Saklama koşulları İçişleri Bakanlığı yönetmeliğiyle düzenlenir."}
  ,{q:"Parmak izi saklama koşullarını düzenleyen yönetmeliği hangi bakanlık çıkarır?",opts:["Adalet Bakanlığı","İçişleri Bakanlığı","Cumhurbaşkanlığı","Sağlık Bakanlığı"],ans:1,exp:"PVSK m.5: Parmak izi saklama yönetmeliği İçişleri Bakanlığı tarafından çıkarılır. Ancak bu yönetmelik Adalet Bakanlığı'nın görüşü alındıktan sonra hazırlanır."}
  ,{q:"Gözaltı sağlık raporu kaç nüsha düzenlenir ve nüshalar kime verilir?",opts:["2 nüsha: kolluk ve kişiye","3 nüsha: sağlık kuruluşu, kişi ve kolluk","4 nüsha: savcı, hakim, kişi ve kolluk","1 nüsha: kolluğa"],ans:1,exp:"Gözaltı sağlık raporu 3 nüsha düzenlenir: 1 nüshası raporu düzenleyen sağlık kuruluşunda kalır, 1 nüshası kişiye verilir, 1 nüshası kolluğa kalır. Rapor; alınırken, yer değiştirirken, gözaltı uzatılırken ve serbest bırakılırken alınır."}
  ,{q:"Gözaltı süresi toplu suçlarda uzatılırken en fazla kaç gün uzatılabilir ve nasıl yapılır?",opts:["Tek seferde 3 gün uzatılabilir","Tek seferde 4 gün uzatılabilir","Günlük +1, +1, +1 şeklinde toplamda 4 güne kadar","Günlük +1, +1 şeklinde toplamda 3 güne kadar"],ans:2,exp:"Gözaltı uzatması tek seferde yapılamaz. Başlangıç 24 saat, ardından +1 gün, +1 gün, +1 gün şeklinde uzatılır. Delil toplamada güçlük ve şüpheli çokluğu durumunda toplamda 4 güne kadar uzatılabilir."}
  ,{q:"7068 sayılı Kanun'a göre uyarma ve kınama disiplin cezaları kaç yılda özlük dosyasından silinir?",opts:["3 yıl","5 yıl","8 yıl","10 yıl"],ans:1,exp:"7068 sayılı Emniyet Teşkilatı Disiplin Kanunu: Uyarma ve kınama cezaları 5 yıl geçmesiyle özlük dosyasından silinir. Aylıktan kesme ve kademe durdurma cezaları ise 10 yılda silinir."}
  ,{q:"7068 sayılı Kanun'a göre aylıktan kesme ve kademe durdurma cezaları kaç yılda özlük dosyasından silinir?",opts:["5 yıl","8 yıl","10 yıl","15 yıl"],ans:2,exp:"7068 sayılı Emniyet Teşkilatı Disiplin Kanunu: Aylıktan kesme ve kademe durdurma cezaları 10 yılda özlük dosyasından silinir. Uyarma/kınama ise 5 yılda silinir. Meslekten çıkarma kalıcıdır."}
  ,{q:"Disiplin soruşturmasında görevden uzaklaştırılan memurun maaşının ne kadarı ödenir ve en fazla ne kadar süreyle uzaklaştırılabilir?",opts:["Maaşın tamamı, 6 ay","Maaşın yarısı, 3 ay","Maaşın 2/3'ü, 3 ay","Maaşın 2/3'ü, 6 ay"],ans:2,exp:"7068 sayılı Kanun: Görevden uzaklaştırılan memura maaşının 2/3'ü ödenir. Görevden uzaklaştırma süresi en fazla 3 aydır. Ayrıca ilçe emniyet amirinin görevden uzaklaştırma yetkisi yoktur."}
  ,{q:"PVSK kapsamında telekomünikasyon sinyal tespitinde hakim onayı kaç saat içinde alınmalıdır?",opts:["12 saat","24 saat","48 saat","72 saat"],ans:2,exp:"PVSK kapsamında önleyici amaçlı telekomünikasyon işlemlerinde birim amirinin kararından sonra 48 saat içinde hâkim onayı alınmalıdır. CMK kapsamında ise savcı talep eder ve derhal hâkim kararı aranır."}
  ,{q:"PVSK kapsamında telekomünikasyon sinyal tespiti ilk başta en fazla kaç ay için yapılabilir ve kaç kez uzatılabilir?",opts:["1 ay, 2 kez uzatma","2 ay, 2 kez uzatma","3 ay, 3 kez uzatma","6 ay, 1 kez uzatma"],ans:2,exp:"PVSK kapsamında telekomünikasyon sinyal tespiti ilk başta 3 ay için yapılabilir ve 3 kez uzatılabilir (toplamda 1 yıla kadar). CMK kapsamında ise 2 ay + 1 ay uzatma öngörülmüştür."}
  ,{q:"PVSK'ya göre kayıp çocuklar için alınan tedbirlerin süresi en fazla ne kadardır?",opts:["15 gün","1 ay","1 ay + 1 ay uzatma","6 ay"],ans:2,exp:"PVSK: Kayıp çocuklar için alınan tedbirler en çok 1 ay devam edebilir; gerektiğinde 1 ay daha uzatılabilir. Mülki amir (vali/kaymakam) karar verir; karar 24 saat içinde hâkim onayına sunulur."}
  ,{q:"Umuma açık yer ruhsatı için kolluk kaç gün içinde görüş bildirmelidir?",opts:["3 gün","7 gün","15 gün","30 gün"],ans:1,exp:"Umuma açık yer ruhsatı başvurularında kolluk, başvurudan itibaren 7 gün içinde görüşünü bildirmek zorundadır. Ruhsat işlemleri 1 ay içinde sonuçlandırılır; ruhsatı veren makam belediye veya il özel idaresidir."}
  ,{q:"Özel güvenlik görevlilerinin ilk temel eğitimi kaç ders saatinden oluşur?",opts:["60 ders saati","80 ders saati","100 ders saati","120 ders saati"],ans:3,exp:"Özel güvenlik görevlileri için ilk kez verilecek temel eğitim 120 ders saatidir. Yenileme eğitimi ise 60 ders saatidir. Özel güvenlik için en az ön lisans mezunu olma şartı aranır."}
  ,{q:"Büyükşehir belediye başkanlarının soruşturma iznini verme yetkisi kime aittir?",opts:["Valiye","Cumhurbaşkanı'na","İçişleri Bakanlığı'na","Adalet Bakanlığı'na"],ans:2,exp:"4483 sayılı Kanun: Büyükşehir belediye başkanları, il ve ilçe belediye başkanları ile büyükşehir ve ilçe belediye meclis üyeleri hakkında soruşturma iznini verme yetkisi İçişleri Bakanlığı'na aittir."}
  ,{q:"Mal bildiriminde bulunanlar ne zaman (periyodik) bildirim yapmakla yükümlüdür?",opts:["Her 5 yılda bir","Her 10 yılda bir","Sonu 0 ve 5 ile biten yıllarda, Şubat ayı sonuna kadar","Her yıl Ocak ayında"],ans:2,exp:"Mal Bildirimi Kanunu: Görevde bulunanlar sonu 0 ve 5 ile biten yıllarda (2020, 2025 gibi) en geç Şubat ayı sonuna kadar mal bildiriminde bulunur. 'Her 5 yılda bir' ifadesi yanlıştır; çünkü görev başlama yılına değil, 0/5 biten yıllara göre hesaplanır."}
  ,{q:"Kaç yaşını doldurmamış çocuklar hiçbir surette suç nedeniyle yakalanamaz?",opts:["10 yaş","12 yaş","15 yaş","18 yaş"],ans:1,exp:"CMK ve Çocuk Koruma Kanunu: 12 yaşını doldurmamış çocuklar hiçbir surette suç nedeniyle yakalanamaz ve suç tespiti yapılamaz. 12-18 yaş arasındakiler yakalanabilir ancak zorunlu müdafilik uygulanır."}
  ,{q:"15 yaşını doldurmamış çocuklara hangi durumlarda tutuklama kararı verilemez?",opts:["Hiçbir suçta tutuklama verilemez","Üst sınırı 3 yılı aşmayan suçlarda","Üst sınırı 5 yılı aşmayan suçlarda","Yalnızca taksirle işlenen suçlarda"],ans:2,exp:"CMK: 15 yaşını doldurmamış çocuklar hakkında üst sınırı 5 yılı aşmayan hapis cezası gerektiren suçlarda tutuklama kararı verilemez. Erteleme süresi 3 yıldır (5 yıl değil)."}
  ,{q:"Çocuk şüphelinin ifadesi alınırken müdafi konusunda doğru olan hangisidir?",opts:["Önce ifade alınır, ardından müdafi dinlenir","İfade ve müdafi aynı anda, birlikte yer alır","Müdafi ifade bittikten sonra rapora itiraz edebilir","Müdafi zorunlu değildir"],ans:1,exp:"CMK: Çocuk şüphelinin ifadesi müdafii hazır bulunurken birlikte alınır. 'Önce ifade, sonra müdafi' uygulaması hukuka aykırıdır. Çocuklar için müdafilik zorunludur ve talep aranmaz."}
  ,{q:"Silah taşıma ve bulundurma ruhsatına sahip kişiler yılda en fazla kaç adet mermi alabilir?",opts:["200 adet","500 adet","1000 adet","Sınır yoktur"],ans:2,exp:"6136 sayılı Kanun: Eski düzenlemede yılda 200 adet mermi alınabilirdi. İçişleri Bakanı kararıyla bu miktar 5 katına kadar artırılabilir; dolayısıyla azami miktar 1000 adete yükselmiştir."}
  ,{q:"Poligon işletme izin belgeleri kaç yıllığına düzenlenir?",opts:["2 yıl","3 yıl","5 yıl","10 yıl"],ans:2,exp:"6136 sayılı Kanun: Bakanlıkça verilen poligon işletme izin belgesi 5 yıllığına verilir. Poligonlarda 18 yaşını ikmal etmiş herkes, silah ruhsatı olup olmadığına bakılmaksızın atış yapabilir."}
  ,{q:"İl spor güvenlik kurulunun hangi üyesi bu kurulda yer almaz?",opts:["İl jandarma","İl emniyet","Sosyal Güvenlik İl Müdürü","Federasyon temsilcisi"],ans:2,exp:"Sporda Şiddet ve Düzensizliğin Önlenmesi Kanunu: İl spor güvenlik kurulunda il jandarma, il emniyet, il sağlık, gençlik ve spor il müdürlüğü, belediye, federasyon temsilcisi ve valiliğin hukukçuları yer alır. Sosyal Güvenlik İl Müdürü bu kurulda yer almaz."}

  // --- Kabahatler Kanunu (5326) ---
  ,{q:"5326 sayılı Kabahatler Kanunu'na göre suçüstü halinde idari para cezasına kim karar verebilir?",opts:["Yalnızca sulh ceza hâkimliği","Yalnızca savcı","Kolluk görevlisi","Vali onayıyla savcı"],ans:2,exp:"5326 sayılı Kabahatler Kanunu: Suçüstü halinde kolluk görevlisi bizzat idari para cezasına karar verebilir. Suçüstü dışındaki hallerde ise kanunda belirtilen yetkili makam (vali, belediye başkanı vb.) karar verir. İdari para cezasına itiraz için 15 gün içinde sulh ceza hâkimliğine başvurulur."}
  ,{q:"5326 sayılı Kabahatler Kanunu'nda öngörülen zamanaşımı süresi kaç yıldır?",opts:["1 yıl","2 yıl","3 yıl","5 yıl"],ans:2,exp:"5326 sayılı Kabahatler Kanunu m.20: Kabahatlerde zamanaşımı süresi 3 yıldır. Süre fiilin işlendiği tarihten itibaren işlemeye başlar. Zamanaşımı dolduğunda idari yaptırım kararı verilemez; verilmişse infaz edilemez."}
  ,{q:"Kabahatler Kanunu'na göre idari para cezasına itiraz nereye ve hangi sürede yapılır?",opts:["İdare mahkemesine, 30 gün içinde","Sulh ceza hâkimliğine, 15 gün içinde","Asliye ceza mahkemesine, 7 gün içinde","Cumhuriyet savcılığına, 10 gün içinde"],ans:1,exp:"5326 sayılı Kabahatler Kanunu: İdari para cezasına itiraz, kararın tebliğinden itibaren 15 gün içinde sulh ceza hâkimliğine yapılır. İtiraz kanun yolunun adı 'başvuru'dur; itiraz incelemesi duruşmasız yapılabilir."}

  // --- Terörle Mücadele Kanunu (3713) ---
  ,{q:"3713 sayılı TMK'ya göre terör suçlarında hâkim kararıyla gözaltı süresi en fazla kaç güne uzatılabilir?",opts:["4 gün","5 gün","6 gün","7 gün"],ans:3,exp:"3713 sayılı Terörle Mücadele Kanunu m.10: Terör suçlarında savcı kararıyla gözaltı 4 güne kadar uzatılabilir; hâkim kararıyla bu süre 7 güne kadar uzatılabilir. Normal suçlarda CMK m.91 kapsamında gözaltı en fazla 4 gündür."}
  ,{q:"TMK kapsamındaki gözaltı uzatma kararlarını hangi hâkim verir?",opts:["Sulh ceza hâkimi","Ağır ceza mahkemesi nöbetçi hâkimi","Asliye ceza hâkimi","Cumhuriyet savcısı"],ans:1,exp:"3713 sayılı TMK m.10: Terör suçlarında gözaltı süresinin uzatılması için Sulh Ceza Hâkimi değil, Ağır Ceza Mahkemesi nöbetçi hâkiminin kararı alınır. Bu, terör suçlarına özgü önemli bir ayrımdır."}
  ,{q:"3713 sayılı Kanun'a göre terör örgütü üyeliği suçunun ceza aralığı nedir?",opts:["2–5 yıl hapis","5–10 yıl hapis","8–12 yıl hapis","10–15 yıl hapis"],ans:1,exp:"3713 sayılı TMK: Terör örgütü üyesi olan kişi 5–10 yıl hapis cezasıyla cezalandırılır. Örgütü kuran/yöneten kişi 10–15 yıl hapis alır. Terör suçlarında ceza alt sınırından indirim yapılamaz ve erteleme uygulanmaz."}

  // --- Ailenin Korunması Kanunu (6284) ---
  ,{q:"6284 sayılı Kanun'a göre şiddet uygulayana verilen 'önleyici tedbir' kararı kim tarafından verilebilir?",opts:["Yalnızca mülki amir","Yalnızca aile mahkemesi hâkimi","Hem hâkim hem mülki amir","Cumhuriyet savcısı"],ans:1,exp:"6284 sayılı Ailenin Korunması Kanunu: Şiddet mağdurunu korumaya yönelik koruyucu tedbirler hem hâkim hem mülki amir tarafından verilebilirken, şiddet uygulayana yönelik önleyici tedbirler (uzaklaştırma, iletişim yasağı vb.) YALNIZCA aile mahkemesi hâkimi tarafından verilebilir."}
  ,{q:"6284 sayılı Kanun'a göre tedbir kararlarının azami süresi ne kadardır?",opts:["3 ay","6 ay","1 yıl","Süre sınırı yoktur"],ans:1,exp:"6284 sayılı Ailenin Korunması Kanunu m.8: Tedbir kararları kural olarak en fazla 6 ay süreyle verilir. Ancak zorunluluk halinde bu süre uzatılabilir. Tedbirlerin uzatılması için yeniden başvuru ve değerlendirme gerekir."}
  ,{q:"6284 sayılı Kanun kapsamında tedbir kararına aykırı davranan kişiye hangi yaptırım uygulanır?",opts:["3–10 gün zorlama hapsi","15–30 gün adli para cezası","1–3 ay hapis","Doğrudan tutuklama"],ans:0,exp:"6284 sayılı Ailenin Korunması Kanunu: Tedbir kararına aykırı davranış halinde 3–10 gün zorlama hapsi uygulanır. Aykırılığın tekrarında zorlama hapsinin süresi artırılır. Zorlama hapsi adli sicile işlenmez ve ceza niteliği taşımaz."}

  // --- Kaçakçılıkla Mücadele Kanunu (5607) ---
  ,{q:"5607 sayılı Kanun'a göre kaçakçılık konusu eşyanın müsaderesi nasıl uygulanır?",opts:["Zorunlu müsaderedir; hâkimin takdir yetkisi yoktur","İhtiyari müsaderedir; hâkim karar verir","Yalnızca değeri 100.000 TL'yi aşan eşya müsadere edilir","Müsadere yerine tazminat ödenir"],ans:0,exp:"5607 sayılı Kaçakçılıkla Mücadele Kanunu m.13: Kaçakçılık konusu eşyanın müsaderesi zorunludur; hâkimin takdir yetkisi bulunmamaktadır. Nakilde kullanılan araç ise örgütlü kaçakçılıkta zorunlu, bireysel kaçakçılıkta ihtiyari olarak müsadere edilebilir."}
  ,{q:"5607 sayılı Kanun'a göre örgütlü kaçakçılıkta temel ceza nasıl değiştirilir?",opts:["1/3 oranında artırılır","1/2 oranında artırılır","2 katına çıkarılır","Alt sınırdan ceza verilir"],ans:1,exp:"5607 sayılı Kaçakçılıkla Mücadele Kanunu: Kaçakçılık suçunun örgüt halinde, silahla veya resmi belge sahteciliğiyle işlenmesi halinde temel ceza 1/2 (yarı) oranında artırılır. Teşebbüs de tamamlanmış suç gibi cezalandırılır."}
  ,{q:"5607 sayılı Kanun'a göre akaryakıt kaçakçılığının temel cezası nedir?",opts:["1–3 yıl hapis","2–5 yıl hapis","3–7 yıl hapis","5–10 yıl hapis"],ans:1,exp:"5607 sayılı Kaçakçılıkla Mücadele Kanunu m.4: Akaryakıt kaçakçılığı (bant uygulamasını ihlal dahil) ve tütün mamulleri kaçakçılığı 2–5 yıl hapis cezasını gerektirmektedir. Kaçak malı satmak, bulundurmak veya nakletmek de aynı suç kapsamında değerlendirilir."}

  // --- Karayolları Trafik Kanunu (2918) ---
  ,{q:"2918 sayılı Karayolları Trafik Kanunu'na göre hafif taşıt sürücüleri için yasal alkol sınırı nedir?",opts:["0,20 promil","0,50 promil","0,80 promil","1,00 promil"],ans:1,exp:"2918 sayılı KTK m.48: Hafif taşıt sürücüleri için yasal alkol sınırı 0,50 promildir. Ticari araç sürücüleri ve kamu taşıtı kullananlar için ise bu sınır 0,20 promildir. 1,00 promil üzerinde TCK m.179 kapsamında suç oluşur."}
  ,{q:"Sürücünün kandaki alkol oranı 1,00 promili aşarsa hangi hüküm uygulanır?",opts:["Yalnızca idari para cezası","Ehliyete el koyma ve 2 ay yasaklama","TCK m.179 uyarınca cezai kovuşturma","Araç müsaderesi"],ans:2,exp:"2918 sayılı KTK m.48 ve TCK m.179: Sürücünün alkol oranı 1,00 promili aştığında idari işlemle kalmaz; TCK m.179 (trafik güvenliğini tehlikeye atma) kapsamında cezai kovuşturma başlatılır. 0,50–1,00 promil arası yalnızca idari yaptırıma tabidir."}
  ,{q:"2918 sayılı Kanun'a göre araç satışı sonrası tescil devri kaç gün içinde yapılmalıdır?",opts:["15 gün","30 gün","60 gün","90 gün"],ans:1,exp:"2918 sayılı Karayolları Trafik Kanunu: Araçların el değiştirmesi halinde tescil devri işleminin 30 gün içinde yapılması zorunludur. 30 günlük süre aşılırsa idari para cezası uygulanır. Tescil işlemleri İçişleri Bakanlığı'na bağlı trafik tescil birimlerince yürütülür."}

  // --- Tanık Koruma Kanunu (5726) ---
  ,{q:"5726 sayılı Tanık Koruma Kanunu'na göre koruma kararı kim tarafından ve hangi süreçle verilir?",opts:["Cumhuriyet savcısı tek başına karar verir","İçişleri Bakanı onayıyla verilir","Savcının talebi ve hâkimin onayıyla ağır ceza mahkemesi koruma kurulunca verilir","Jandarma komutanı tarafından verilir"],ans:2,exp:"5726 sayılı Tanık Koruma Kanunu m.4: Koruma kararı; Cumhuriyet savcısının talebi ve hâkimin onayıyla, ağır ceza mahkemesi bünyesinde oluşturulan koruma kurulu tarafından verilir. Savcı veya hâkim tek başına karar veremez."}
  ,{q:"5726 sayılı Kanun kapsamındaki en ağır tanık koruma tedbiri hangisidir?",opts:["Adres gizleme","Kılık değişikliği","Korunan konut sağlama","Kimlik değişikliği"],ans:3,exp:"5726 sayılı Tanık Koruma Kanunu m.3: Tanık koruma tedbirleri beş kademede uygulanır. En hafifi kimlik ve adres bilgilerinin gizlenmesi, en ağırı ise kimlik değişikliğidir. Kimlik değişikliği yalnızca istisnai durumlarda uygulanır."}
  ,{q:"5726 sayılı Kanun'a göre korunan tanığın kimlik bilgileri sanığa açıklanabilir mi?",opts:["Evet, savunma hakkı gereği sanık her zaman öğrenebilir","Hayır, sanığa ve hatta dosyaya bile gizli tutulabilir","Yalnızca mahkeme kararıyla sanığa açıklanabilir","Yargılama sona erince açıklanır"],ans:1,exp:"5726 sayılı Tanık Koruma Kanunu: Korunan tanığın kimlik bilgileri; sanığa, müdafiine ve hatta dosyaya bile gizli tutulabilir. Bu durum savunma hakkıyla gerilim yaratsa da tanığın güvenliği öncelik taşır. Tanık ses/görüntü bağlantısıyla da ifade verebilir."}

  // --- Pasaport Kanunu (5682) ---
  ,{q:"5682 sayılı Kanun'a göre pasaport hangi kurum tarafından düzenlenir?",opts:["Adalet Bakanlığı","Dışişleri Bakanlığı","İçişleri Bakanlığı","Cumhurbaşkanlığı"],ans:2,exp:"5682 sayılı Pasaport Kanunu: Pasaport, TC adına İçişleri Bakanlığı tarafından düzenlenir. Yurt dışında ise konsolosluklarca verilebilir. Pasaport bir kimlik belgesi değil, yurt dışına çıkış ve ülkeye giriş belgesidir."}
  ,{q:"5682 sayılı Kanun'a göre hususi pasaport (gri pasaport) kimlere verilir?",opts:["Tüm TC vatandaşlarına","Diplomatik göreve atananlara","Kamu görevlilerine ve ailelerine","Yalnızca büyükelçilere"],ans:2,exp:"5682 sayılı Pasaport Kanunu m.14: Hususi pasaport (gri) kamu görevlilerine ve ailelerine verilir. Umuma mahsus (bordo): tüm vatandaşlar. Hizmet (yeşil): kamu hizmetiyle yurt dışına gidenler. Diplomatik (siyah): diplomatik göreve atananlar."}
  ,{q:"5682 sayılı Kanun'a göre icra-iflas takibinde borçlu kişinin pasaportunun alınması için ne gerekir?",opts:["Savcılık kararı yeterlidir","Mahkeme kararı gerekir","İcra müdürlüğü kendiliğinden alabilir","Borç miktarının 100.000 TL'yi aşması gerekir"],ans:1,exp:"5682 sayılı Pasaport Kanunu m.22: İcra-iflas takibinde borçlu kişinin pasaportunun iptal edilmesi veya verilmemesi için mahkeme kararı gerekmektedir. Tutuklu/hükümlüler ise ayrıca karar olmaksızın doğrudan pasaport alamazlar."}

  // --- KVKK (6698) ---
  ,{q:"6698 sayılı KVKK'ya göre veri ihlali meydana geldiğinde veri sorumlusu KVK Kuruluna kaç saat içinde bildirim yapmak zorundadır?",opts:["24 saat","48 saat","72 saat","1 hafta"],ans:2,exp:"6698 sayılı Kişisel Verilerin Korunması Kanunu: Kişisel veri ihlalinin öğrenilmesi halinde veri sorumlusu, 72 saat içinde KVK Kuruluna bildirimde bulunmak zorundadır. İhlal ilgili kişileri de etkiliyorsa onlara da gecikmeksizin bildirim yapılmalıdır."}
  ,{q:"KVKK kapsamında Kişisel Verileri Koruma Kurulu kaç üyeden oluşur ve seçim dağılımı nasıldır?",opts:["7 üye; 4 TBMM, 3 Cumhurbaşkanı","9 üye; 5 TBMM, 4 Cumhurbaşkanı","11 üye; 6 TBMM, 5 Cumhurbaşkanı","7 üye; tamamı Cumhurbaşkanınca seçilir"],ans:1,exp:"6698 sayılı KVKK m.20: KVK Kurulu 9 üyeden oluşur. 5 üye TBMM tarafından, 4 üye Cumhurbaşkanı tarafından seçilir. Üyelerin görev süresi 4 yıldır; aynı kişi iki dönemden fazla üye seçilemez."}
  ,{q:"KVKK'ya göre sağlık verisi özel nitelikli kişisel veri kapsamında yalnızca kimler tarafından işlenebilir?",opts:["Sağlık personeli, koruyucu hekimlik ve tıbbi teşhis/tedavi hizmetleri kapsamında","Yalnızca hastaneler tarafından","Devlet kurumları tarafından serbestçe","Açık rıza olmaksızın hiçbir şekilde işlenemez"],ans:0,exp:"6698 sayılı KVKK m.6: Sağlık ve cinsel hayata ilişkin veriler, yeterli önlemler alınmak kaydıyla ve yalnızca sır saklama yükümlülüğü altındaki sağlık personeli tarafından kamu sağlığı, koruyucu hekimlik, tıbbi teşhis, tedavi ve bakım hizmetleri kapsamında işlenebilir."}

  // --- Kimlik Bildirme Kanunu (1774) ---
  ,{q:"1774 sayılı Kimlik Bildirme Kanunu'na göre konaklama yerleri misafir bilgilerini kaç saat içinde güvenlik birimine bildirmek zorundadır?",opts:["12 saat","24 saat","48 saat","72 saat"],ans:1,exp:"1774 sayılı Kimlik Bildirme Kanunu m.1–2: Otel, motel, pansiyon ve benzeri konaklama yerleri; misafirin giriş tarihinden itibaren 24 saat içinde kimlik bilgilerini yetkili güvenlik birimine (emniyet veya jandarma) bildirmek zorundadır. Hem Türk hem yabancı misafirler bildirim kapsamındadır."}
  ,{q:"1774 sayılı Kanun'a göre kimlik bildirme kayıtları en az kaç yıl muhafaza edilmelidir?",opts:["2 yıl","3 yıl","5 yıl","10 yıl"],ans:2,exp:"1774 sayılı Kimlik Bildirme Kanunu m.3–4: Konaklama yerlerince tutulan kimlik kayıtları en az 5 yıl süreyle muhafaza edilmek zorundadır. Elektronik bildirim sistemleri (GÖÇ-NET vb.) üzerinden yapılan bildirimler de bu kapsama girer."}
  ,{q:"1774 sayılı Kimlik Bildirme Kanunu'nun denetim ve yaptırım boyutunda hangi ifade doğrudur?",opts:["Denetim yalnızca belediyeye aittir; yaptırım adli para cezasıdır","Denetim emniyet ve jandarmaya aittir; yaptırım idari para cezasıdır","Denetim valiliklere aittir; yaptırım lisans iptalidir","Denetim Ticaret Bakanlığı'na aittir"],ans:1,exp:"1774 sayılı Kimlik Bildirme Kanunu m.6: Konaklama yerlerinin kimlik bildirme yükümlülüğünü yerine getirip getirmediğini denetleme yetkisi emniyet ve jandarma birimlerine aittir. Yükümlülüğü ihlal eden işletme sahiplerine idari para cezası uygulanır."}

  // --- Devlet Memurları Kanunu (657) ---
  ,{q:"657 sayılı Devlet Memurları Kanunu'na göre memur olabilmek için gereken asgari öğrenim düzeyi nedir?",opts:["İlköğretim mezunu olmak","Ortaöğretim (lise) mezunu olmak","Ön lisans mezunu olmak","Lisans mezunu olmak"],ans:1,exp:"657 sayılı Devlet Memurları Kanunu m.48: Memur olabilmek için asgari şart en az ortaöğretim (lise) mezunu olmaktır. Ancak göreve göre daha yüksek öğrenim şartı aranabilir. PAEM gibi yükseköğretim gerektiren kadrolarda ise ön lisans/lisans mezuniyeti aranır."}
  ,{q:"657 sayılı Kanun'a göre 'devlet memurluğundan çıkarma' cezasına hangi kurul karar verir?",opts:["Disiplin kurulu","Yüksek disiplin kurulu","Danıştay","İdare mahkemesi"],ans:1,exp:"657 sayılı Devlet Memurları Kanunu m.125: Devlet memurluğundan çıkarma en ağır disiplin cezasıdır ve Yüksek Disiplin Kurulu tarafından verilir. Uyarma, kınama ve aylıktan kesme cezalarına ilgili disiplin kurulları karar verir; çıkarma kararı ise doğrudan Yüksek Disiplin Kuruluna aittir."}
  ,{q:"657 sayılı Kanun'a göre 10 yılı aşkın kıdeme sahip memurun yıllık izin süresi kaç gündür?",opts:["14 gün","20 gün","25 gün","30 gün"],ans:3,exp:"657 sayılı Devlet Memurları Kanunu m.177: Devlet memurlarının yıllık izin hakkı kıdeme göre farklılaşır: 1–10 yıl kıdem için 20 gün, 10 yılı aşkın kıdem için 30 gündür. Üst görevlerde fiilen görev yapanlara bu süreler uygulanır."}

  // --- Türk Vatandaşlığı Kanunu (5901) ---
  ,{q:"5901 sayılı Türk Vatandaşlığı Kanunu'na göre doğumla vatandaşlık kazanımında birincil ilke nedir?",opts:["Soy bağı (neseple kazanım)","Doğum yeri (ius soli)","Evlat edinme","Cumhurbaşkanı kararı"],ans:0,exp:"5901 sayılı Türk Vatandaşlığı Kanunu m.6–7: Türk vatandaşlığının doğumla kazanılmasında birincil ilke soy bağıdır (ius sanguinis/neseple kazanım). TC vatandaşı anne veya babanın çocuğu, doğum yeri ne olursa olsun Türk vatandaşı olur. Doğum yeri ilkesi yalnızca tamamlayıcı niteliktedir."}
  ,{q:"5901 sayılı Kanun'a göre evlenme yoluyla Türk vatandaşlığı kazanmak için evliliğin en az kaç yıl sürmesi gerekir?",opts:["1 yıl","2 yıl","3 yıl","5 yıl"],ans:2,exp:"5901 sayılı Türk Vatandaşlığı Kanunu m.16: Yabancı eşin Türk vatandaşlığı kazanabilmesi için TC vatandaşıyla en az 3 yıl evli kalmak, evlilik birliği içinde birlikte yaşamak ve başvuruda bulunmak gerekmektedir. Evliliğin devam etmesi zorunludur; boşanma halinde vatandaşlık kaybedilmez ancak başvuru hakkı düşer."}
  ,{q:"5901 sayılı Kanun'a göre yetkili makam kararıyla Türk vatandaşlığı kazanmak için gereken asgari ikamet süresi ne kadardır?",opts:["2 yıl","3 yıl","4 yıl","5 yıl"],ans:3,exp:"5901 sayılı Türk Vatandaşlığı Kanunu m.11: Yetkili makam kararıyla (normal yoldan) vatandaşlık kazanmak için Türkiye'de kesintisiz 5 yıl ikamet etmek zorunludur. Bunun yanı sıra medeni hal bakımından yeterlilik, TC vatandaşlığıyla bağdaşmayan suç kaydı olmama ve vatandaşlığa alınmanın uygun görülmesi şartları da aranır."}

  // --- Resmî Yazışma Yönetmeliği ---
  ,{q:"Resmî Yazışma Yönetmeliği'ne göre resmî yazının zorunlu bölüm sayısı kaçtır?",opts:["5","6","8","10"],ans:2,exp:"Resmî Yazışmalarda Uygulanacak Usul ve Esaslar Hakkında Yönetmelik: Resmî yazının 8 zorunlu bölümü bulunmaktadır: Başlık, Sayı ve Tarih, Konu, Gönderilen Makam, Metin, İmza, Ekler ve Dağıtım. Bu bölümlerin hepsinin doğru biçimde doldurulması zorunludur."}
  ,{q:"Resmî Yazışma Yönetmeliği'ne göre 'paraf' ne anlama gelir?",opts:["Amirin belgeyi onayladığını gösteren resmi mühür","Yetkili imzadan önce hazırlayan/inceleyen kişilerin koyduğu onay işareti","İmza yetkisi olmayan birinin belgeyi imzalaması","Belgenin gizli olduğunu gösteren işaret"],ans:1,exp:"Resmî Yazışma Yönetmeliği: Paraf; resmî yazıyı hazırlayan veya inceleyen yetkililerin, yazıyı imzalayacak makam imzalamadan önce belgeyi incelediklerini ve uygun bulduklarını gösteren onay işaretidir. Paraf, imzadan farklı olup belgeyi hazırlayanın sorumluluğunu yansıtır."}
  ,{q:"Resmî Yazışma Yönetmeliği'nde 'onay' ve 'olur' belgeleri arasındaki fark nedir?",opts:["İkisi aynı belgedir","Onay makam içi; olur üst makamdan alınan yazılı izindir","Olur daha resmî; onay gayri resmîdir","Onay yalnızca bakanlıklarda kullanılır"],ans:1,exp:"Resmî Yazışma Yönetmeliği: Onay belgesi, aynı kurum/makam içinde yapılacak işlemlerde amirin onayını almak için kullanılan iç belgedir. Olur ise bir işlem veya eylem için üst makamdan yazılı izin alınmasına yarayan belgedir. 'Onur' makam içi, 'Olur' üst makama yönelik olduğundan birbirinden farklıdır."}
],
idare:[
  {q:"İdare hukukunda 'yetki' unsurundaki sakatlık işlemi nasıl etkiler?",opts:["İptal edilebilir veya yokluğa sürükler","Sadece geciktirir","Hiçbir etkisi yoktur","İşlemi kesinleştirir"],ans:0,exp:"Yetki, idari işlemin kim tarafından yapılacağını belirler. Ağır yetki ihlalleri işlemi yokluğa sürükler; hafif ihlaller ise işlemi iptal edilebilir kılar."},
  {q:"Tam yargı davası ile iptal davasının temel farkı nedir?",opts:["İkisi aynıdır","İptal davası işlemi kaldırır; tam yargı davası tazminat içerir","Tam yargı davası Danıştay'da açılır","İptal davası özel mahkemede görülür"],ans:1,exp:"İptal davası hukuka aykırı idari işlemin ortadan kaldırılmasını sağlar. Tam yargı davası ise idarenin eylem ve işlemleri nedeniyle uğranılan zararın tazmini için açılır."},
  {q:"İdari işlemin unsurları nelerdir?",opts:["Sadece konu ve yetki","Yetki, şekil, sebep, konu, amaç","Yetki ve amaç yeterlidir","Şekil ve sebep zorunludur"],ans:1,exp:"İdari işlemin beş unsuru; yetki, şekil, sebep, konu ve amaçtır. Bu unsurlardan herhangi birindeki sakatlık işlemi iptal edilebilir veya yokluğa sürükler."},
  {q:"İdari yargı düzeni içindeki üst mahkeme hangisidir?",opts:["Yargıtay","Anayasa Mahkemesi","Danıştay","Uyuşmazlık Mahkemesi"],ans:2,exp:"Danıştay, idari yargı düzeninin en üst mahkemesi ve temyiz merciidir. İlk derece mahkemesi olarak da görev yapar; bazı davalarda Danıştay doğrudan ilk ve son derece mahkemesi olarak yetkilidir."},
  {q:"'Hukuki güvenlik ilkesi' idare hukukunda ne anlama gelir?",opts:["İdarenin her kararı lehte vermesi","İdari işlemlerin belirli, öngörülebilir ve istikrarlı olması","İdarenin hiçbir zaman hata yapmaması","Tüm işlemlerin yazılı olması"],ans:1,exp:"Hukuki güvenlik ilkesi; bireylerin devletle ilişkilerini güvenle sürdürebilmeleri için idari işlemlerin belirli, öngörülebilir ve tutarlı olmasını gerektirir. Geriye yürümezlik de bu ilkenin bir sonucudur."},
  {q:"Yetki genişliği ilkesi nedir?",opts:["Merkezden yönetimin güçlendirilmesi","Taşra amirine merkez adına karar alma yetkisi tanınması","Yerel yönetimlerin bağımsızlığı","Valinin yargı yetkisi kullanması"],ans:1,exp:"Yetki genişliği; merkezden yönetimin sakıncalarını azaltmak amacıyla taşra amirine (vali gibi) bazı konularda merkez adına karar alma yetkisi tanınmasıdır. 5442 sayılı Kanun m.9'da düzenlenmiştir."},
  {q:"Ombudsman (Kamu Denetçisi) kararları bağlayıcı mıdır?",opts:["Evet, kesinlikle bağlayıcıdır","Hayır, tavsiye niteliğindedir","Sadece belirli davalarda bağlayıcıdır","Mahkeme onayıyla bağlayıcı olur"],ans:1,exp:"Kamu Denetçiliği Kurumu (KDK) kararları bağlayıcı değildir; tavsiye niteliği taşır. İdare, kararı aldıktan sonra 30 gün içinde yanıt vermek zorundadır."},
  {q:"İdari para cezalarının adli sicile işlenmesi hakkında ne söylenebilir?",opts:["Her zaman işlenir","Hiçbir zaman işlenmez","Sadece ağır cezalar işlenir","Savcı kararıyla işlenir"],ans:1,exp:"İdari para cezaları idari yaptırım niteliğinde olup adli sicile işlenmez; ceza niteliği taşımaz. Ödenmemesi halinde 6183 sayılı Amme Alacaklarının Tahsil Usulü Hakkında Kanun kapsamında tahsil edilir."},
  {q:"'Takdir yetkisi' ne anlama gelir?",opts:["İdarenin kanuna aykırı karar verebilmesi","İdarenin kanun çerçevesinde birden fazla hukuka uygun seçenek arasında tercih yapabilmesi","İdarenin yargısal denetimden muaf olması","İdarenin keyfi karar alabilmesi"],ans:1,exp:"Takdir yetkisi; kanunun birden fazla hukuka uygun seçeneğe izin verdiği durumlarda idarenin hangisini tercih edeceğine karar verebilmesidir. Ancak takdir yetkisi de hukuk sınırları içinde kullanılmalıdır."},
  {q:"İdare mahkemelerinde dava açma süresi kural olarak kaç gündür?",opts:["30 gün","60 gün","90 gün","1 yıl"],ans:1,exp:"İdari Yargılama Usulü Kanunu m.7: İdari dava açma süresi, idari işlemin tebliğinden itibaren kural olarak 60 gündür. Vergi mahkemelerinde bu süre 30 gün, bazı özel kanunlarda farklı süreler öngörülmüştür."},
  {q:"Yürütmenin durdurulması için hangi şartlar birlikte aranır? (2025 PAEM)",opts:["Sadece telafisi güç zarar","Açıkça hukuka aykırılık VE telafisi güç zarar","Siyasi nitelik ve kamu düzeni","Kanuna aykırılık ve kamu yararı ihlali"],ans:1,exp:"İYUK m.27: Açıkça hukuka aykırılık + telafisi güç zarar. Her iki şart birlikte aranır."},
  {q:"İdari makamlara başvuruya 30 gün içinde cevap verilmezse ne olur? (2025 PAEM)",opts:["İdari makam yeni cevap verme yükümlülüğü altına girer","İstek reddedilmiş sayılır ve dava açılabilir","İstek kabul edilmiş sayılır","Dava doğrudan Danıştay'a açılır"],ans:1,exp:"İYUK m.10/2: Cevap verilmezse istek reddedilmiş sayılır."},
  {q:"İdari işlemin hukuki sonucunu ifade eden unsur hangisidir? (2025 PAEM)",opts:["Yetki","Sebep","Amaç","Konu"],ans:3,exp:"İdari işlemin unsurları: Yetki, Şekil, Sebep, Konu (hukuki sonuç), Amaç."},

  ,
  // --- İdare Hukuku Video 1'den eklenen sorular ---
  {q:"Cumhurbaşkanlığına bağlı 2025 yılında eklenen yeni kurum hangisidir?",opts:["Dijital Dönüşüm Ofisi","Siber Güvenlik Kurumu","İnsan Kaynakları Ofisi","Yatırım Ofisi"],ans:1,exp:"2025 yılında Cumhurbaşkanlığına bağlı kurum olarak Siber Güvenlik Kurumu eklenmiştir. Böylece CB'na bağlı kurum sayısı 11'e yükselmiştir. Ayrıca 2025'te 4 olan CB ofisleri 1'e (Yatırım ve Finans Ofisi) indirilmiş ve İdari İşler Başkanlığı, Genel Sekreterliğe dönüştürülmüştür."},
  {q:"Cumhurbaşkanlığı ofisi kaç tanedir ve adı nedir?",opts:["4 adet — Dijital, Finans, Yatırım, İnsan Kaynakları","1 adet — Yatırım ve Finans Ofisi","3 adet — FİDYE kodlamasıyla bilinir","2 adet — Yatırım Ofisi ve Finans Ofisi"],ans:1,exp:"2025 öncesinde 4 adet CB ofisi (FİDYE kodlaması) mevcuttu. 2025 yılında bunların tamamı birleştirilerek tek bir Cumhurbaşkanlığı Yatırım ve Finans Ofisi oluşturulmuştur. Bu ofis özel bütçelidir, kamu tüzel kişiliği vardır, merkezi Ankara'dadır."},
  {q:"Cumhurbaşkanlığı politika kurulu sayısı kaçtır?",opts:["8","9","10","12"],ans:2,exp:"2025 itibarıyla Cumhurbaşkanlığı politika kurulları 10 adettir: Bilim ve Teknoloji, Eğitim ve Öğretim, Ekonomi, Güvenlik, Hukuk, Kültür, Sağlık, Sosyal ve Gençlik, Tarım ve Gıda, Yerel Yönetim ve Afet Politikaları Kurulları."},
  {q:"CB'na bağlı kurumlardan hangilerinin kamu tüzel kişiliği vardır?",opts:["Diyanet İşleri Başkanlığı ve MİT","Savunma Sanayii Başkanlığı ve Türkiye Varlık Fonu","Milli Saraylar İdaresi ve Strateji ve Bütçe Başkanlığı","DDK ve İletişim Başkanlığı"],ans:1,exp:"CB'na bağlı kurumlar arasında kamu tüzel kişiliğine sahip olanlar Savunma Sanayii Başkanlığı ve Türkiye Varlık Fonu'dur. Cumhurbaşkanlığı Yatırım ve Finans Ofisi de kamu tüzel kişiliğine sahiptir."},
  {q:"Cumhurbaşkanlığı İdari İşler Başkanlığı'nın 2025'teki yeni adı nedir?",opts:["Cumhurbaşkanlığı Ofisi","Cumhurbaşkanlığı Genel Sekreterliği","Cumhurbaşkanlığı Koordinasyon Merkezi","Cumhurbaşkanlığı Stratejik Yönetim Birimi"],ans:1,exp:"Cumhurbaşkanlığı İdari İşler Başkanlığı, 2025 yılında yapılan değişiklikle Cumhurbaşkanlığı Genel Sekreterliği olarak yeniden adlandırılmıştır. Görev ve yetkilerinde değişiklik olmamış, yalnızca isim değişikliği gerçekleşmiştir."},
  {q:"Yer bakımından yerinden yönetim kuruluşlarında hizmet ve yer açısından durum nedir?",opts:["Hizmet sınırlı, yer sınırsız","Hizmet sınırsız, yer sınırsız","Hizmet sınırsız, yer sınırlı","Hem hizmet hem yer sınırsız"],ans:2,exp:"Yer bakımından yerinden yönetim kuruluşları (belediye, il özel idaresi, köy), kendi mülki sınırları içinde her türlü hizmeti sunabilir. Bu nedenle hizmet çeşidi sınırsız, ancak hizmetin götürüleceği coğrafi alan sınırlıdır. Hizmet bakımından kuruluşlarda ise tam tersi geçerlidir."},
  {q:"Hiyerarşi ile idari vesayet arasındaki temel fark nedir?",opts:["Hiyerarşi yalnızca merkezde, idari vesayet yalnızca taşrada uygulanır","Hiyerarşide üst astın yerine geçebilir; idari vesayette vesayet makamı yetki ikame edemez","İdari vesayet daha güçlü bir denetim aracıdır","Aralarında hukuki fark yoktur"],ans:1,exp:"Hiyerarşi, aynı tüzel kişilik içindeki üst-ast ilişkisidir; üst makam astın işlemini re'sen değiştirebilir ve onun yerine geçebilir. İdari vesayette ise merkezi idare, yerinden yönetim kuruluşları üzerinde sınırlı denetim uygular; vesayet makamı işlemi yalnızca onaylayabilir veya iptal edebilir, yerine geçemez."},
  {q:"Suç teşkil eden bir emrin yerine getirilmesi için ne gerekir?",opts:["Üstün yazılı emri yeterlidir","Hiçbir koşulda yerine getirilemez","İkinci bir üstün onayı gerekir","Savcılığa bildirildikten sonra yerine getirilebilir"],ans:1,exp:"Anayasa m.137: Hukuka aykırı emirler üst ısrar edip yazılı hale getirirse yerine getirilebilir (sorumluluk emri verene ait). Ancak suç teşkil eden emirler yazılı hale getirilse bile yerine getirilemez. Yerine getiren memur cezai sorumluluktan kurtulamaz."}
  ,
  // --- İdare Hukuku Video 2'den eklenen sorular ---
  {q:"Cumhurbaşkanlığı Genel Sekreterliği'nin kaç hizmet birimi (genel müdürlüğü) vardır ve bunların kodlaması nedir?",opts:["3 birim — HGK","4 birim — HKPG","5 birim — Personel, Güvenlik, Destek, Koruma, Hukuk","6 birim — PEGDKH"],ans:2,exp:"CB Genel Sekreterliği'nin 5 hizmet birimi vardır: Personel Prensipleri GM, Güvenlik İşleri GM, Destek ve Mali Hizmetler GM, Koruma Hizmetleri GM, Hukuk ve Mevzuat GM. Kodlama: 'Personel, Güvenliğe Destek Ver, Koru Hukuku'."},
  {q:"Resmi Gazete'nin yayımlanması hangi birimin görevidir?",opts:["Güvenlik İşleri Genel Müdürlüğü","Destek ve Mali Hizmetler Genel Müdürlüğü","Hukuk ve Mevzuat Genel Müdürlüğü","Personel Prensipleri Genel Müdürlüğü"],ans:2,exp:"Hukuk ve Mevzuat Genel Müdürlüğü, kanunların ve CBK'ların yayımlanmasına ilişkin işlemleri yapar ve Resmi Gazete'nin yayımlanmasını sağlar. Ayrıca kanunların AYM'ye uygunluğunu inceler ve ceza hafifletme kararlarını Adalet Bakanlığı'na bildirir."},
  {q:"Cumhurbaşkanının korunması hangi birimin görevidir?",opts:["Güvenlik İşleri Genel Müdürlüğü","Koruma Hizmetleri Genel Müdürlüğü","Milli İstihbarat Teşkilatı","Personel Prensipleri Genel Müdürlüğü"],ans:1,exp:"CB, ailesi, CB Yardımcıları, Bakanlar ve Genel Sekreterin korunması Koruma Hizmetleri Genel Müdürlüğü'nün görevidir. Güvenlik İşleri GM ise devletin güvenlik politika ve stratejilerini belirler — bunlar birbirine karıştırılan sınav tuzaklarıdır."},
  {q:"CB özel kalem müdürü ile özel temsilci arasında büyükelçilik unvanı konusundaki fark nedir?",opts:["Her ikisine de büyükelçilik unvanı verilir (zorunlu)","Özel kalem müdürüne büyükelçilik unvanı verilir (zorunlu), özel temsilciye verilebilir (ihtiyari)","Her ikisine de büyükelçilik unvanı verilebilir (ihtiyari)","Hiçbirine büyükelçilik unvanı verilmez"],ans:1,exp:"Özel kalem müdürüne büyükelçi unvanı verilir (emredici — zorunlu). Özel temsilciye ise büyükelçi unvanı verilebilir (ihtiyari). Özel temsilcinin unvanı, temsilcilik görevi süresince devam eder; görev sona erince unvan da sona erer."},
  {q:"Cumhurbaşkanı özel kalem müdürünün temel görevleri arasında hangisi yer almaz?",opts:["CB'nin resmi ve özel yazışmalarını yürütmek","Tören ve yurt içi/dışı gezileri düzenlemek","Devletin güvenlik politika ve stratejilerini belirlemek","Protokol ve halkla ilişkiler hizmetlerini yürütmek"],ans:2,exp:"Devletin güvenlik politika ve stratejilerini belirlemek Güvenlik İşleri Genel Müdürlüğü'nün görevidir, özel kalem müdürünün değil. Özel kalem müdürünün görevleri: yazışmalar, tören/gezi organizasyonu, protokol, halkla ilişkiler, milli saraylar ve devlet arşivlerine ilişkin talimatlar."},
  {q:"Kanun ile Cumhurbaşkanlığı Kararnamesi çelişirse hangi kural uygulanır?",opts:["CBK üstündür, çünkü daha sonra çıkarılmıştır","Kanun üstündür, CBK hükümsüz kalır","Anayasa Mahkemesi karar verir","Cumhurbaşkanı hangisini tercih ederse o uygulanır"],ans:1,exp:"Anayasa m.104: Kanun ile CBK aynı konuda farklı hükümler içerirse kanunun hükmü uygulanır ve CBK hükümsüz kalır. TBMM aynı konuda sonradan kanun çıkarırsa da CBK kendiliğinden hükümsüz olur. Kanunların üstünlüğü ilkesi geçerlidir."},
  {q:"CB Genel Sekreteri hakkında hangisi doğrudur?",opts:["Bakanlara karşı sorumludur","En yüksek devlet memurudur ve CB'na karşı sorumludur","Milletvekilliği sona ermeksizin bu göreve atanabilir","TBMM tarafından seçilir"],ans:1,exp:"CB Genel Sekreteri en yüksek devlet memurudur. Genel Sekreterliğin en üst amiri olup Cumhurbaşkanına karşı sorumludur. Tüm birimlerin faaliyetlerini, işlemlerini ve hesaplarını denetleme görevi ve yetkisi vardır."}
  ,
  // --- İdare Hukuku Video 3'ten eklenen sorular ---
  {q:"Bakanlıkların kurulması ve kaldırılması hangi işlemle gerçekleşir?",opts:["Kanunla","Cumhurbaşkanlığı kararnamesiyle","TBMM kararıyla","Bakanlar Kurulu kararıyla"],ans:1,exp:"Bakanlıkların kurulması, kaldırılması, görev ve yetkileri, teşkilat yapısı ile merkez ve taşra teşkilatının kurulması Cumhurbaşkanlığı kararnamesiyle düzenlenir. Adalet Bakanlığı tek istisnadır — bu bakanlık ismi Anayasa'da geçtiğinden CBK ile kaldırılamaz."},
  {q:"Her bakanlıkta en fazla kaç bakan müşaviri istihdam edilebilir?",opts:["10","12","15","20"],ans:2,exp:"2025 yılında yapılan düzenlemeyle bakanlık başına en fazla 15 bakan müşaviri istihdam edilebilir. Bakan müşavirleri istisnai memurluktur; sınav ve kademe kurallarına tabi olmaksızın atanırlar ve görevleri bakanın görev süresiyle sınırlıdır."},
  {q:"Bakan müşavirinin görevi ne zaman sona erer?",opts:["Cumhurbaşkanı kararıyla","Bakanın görev süresi sona erdiğinde veya görevden alındığında","5 yıllık görev süresinin sonunda","TBMM kararıyla"],ans:1,exp:"Bakan müşaviri doğrudan bakana bağlı çalışır ve görevi bakanın görev süresiyle sınırlıdır. Bakan değiştiğinde müşavirlerin de görevi sona erer. Eski kamu görevlisi olan müşavirler görev bitiminden itibaren en geç 1 ay içinde eski kadrolarına atanır."},
  {q:"Bakan müşaviri görevden ayrıldıktan sonra eski kadrosuna en geç ne zaman atanır?",opts:["2 hafta","1 ay","3 ay","6 ay"],ans:1,exp:"Kamu görevlisi iken bakan müşavirliğine atananlar, görevleri sona erdiğinde veya görevden alındıklarında en geç 1 ay içinde eski kadro ve pozisyonlarına atanır. Atama tamamlanana kadar mali ve sosyal hakları ödenmeye devam eder."},
  {q:"Cumhurbaşkanlığı makamının ani boşalması halinde vekalet eden kimdir?",opts:["CB'nın önceden belirlediği CB Yardımcısı","En yaşlı CB Yardımcısı","TBMM Başkanı","Adalet Bakanı"],ans:1,exp:"CB makamının herhangi bir nedenle ani boşalması (ölüm, istifa, mahkumiyet vb.) halinde yenisi seçilene kadar en yaşlı CB Yardımcısı vekalet eder. Bu kural kaos çıkmaması için yaşa dayalıdır. Geçici ayrılmalarda (yurt dışı, hastalık) ise CB'nın görevlendirdiği yardımcı vekalet eder."},
  {q:"Bir bakan 'göreviyle ilgili olmayan' bir suç işlerse hangi hükümden yararlanır?",opts:["Yasama dokunulmazlığından yararlanamaz","Yüce Divan'da yargılanır","Yasama dokunulmazlığından yararlanır","Görevinden derhal uzaklaştırılır"],ans:2,exp:"CB Yardımcıları ve Bakanlar, görevleriyle ilgili olmayan suçlarda yasama dokunulmazlığından yararlanır (devlet hizmetlerinin sürekliliği için). Görevleriyle ilgili suçlarda ise meclis soruşturmasına ve Yüce Divan'a sevk söz konusu olabilir."},
  {q:"CB Genel Sekreterliği'nin koruma personelini nasıl temin eder?",opts:["Doğrudan Emniyet Genel Müdürlüğü'nden atar","Genel Sekreterin talebi üzerine İçişleri Bakanlığı Emniyet/Jandarma/Sahil Güvenlik mensupları arasından görevlendirir","CB'nın onayıyla Millî İstihbarat'tan sağlar","Özel güvenlik firmaları ile sözleşme yapar"],ans:1,exp:"Koruma Hizmetleri Genel Müdürlüğü personeli; CB Genel Sekreterinin talebi üzerine, İçişleri Bakanlığı tarafından Emniyet, Jandarma ve Sahil Güvenlik sınıflarına mensup personel arasından görevlendirilir."},
  // --- İdare Hukuku Ek Sorular ---
  {q:"Milletlerarası antlaşmalar Anayasa'ya aykırılık iddiasıyla AYM'ye taşınabilir mi?",opts:["Evet, her antlaşma denetlenebilir","Hayır, antlaşmanın kendisi denetlenemez; ancak TBMM uygun bulma kanunu AYM denetimine tabidir","Evet, yalnızca ceza hükmü içerenler denetlenir","Hayır, AYM'nin milletlerarası antlaşmalarla hiçbir ilgisi yoktur"],ans:1,exp:"Anayasa m.90: Usulüne uygun onaylanmış antlaşmaların kendisi AYM'ye götürülemez. Ancak TBMM'nin uygun bulma kanunu iptal davasına konu olabilir. 'Antlaşma değil, onay kanunu denetlenir' ayrımı sınavda kritik bir tuzaktır."},
  {q:"İdari vesayet kapsamında merkezi idare aşağıdaki yetkilerden hangisine sahip DEĞİLDİR?",opts:["Onay yetkisi","İptal yetkisi","Erteleme (yürütmeyi durdurma) yetkisi","Yerinden yönetim kuruluşu adına işlem yapma (yerine geçme) yetkisi"],ans:3,exp:"İdari vesayet yetkileri üç türlüdür: 1) Onay (işlem onaysız yürürlüğe giremez), 2) İptal (işlemin kaldırılması), 3) Erteleme (yürütmenin durdurulması). Merkezi idare yerinden yönetim kuruluşu adına re'sen işlem YAPAMAZ — bu temel hiyerarşiden fark. Hiyerarşide üst, astın yerine geçebilir; vesayette geçemez."},
  {q:"Türkiye'de yer bakımından yerinden yönetim kuruluşları hangileridir?",opts:["Üniversiteler, baro ve kamu iktisadi teşebbüsleri","İl özel idaresi, belediye ve köy","Valilik, kaymakamlık, bucak","Bakanlıklar ve müsteşarlıklar"],ans:1,exp:"Yer bakımından yerinden yönetim kuruluşları: il özel idaresi, belediye ve köy. Her üçü kamu tüzel kişiliğine sahiptir. Üniversiteler ise hizmet bakımından yerinden yönetim kuruluşlarıdır. Köyün tüzel kişiliği sınavda dikkat çeken detaydır — köy muhtarlığı köyün organıdır, ayrı bir tüzel kişilik değildir."},
  {q:"İdari hiyerarşi ile idari vesayet arasındaki temel ayrım için hangisi doğrudur?",opts:["Her ikisi de farklı tüzel kişilikler arasında uygulanır","Hiyerarşi aynı tüzel kişilik içinde uygulanır; vesayet farklı tüzel kişilikler arasında","İdari vesayet daha güçlü bir denetimdir; üst astın işlemini re'sen değiştirebilir","Aralarında hukuki fark yoktur"],ans:1,exp:"Hiyerarşi, aynı idari tüzel kişilik içindeki üst-ast ilişkisidir; üst astın işlemini bozabilir, değiştirebilir, yerine geçebilir. İdari vesayet ise farklı kamu tüzel kişilikleri arasındaki denetimdir; vesayet makamı sınırlı denetim yapar, yerinden yönetim kuruluşunun yerine geçemez."}

  // --- İdare Hukuku Tamamlama Soruları ---
  ,{q:"İdari işlemler 'kapsam' bakımından ikiye ayrılır. Bu ayrım nedir?",opts:["Yazılı-sözlü işlemler","Düzenleyici (genel) işlemler ve bireysel (özel) işlemler","Bağlı-takdiri işlemler","Zorunlu-ihtiyari işlemler"],ans:1,exp:"İdari işlemler kapsam bakımından: (1) Düzenleyici (genel-soyut) işlemler: yönetmelik, tüzük, genelge gibi herkese uygulanabilir. (2) Bireysel (somut-özel) işlemler: belirli kişi veya olayı etkileyen atama, lisans verme, para cezası gibi işlemler. Bu ayrım, idari yargıda dava açma ve yürütmeyi durdurma şartları bakımından önem taşır."}
  ,{q:"İYUK'a göre idari yargıda üç temel dava türü nelerdir?",opts:["İptal davası, tam yargı davası, tespit davası","İptal davası, tam yargı davası, idari sözleşmelerden doğan davalar","Hukuka uygunluk davası, tazminat davası, yürütme durdurma davası","İptal davası, itiraz davası, temyiz davası"],ans:1,exp:"İYUK m.2: İdari yargıda üç dava türü vardır: (1) İptal davası: hukuka aykırı idari işlemin iptali. (2) Tam yargı davası: idari eylem ve işlemlerden doğan zarar için tazminat. (3) İdari sözleşmelerden doğan davalar: kamu ihale sözleşmesi, imtiyaz sözleşmesi gibi uyuşmazlıklar. Tespit davası idari yargıda yer almaz."}
  ,{q:"İdare hukuku kapsamında 'hizmet kusuru' ile 'kişisel kusur' arasındaki fark nedir?",opts:["Her ikisi de kişisel sorumluluğu doğurur","Hizmet kusuru kamu görevlisinin şahsına; kişisel kusur idareye yüklenir","Hizmet kusurunda devlet sorumludur; kişisel kusurda kamu görevlisi bireysel olarak sorumludur","İkisi arasında hukuki fark yoktur"],ans:2,exp:"Hizmet kusuru: İdarenin örgütlenme, işleyiş veya donanımındaki aksaklıktan kaynaklanan kusur; devlet tam yargı davasıyla sorumlu tutulur. Kişisel kusur: Kamu görevlisinin göreviyle bağlantısı bulunmayan veya özel yaşamına ait davranışı; görevli doğrudan kişisel sorumluluk taşır. Ayrımın önemi: devlete dava mı, bireye dava mı açılacağını belirler."}
  ,{q:"Danıştay hangi davalara ilk derece mahkemesi sıfatıyla bakar?",opts:["Tüm idari davalara","Yalnızca temyiz mercii olarak görev yapar","Cumhurbaşkanlığı kararnamelerine karşı açılan davalar ile bakanlıkların düzenleyici işlemleri","Kanunda sayılan belirli davalara (kamu hizmet sözleşmeleri, bakanlık işlemleri vb.)"],ans:3,exp:"Danıştay hem temyiz mercii hem de kanunda sayılan belirli davalarda ilk derece mahkemesidir. İlk derece sıfatıyla baktığı başlıca davalar: bakanlar, vali ve büyükelçiler hakkında açılan davalar; Cumhurbaşkanlığı Kararnameleri; birden fazla idare mahkemesinin yetki alanına giren davalar."}
  ,{q:"5393 sayılı Belediye Kanunu'na göre belediye başkanı nasıl seçilir ve görev süresi kaç yıldır?",opts:["Belediye meclisi tarafından, 4 yıl","Halk tarafından doğrudan, 5 yıl","Halk tarafından doğrudan, 4 yıl","Vali tarafından atanır, 5 yıl"],ans:2,exp:"5393 sayılı Belediye Kanunu: Belediye başkanı halk tarafından doğrudan seçilir. Görev süresi yerel yönetim seçim dönemiyle örtüşür ve 5 yılda bir yapılan seçimlerle yenilenir (2019 değişikliğiyle 4 yıldan 5 yıla çıkarılmıştır). Atama değil, seçimle iş başına gelir."}
  ,{q:"İdari sözleşmelerde idarenin 'tek taraflı değişiklik yetkisi' ne anlama gelir?",opts:["İdare sözleşmeyi istediği zaman feshedebilir","İdare kamu yararı gerektiğinde sözleşme koşullarını müteahhide danışmadan değiştirebilir; ancak müteahhit tazminat talep hakkını korur","Müteahhit de idareyle eş yetkiye sahiptir","Bu yetki yalnızca imtiyaz sözleşmelerinde kullanılır"],ans:1,exp:"İdari sözleşmelerde idarenin ayrıcalıklı yetkilerinden biri tek taraflı değişiklik yetkisidir. Kamu yararı gerektirdiğinde idare, müteahhidin rızası olmaksızın edim ve koşulları değiştirebilir. Ancak bu değişiklik müteahhidin mali denge hakkını ortadan kaldırmaz; mali denge bozulmuşsa tazminat talep edilebilir."}
  ,{q:"Acele kamulaştırma kararı hangi makam tarafından ve hangi durumlarda alınabilir?",opts:["Bakanlar Kurulu kararıyla, olağanüstü hallerde","Cumhurbaşkanı kararıyla, kamu yararının acil gerektirdiği durumlarda","Vali kararıyla, afet hallerinde","Danıştay kararıyla, yargısal zorunluluk halinde"],ans:1,exp:"2942 sayılı Kamulaştırma Kanunu m.27: Acele kamulaştırma, kamu yararının ivedi biçimde gerektirdiği hallerde Cumhurbaşkanı kararıyla yapılır. Acele kamulaştırmada bedel tespiti ve tescil için 7 gün içinde mahkemeye başvurulur; tapuya şerh konularak mülkiyet önceden teslim alınabilir."}
  ,{q:"İdari yargılama usulünde 'itiraz yolu' (üst idareye başvuru) dava açma süresini nasıl etkiler?",opts:["Dava açma süresini 30 gün uzatır","Üst idareye başvurulması halinde dava açma süresi durur; cevap verme ya da 30 günlük susma süresi sonunda yeniden işlemeye başlar","Dava açma süresini tamamen ortadan kaldırır","Etkisi yoktur; süreler ayrı ayrı işler"],ans:1,exp:"İYUK m.11: Kesin olmayan bir işleme karşı üst makama ya da aynı makama başvuru yapılabilir. Başvuru yapılması dava açma süresini durdurur. Başvuru reddedilirse veya 30 gün içinde cevap verilmezse kalan dava açma süresi kaldığı yerden işlemeye devam eder. Toplam süre 60 günü geçemez."}
  ,{q:"Kamu hizmetinin 'süreklilik' ilkesi grevle nasıl bağdaştırılır?",opts:["Kamu hizmetinde greve hiçbir şekilde izin verilmez","Süreklilik ilkesi gereği tüm kamu görevlileri greve gidemez; memurların grevi anayasaca yasaktır","Tüm kamu çalışanları grev hakkına sahiptir","Yalnızca emniyet mensupları greve gidemez"],ans:1,exp:"Kamu hizmetinin süreklilik ilkesi, hizmetin kesintisiz yürütülmesini gerektirir. Anayasa m.54: Grev hakkı özel sektör işçilerine tanınmıştır. Devlet memurları ise 657 sayılı Kanun ve Anayasa m.128 çerçevesinde greve gidemez. Sözleşmeli personel ve işçi statüsündeki kamu çalışanları için farklı düzenlemeler mevcuttur."}
],
gelkul:[
  {q:"Türkiye Cumhuriyeti'nin başkenti ve kuruluş yılı nedir?",opts:["İstanbul – 1920","Ankara – 1923","Ankara – 1920","İstanbul – 1923"],ans:1,exp:"Türkiye Cumhuriyeti 29 Ekim 1923'te ilan edilmiştir. Başkent olarak Ankara seçilmiş; İstanbul'un 470 yıllık başkentliği sona ermiştir. 'Cumhuriyet' kelimesinin anlamı 'halk yönetimi'dir."},
  {q:"Türkiye'nin yüzölçümü ve kıtalar arası konumu hakkında doğru bilgi hangisidir?",opts:["~500.000 km², yalnızca Asya","~783.000 km², yalnızca Avrupa","~783.000 km², hem Asya (Anadolu) hem Avrupa (Trakya)","~1.000.000 km², Orta Doğu"],ans:2,exp:"Türkiye'nin yüzölçümü yaklaşık 783.562 km²'dir. Topraklarının %97'si Anadolu (Asya), %3'ü Trakya (Avrupa) kıtasındadır. Bu köprü konumu tarihsel, kültürel ve stratejik açıdan büyük önem taşır."},
  {q:"Türkiye'nin en uzun nehri ve Anadolu'da tamamen Türkiye sınırları içinde akan en uzun nehir hangisidir?",opts:["Fırat","Dicle","Kızılırmak","Sakarya"],ans:2,exp:"Kızılırmak (~1355 km), tamamen Türkiye sınırları içinde akan en uzun nehirdir. Fırat ise Türkiye'den geçen en uzun nehirdir ancak Suriye ve Irak'a da uzanır. Kızılırmak Karadeniz'e dökülür."},
  {q:"Türkiye'nin üç kıyıya komşu denizleri hangileridir?",opts:["Karadeniz, Ege, Akdeniz","Karadeniz, Marmara, Hazar","Ege, Akdeniz, Kızıldeniz","Marmara, Adriyatik, Ege"],ans:0,exp:"Türkiye kuzeyinde Karadeniz, batısında Ege Denizi ve güneyinde Akdeniz ile çevrilidir. Ayrıca kuzeybatıda dört kıyıya kapalı bir iç deniz olan Marmara Denizi de Türkiye topraklarıyla çevrilidir."},
  {q:"Mustafa Kemal Atatürk'ün Türk tarihine kazandırdığı en önemli inkılap hangisi DEĞİLDİR?",opts:["Harf devrimi (1928)","Tevhid-i Tedrisat Kanunu (1924)","Cumhuriyet'in ilanı (1923)","NATO'ya üyelik (1952)"],ans:3,exp:"NATO'ya üyelik 1952'de gerçekleşmiştir; Atatürk 1938'de vefat etmiştir. Harf devrimi (1928), Tevhid-i Tedrisat (1924), Cumhuriyet'in ilanı (1923) Atatürk döneminin inkılaplarıdır."},
  {q:"Türkiye'de kaç il bulunmaktadır ve son eklenen il hangisidir?",opts:["78 il – Bartın","80 il – Kilis","81 il – Düzce","81 il – Osmaniye"],ans:2,exp:"Türkiye'de 81 il bulunmaktadır. 1999 Marmara depremi sonrasında Sakarya'dan ayrılan Düzce, en son eklenen 81. ildir. Toplam ilçe sayısı 922'dir."},
  {q:"Türkiye'de zorunlu eğitim kaç yıldır ve sistemi nasıldır?",opts:["8 yıl – 4+4","10 yıl – 5+5","12 yıl – 4+4+4","14 yıl – 4+4+4+2"],ans:2,exp:"2012 yılında yapılan düzenlemeyle zorunlu eğitim 8 yıldan 12 yıla çıkarılmıştır. Sistem: 4 yıl ilkokul + 4 yıl ortaokul + 4 yıl lise = 12 yıl (4+4+4 sistemi)."},
  {q:"Anadolu'da kurulan ilk Türk devletleri hangileridir?",opts:["Osmanlı ve Selçuklu","Büyük Selçuklu ve Anadolu Selçuklu","Anadolu Selçuklu ve Osmanlı","Karamanoğulları ve Osmanlı"],ans:2,exp:"Anadolu'da kurulan önemli Türk devletleri: Anadolu Selçukluları (1075-1308) ve akabinde Osmanlı Devleti (1299-1922). Büyük Selçuklu İran merkezi olup Anadolu Selçuklularının ayrı bir koldur."},
  {q:"Türkiye'nin yönetim sistemi nasıl tanımlanır?",opts:["Parlamenter monarşi","Federal cumhuriyet","Üniter cumhuriyet","Başkanlık federasyonu"],ans:2,exp:"Türkiye üniter (tekçi) cumhuriyet yönetim biçimine sahip demokratik bir devlettir. 2018 yılında Cumhurbaşkanlığı Hükümet Sistemi'ne geçilmiş; ancak üniter yapı korunmuştur. Federasyon değil, tek merkezli yönetim uygulanmaktadır."},
  {q:"INTERPOL'ün merkezi nerede ve Türkiye bu örgüte üye midir?",opts:["New York – Evet","Cenevre – Hayır","Lyon (Fransa) – Evet","Brüksel – Evet"],ans:2,exp:"INTERPOL (Uluslararası Kriminal Polis Örgütü) genel merkezi Lyon, Fransa'dadır. Türkiye INTERPOL üyesidir. Emniyet Genel Müdürlüğü bünyesindeki INTERPOL Türkiye Millî Merkez Bürosu koordinasyonu yürütür."},
  {q:"Türkiye'nin para birimi ve Merkez Bankası'nın bulunduğu şehir hangisidir?",opts:["Türk Lirası – İstanbul","Türk Lirası – Ankara","Kuruş – İzmir","Yeni Lira – İstanbul"],ans:1,exp:"Türkiye'nin para birimi Türk Lirası (TL)'dir. Türkiye Cumhuriyet Merkez Bankası 1930 yılında kurulmuş olup Ankara'da faaliyet göstermektedir. Para politikasını bağımsız olarak yürütür."},
  {q:"Türkiye'de seçme ve seçilme yaşı kaçtır?",opts:["18 – 25","18 – 18","21 – 25","18 – 30"],ans:1,exp:"2017 Anayasa değişikliğiyle hem seçme hem milletvekili seçilme yaşı 18'dir. Cumhurbaşkanı olabilmek için ise 40 yaşını doldurmak gerekir."},
  {q:"Boğazlar rejimini düzenleyen Montrö Sözleşmesi hangi yılda imzalanmıştır?",opts:["1923","1936","1945","1952"],ans:1,exp:"Montrö Sözleşmesi 20 Temmuz 1936'da imzalanmış, aynı yıl yürürlüğe girmiştir. Türkiye'ye İstanbul ve Çanakkale Boğazları'nın yönetimi üzerinde egemenlik hakkı tanımış; savaş gemilerinin geçişini sınırlandırmıştır."},
  {q:"Türkiye Anayasa Mahkemesi hangi yılda kurulmuştur?",opts:["1950","1961","1973","1982"],ans:1,exp:"Türkiye Anayasa Mahkemesi 1961 Anayasası ile kurulmuş ve 1962 yılında fiilen faaliyete geçmiştir. 1982 Anayasası ile yapısı yeniden düzenlenmiş; 2010 anayasa değişikliğiyle bireysel başvuru yetkisi de tanınmıştır."},
  {q:"Türkiye OECD'ye hangi yıl katılmıştır?",opts:["1948","1955","1961","1973"],ans:2,exp:"Türkiye, OECD'nin (Ekonomik İşbirliği ve Kalkınma Örgütü) 1961'deki kuruluşunda imzacı ve kurucu üyeler arasında yer almıştır. OECD merkezi Paris'tedir ve yaklaşık 38 üye ülkeden oluşmaktadır."},
  {q:"Türkiye'de idare mahkemelerinin kararlarını temyiz eden yüksek mahkeme hangisidir?",opts:["Yargıtay","Anayasa Mahkemesi","Danıştay","Uyuşmazlık Mahkemesi"],ans:2,exp:"Danıştay, idare mahkemelerinin kararlarını temyizen inceleyen en yüksek idare mahkemesidir. 1868'de kurulmuştur. Aynı zamanda bazı uyuşmazlıklarda ilk derece mahkemesi olarak da görev yapar."},
  {q:"Türkiye G20'ye hangi yılda katılmış ve dönem başkanlığını hangi yılda üstlenmiştir?",opts:["1999 katılım – 2015 başkanlık","2000 katılım – 2010 başkanlık","1999 katılım – 2010 başkanlık","2005 katılım – 2020 başkanlık"],ans:0,exp:"G20, 1999 yılında kurulmuş olup Türkiye kurucu üyeler arasındadır. Türkiye G20 dönem başkanlığını 2015 yılında üstlenmiştir. Zirve Antalya'da düzenlenmiştir."},
  {q:"Türkiye'nin BM'ye üyelik yılı kaçtır?",opts:["1945","1949","1952","1955"],ans:0,exp:"Türkiye BM'nin (Birleşmiş Milletler) kurucu üyeleri arasında yer almakta olup örgüte 1945 yılında katılmıştır. BM Şartı 26 Haziran 1945'te imzalanmış, 24 Ekim 1945'te yürürlüğe girmiştir."},
  {q:"Türkiye Büyük Millet Meclisi'nin mevcut binasının mimarı kimdir?",opts:["Vedat Tek","Mimar Sinan","Clemens Holzmeister","Mimar Kemaleddin"],ans:2,exp:"TBMM'nin mevcut binası Avusturyalı mimar Clemens Holzmeister tarafından tasarlanmış; 1961 yılında hizmete girmiştir. Holzmeister Türkiye'de pek çok önemli yapının da mimarıdır."},
  {q:"Türkiye'nin Interpol üyeliği ve Interpol'ün merkezi hakkında hangisi doğrudur?",opts:["Türkiye üye değildir – Cenevre","Türkiye üyedir – Lyon (Fransa)","Türkiye üyedir – New York","Türkiye üyedir – Brüksel"],ans:1,exp:"INTERPOL (Uluslararası Kriminal Polis Örgütü) genel merkezi Lyon, Fransa'dadır. Türkiye INTERPOL üyesidir. Emniyet Genel Müdürlüğü bünyesindeki INTERPOL Türkiye Millî Merkez Bürosu koordinasyonu yürütür."},
  // --- Genel Kültür Ek Sorular (21.03.2026) ---
  {q:"Türkiye'nin 7 coğrafi bölgesi doğru olarak hangisinde verilmiştir?",opts:["Marmara, Ege, Akdeniz, Karadeniz, İç Anadolu, Doğu Anadolu, Güneydoğu Anadolu","Marmara, Ege, Akdeniz, Karadeniz, İç Anadolu, Orta Anadolu, Doğu Anadolu","Trakya, Ege, Akdeniz, Karadeniz, Orta, Doğu, Güneydoğu","Marmara, Ege, Akdeniz, Karadeniz, İç Anadolu, Kuzey Anadolu, Doğu Anadolu"],ans:0,exp:"Türkiye 1941 Birinci Coğrafya Kongresi kararıyla 7 coğrafi bölgeye ayrılmıştır: Marmara, Ege, Akdeniz, Karadeniz, İç Anadolu, Doğu Anadolu ve Güneydoğu Anadolu. Bu bölge adları sınavda sıklıkla karışık verilir; 'Güneydoğu' ile 'Doğu' ayrımına dikkat edilmelidir."},
  {q:"Türkiye'nin en yüksek dağı ve yüksekliği nedir?",opts:["Erciyes Dağı – 3.917 m","Kaçkar Dağı – 3.937 m","Ağrı Dağı – 5.137 m","Süphan Dağı – 4.058 m"],ans:2,exp:"Ağrı Dağı 5.137 m yüksekliğiyle Türkiye'nin en yüksek dağıdır. Doğu Anadolu Bölgesi'nde İran sınırına yakın konumdadır. İkinci en yüksek dağ Doğu Karadeniz'deki Kaçkar Dağı'dır (3.937 m)."},
  {q:"TÜİK'in açılımı nedir ve temel görevi nedir?",opts:["Türkiye Uluslararası İstatistik Kurumu — dış ticaret verileri","Türkiye İstatistik Kurumu — resmî istatistikleri derlemek ve yayımlamak","Türkiye İktisadi İzleme Kurumu — ekonomik raporlar","Türkiye İnsan Kaynakları Kurumu — istihdam istatistikleri"],ans:1,exp:"TÜİK (Türkiye İstatistik Kurumu), Cumhurbaşkanlığı'na bağlı olup ülkenin resmî istatistiklerini (nüfus sayımı, enflasyon, işsizlik, GSYH, dış ticaret vb.) derleyen ve yayımlayan kurumdur. Bağımsız istatistik üretim yetkisine sahiptir."},
  {q:"SGK (Sosyal Güvenlik Kurumu) hangi üç kuruluşun birleşmesiyle oluşturulmuştur?",opts:["Sadece SSK ve Bağ-Kur","SSK, Bağ-Kur ve Emekli Sandığı","SSK ve Emekli Sandığı","İş-Kur, SSK ve Bağ-Kur"],ans:1,exp:"SGK 2006 yılında kurulmuş; SSK (işçiler), Bağ-Kur (esnaf ve sanatkârlar) ve Emekli Sandığı (devlet memurları) olmak üzere üç ayrı sosyal güvenlik kuruluşu tek çatı altında birleştirilmiştir. Amaç sistemi bütünleştirmek ve mali sürdürülebilirliği sağlamaktır."},
  {q:"Aşağıdakilerden hangisi Türkiye'nin UNESCO Dünya Mirası Listesi'ndeki alanlarından biridir?",opts:["Çanakkale Savaş Anıtları","Göbeklitepe","Atatürk Orman Çiftliği","Topkapı Sarayı dış avlusu"],ans:1,exp:"Göbeklitepe (Şanlıurfa) 2018 yılında UNESCO Dünya Mirası Listesi'ne alınmıştır. MÖ 10.000-8.000 yıllarına tarihlenen bu taş tapınak kompleksi, bilinen en eski anıtsal yapı olarak kabul edilmektedir. Türkiye'den ayrıca Hattuşa, Efes, Nemrut Dağı ve Pamukkale-Hierapolis da listede yer almaktadır."},
  {q:"Türkiye'nin en kalabalık coğrafi bölgesi hangisidir?",opts:["İç Anadolu","Ege","Marmara","Akdeniz"],ans:2,exp:"Marmara Bölgesi, İstanbul başta olmak üzere Bursa, Kocaeli, Tekirdağ gibi büyük sanayi ve ticaret merkezlerini barındırmasıyla Türkiye'nin en kalabalık bölgesidir. İstanbul tek başına yaklaşık 15-16 milyon nüfusuyla ülke nüfusunun yaklaşık beşte birini oluşturur."},
  {q:"ÖSYM'nin bağlı olduğu üst kurul ve temel görevi nedir?",opts:["Millî Eğitim Bakanlığı — okul sınavları düzenlemek","Yükseköğretim Kurulu (YÖK) — YKS, KPSS, TUS gibi ulusal sınavları düzenlemek","Hazine ve Maliye Bakanlığı — personel seçme sınavları","Cumhurbaşkanlığı — devlet memuru sınavları"],ans:1,exp:"ÖSYM (Ölçme, Seçme ve Yerleştirme Merkezi) Yükseköğretim Kurulu'na (YÖK) bağlıdır. YKS (üniversite), KPSS (kamu personeli), TUS (tıp uzmanlığı), DGS, YDS, ALES gibi ülkenin en kritik sınavlarını yürütür."}
  // --- Genel Kültür Tamamlama Soruları ---
  ,{q:"NATO hangi yılda kurulmuş ve Türkiye hangi yılda katılmıştır?",opts:["1945 kuruldu — 1945 katıldı","1949 kuruldu — 1952 katıldı","1949 kuruldu — 1955 katıldı","1952 kuruldu — 1952 katıldı"],ans:1,exp:"NATO 4 Nisan 1949'da Washington'da kurulmuştur. Türkiye kurucu üyeler arasında yer almamakla birlikte Yunanistan ile birlikte 18 Şubat 1952'de ittifaka katılmıştır. NATO merkezi Brüksel'dedir. Türkiye NATO'nun ikinci büyük ordusuna sahiptir."}
  ,{q:"Türkiye kaç ülkeyle kara sınırı paylaşmaktadır?",opts:["6","7","8","9"],ans:2,exp:"Türkiye 8 ülkeyle kara sınırı paylaşmaktadır: Batıda Yunanistan ve Bulgaristan; kuzeydoğuda Gürcistan, Ermenistan ve Azerbaycan'ın Nahçıvan özerk cumhuriyeti; doğuda İran; güneyde Irak ve Suriye. Toplam kara sınırı uzunluğu yaklaşık 2.628 km'dir."}
  ,{q:"Türkiye'de büyükşehir belediyesi sayısı kaçtır?",opts:["16","20","30","35"],ans:2,exp:"2012 yılında 6360 sayılı Kanun ile büyükşehir belediyesi sayısı 16'dan 30'a çıkarılmıştır. Bu düzenlemeyle 30 ilde il sınırının tamamı belediye sınırı olarak kabul edilmiş; köy ve il özel idareleri bu illerde kaldırılmıştır."}
  ,{q:"Polis Akademisi hangi bakanlığa bağlıdır?",opts:["Adalet Bakanlığı","İçişleri Bakanlığı","Millî Eğitim Bakanlığı","Cumhurbaşkanlığı"],ans:1,exp:"Polis Akademisi İçişleri Bakanlığı'na bağlıdır. Emniyet teşkilatı için lisansüstü eğitim, araştırma ve geliştirme faaliyetleri yürütür. PAEM (Polis Amirleri Eğitim Merkezi) komiser yardımcısı yetiştiren birim olarak Polis Akademisi bünyesinde yer almaktadır."}
  ,{q:"Jandarma Genel Komutanlığı hangi bakanlığa bağlıdır?",opts:["Millî Savunma Bakanlığı","İçişleri Bakanlığı","Cumhurbaşkanlığı","Adalet Bakanlığı"],ans:1,exp:"2017 yılında 696 sayılı KHK ile Jandarma Genel Komutanlığı Millî Savunma Bakanlığı'ndan ayrılarak İçişleri Bakanlığı'na bağlanmıştır. Sahil Güvenlik Komutanlığı da aynı tarihte İçişleri Bakanlığı'na bağlanmıştır."}
  ,{q:"Türk polis teşkilatının resmi kuruluş tarihi olarak kabul edilen gün hangisidir?",opts:["23 Nisan 1920","29 Ekim 1923","10 Nisan 1845","3 Mart 1924"],ans:2,exp:"10 Nisan 1845'te kurulan Zaptiye Müşirliği modern Türk polis teşkilatının öncüsü olarak kabul edilir. Bu nedenle 10 Nisan her yıl Türk Polis Teşkilatı'nın kuruluş yıldönümü olarak kutlanmakta; polis haftası 10-16 Nisan tarihleri arasında düzenlenmektedir."}
  ,{q:"Birleşmiş Milletler'in 2024 itibarıyla toplam üye sayısı kaçtır?",opts:["177","185","193","197"],ans:2,exp:"BM'nin 2024 itibarıyla 193 üye devleti bulunmaktadır. Güney Sudan 2011'de en son katılan üye olmuştur. Vatikan ve Filistin BM'de gözlemci statüsüne sahiptir; tam üye değildir. BM genel merkezi New York'tadır."}
  ,{q:"Türkiye'nin 2024 itibarıyla yaklaşık nüfusu kaçtır?",opts:["75 milyon","82 milyon","85 milyon","92 milyon"],ans:2,exp:"TÜİK verilerine göre Türkiye'nin 2024 yılı nüfusu yaklaşık 85 milyon kişidir. Türkiye nüfus büyüklüğü bakımından Avrupa'nın en kalabalık ülkeleri arasındadır. En kalabalık il yaklaşık 15-16 milyon ile İstanbul'dur."}
  ,{q:"Türk Bayrağı'nın düzenlendiği kanunun numarası ve temel özelliği nedir?",opts:["1593 sayılı — kırmızı zemin, beyaz hilal ve altı köşeli yıldız","2893 sayılı — kırmızı zemin, beyaz hilal ve beş köşeli yıldız","3201 sayılı — kırmızı-beyaz yatay şeritler","6136 sayılı — kırmızı zemin, altın hilal"],ans:1,exp:"Türk Bayrağı 2893 sayılı Türk Bayrağı Kanunu ile düzenlenmiştir. Kırmızı zemin üzerine beyaz renkli hilal ve beş köşeli yıldızdan oluşmaktadır. Bayrağın boyu eninin bir buçuk katı olmalıdır. Hilal ve yıldız birlikte kullanılır; ayrı ayrı kullanılamaz."}
  ,{q:"AFAD'ın açılımı nedir ve hangi bakanlığa bağlıdır?",opts:["Acil Faaliyet ve Afet Dairesi — Sağlık Bakanlığı","Afet ve Acil Durum Yönetimi Başkanlığı — İçişleri Bakanlığı","Afet Faaliyetleri Araştırma Dairesi — Çevre Bakanlığı","Afet Yönetimi Ajansı — Cumhurbaşkanlığı"],ans:1,exp:"AFAD (Afet ve Acil Durum Yönetimi Başkanlığı) İçişleri Bakanlığı'na bağlıdır. Doğal afetler, büyük yangınlar ve kimyasal/biyolojik tehditler gibi acil durumlarda koordinasyon ve kriz yönetiminden sorumludur. 2009 yılında kurulmuştur."}
  ,{q:"Diyanet İşleri Başkanlığı hangi makama bağlıdır?",opts:["İçişleri Bakanlığı","Millî Eğitim Bakanlığı","Cumhurbaşkanlığı","Adalet Bakanlığı"],ans:2,exp:"Diyanet İşleri Başkanlığı doğrudan Cumhurbaşkanlığı'na bağlıdır. 3 Mart 1924'te Şeyhülislamlık kaldırılarak kurulan Diyanet, İslam dinine ilişkin işleri yürütmek ve toplumu dinî konularda aydınlatmakla görevlidir."}
  ,{q:"YÖK (Yükseköğretim Kurulu) hangi yılda kurulmuştur?",opts:["1961","1973","1981","1992"],ans:2,exp:"YÖK 1981 yılında 2547 sayılı Kanun'la kurulmuştur. 12 Eylül 1980 sonrasında yükseköğretimi merkezi bir yapıya kavuşturmak amacıyla oluşturulmuştur. Türkiye'deki üniversitelerin planlanmasını, düzenlenmesini ve denetimini yürütür."}
  ,{q:"Türkiye'nin en büyük gölü hangisidir?",opts:["Beyşehir Gölü","Tuz Gölü","Van Gölü","Eğirdir Gölü"],ans:2,exp:"Van Gölü yaklaşık 3.713 km² yüzey alanıyla Türkiye'nin en büyük gölüdür. Doğu Anadolu'da yer alan bu sodalı göl aynı zamanda dünyanın en büyük sodalı göllerinden biridir. İkinci en büyük göl Tuz Gölü'dür (yaklaşık 1.500 km²)."}
  ,{q:"TRT (Türkiye Radyo ve Televizyon Kurumu) hangi yılda kurulmuştur?",opts:["1954","1964","1972","1990"],ans:1,exp:"TRT 1 Mayıs 1964'te 359 sayılı Kanun'la kurulmuştur. Cumhurbaşkanlığı'na bağlı kamu tüzel kişiliğine sahip bir yayın kuruluşudur. İlk televizyon yayını 1968'de başlamıştır. Türkiye'nin resmi ve ulusal yayın kuruluşudur."}
  ,{q:"Sahil Güvenlik Komutanlığı hangi bakanlığa bağlıdır?",opts:["Millî Savunma Bakanlığı","İçişleri Bakanlığı","Ulaştırma ve Altyapı Bakanlığı","Dışişleri Bakanlığı"],ans:1,exp:"Sahil Güvenlik Komutanlığı 2017'de Millî Savunma Bakanlığı'ndan ayrılarak İçişleri Bakanlığı'na bağlanmıştır. Türk karasularında güvenlik, kaçakçılık önleme, göçmen kurtarma, arama-kurtarma ve çevre koruma görevlerini üstlenir."}
  ,{q:"Osmanlı Devleti hangi yılda kurulmuştur?",opts:["1071","1243","1299","1453"],ans:2,exp:"Osmanlı Devleti 1299 yılında Osman Bey tarafından Söğüt'te kurulmuştur. 1453'te İstanbul'u fetheden Fatih Sultan Mehmed ile dünya gücü haline gelmiş; 1922'ye kadar yaklaşık 600 yıl varlığını sürdürmüştür. 1071 Malazgirt Muharebesi ise Anadolu'nun Türklere açılmasını sağlamıştır."}
  ,{q:"Türkiye İnsan Hakları ve Eşitlik Kurumu'nun (TİHEK) kısa adı ve kuruluş yılı nedir?",opts:["İHKB — 2004","TİHEK — 2016","TBMM İHK — 2012","HRD — 2010"],ans:1,exp:"TİHEK (Türkiye İnsan Hakları ve Eşitlik Kurumu) 6701 sayılı Kanun ile 2016 yılında kurulmuştur. İnsan hakları ihlalleri ile ayrımcılık başvurularını incelemek ve denetlemek temel görevidir. İnsan Hakları Kurumu ve Ayrımcılıkla Mücadele Kurulu birleştirilerek oluşturulmuştur."}
  ,{q:"Türkiye'deki sivil toplum kuruluşlarını (dernekler, vakıflar) denetleme görevi hangi birime aittir?",opts:["Adalet Bakanlığı","İçişleri Bakanlığı bünyesindeki Sivil Toplumla İlişkiler Genel Müdürlüğü","Cumhurbaşkanlığı Hukuk ve Mevzuat GM","Hazine ve Maliye Bakanlığı"],ans:1,exp:"Dernek, vakıf ve kooperatif gibi sivil toplum kuruluşlarının tescil, denetim ve desteklenmesi işlemleri İçişleri Bakanlığı bünyesindeki Sivil Toplumla İlişkiler Genel Müdürlüğü tarafından yürütülmektedir. Bu birim dernekler sicilini tutar ve denetimleri gerçekleştirir."}
  ,{q:"Türkiye yüzölçümü bakımından Avrupa ülkeleri arasında kaçıncı sıradadır?",opts:["Rusya'dan sonra ikinci","En büyük","Fransa'dan sonra ikinci","Üçüncü"],ans:0,exp:"Türkiye yaklaşık 783.000 km² yüzölçümüyle Rusya'dan sonra Avrupa ülkeleri arasında en büyük ülkedir. Topraklarının yalnızca %3'ü (Trakya) Avrupa kıtasında yer alsa da ülke coğrafi açıdan Avrupa'nın en büyüğüdür. Dünya genelinde ise yaklaşık 36. büyük ülkedir."}
  ,{q:"Türkiye'de e-Devlet kapısının koordinasyonunu hangi birim üstlenmektedir?",opts:["Hazine ve Maliye Bakanlığı","Ulaştırma ve Altyapı Bakanlığı","Cumhurbaşkanlığı Dijital Dönüşüm Ofisi","İçişleri Bakanlığı"],ans:2,exp:"e-Devlet kapısı ve dijital devlet hizmetleri Cumhurbaşkanlığı Dijital Dönüşüm Ofisi koordinasyonunda yürütülmektedir. Yaklaşık 60 milyonun üzerindeki kullanıcıya sahip e-Devlet platformu 7.000'den fazla kurumdan 10.000'i aşkın hizmet sunmaktadır."}
  ,{q:"Türk Standartları Enstitüsü (TSE) hangi bakanlığa bağlıdır?",opts:["Ticaret Bakanlığı","Sanayi ve Teknoloji Bakanlığı","Hazine ve Maliye Bakanlığı","Cumhurbaşkanlığı"],ans:1,exp:"TSE (Türk Standartları Enstitüsü) Sanayi ve Teknoloji Bakanlığı'na bağlıdır. Türk Standartları'nı (TS) hazırlar, yayımlar ve ISO, IEC gibi uluslararası standart kuruluşlarıyla koordinasyon sağlar. Ürün ve hizmetler için TSE belgelendirmesi ve laboratuvar hizmetleri sunar."}
  ,{q:"TBMM'nin mevcut binası hangi semtte ve hangi yılda hizmete girmiştir?",opts:["Ulus — 1923","Çankaya — 1950","Bakanlıklar — 1961","Kızılay — 1973"],ans:2,exp:"TBMM'nin mevcut binası Ankara'nın Bakanlıklar semtinde yer almaktadır. Avusturyalı mimar Clemens Holzmeister tasarımındaki bina 1961'de hizmete girmiştir. 1920-1960 yılları arasında kullanılan ilk bina ise bugün 'Birinci TBMM Binası' olarak müzeye dönüştürülmüştür."}
  ,{q:"Türkiye'nin zaman dilimi (saat dilimi) nedir?",opts:["UTC+2 (yaz saati uygulamasına göre değişir)","UTC+3 (sabit, yaz saati uygulanmaz)","UTC+4","UTC+2"],ans:1,exp:"Türkiye 2016 yılından itibaren yaz saati uygulamasını kaldırarak UTC+3 saat dilimine sabitlenmiştir. Daha önce kış mevsiminde UTC+2, yaz mevsiminde UTC+3 uygulanıyordu. Bu değişiklikle Türkiye her mevsim UTC+3'te kalmaktadır."}
],
guncel:[
  {q:"Türkiye'nin NATO'ya üyelik yılı hangisidir?",opts:["1945","1949","1952","1955"],ans:2,exp:"Türkiye 18 Şubat 1952'de Yunanistan ile birlikte NATO'ya katılmıştır. NATO 4 Nisan 1949'da kurulmuş olup Türkiye kurucu üyeler arasında bulunmamakla birlikte ilk genişleme döneminde ittifaka dahil olmuştur."},
  {q:"Türkiye Cumhuriyeti 2023 yılında kaçıncı kuruluş yıl dönümünü kutlamıştır?",opts:["75. yıl","90. yıl","100. yıl","110. yıl"],ans:2,exp:"Türkiye Cumhuriyeti 29 Ekim 2023'te 100. kuruluş yıl dönümünü kutlamıştır. Bu özel dönüm noktası 'Cumhuriyetin 100. Yılı' temasıyla çeşitli etkinlik ve törenlerle kutlanmıştır."},
  {q:"BM Güvenlik Konseyi'nin daimi üye sayısı kaçtır?",opts:["3","4","5","6"],ans:2,exp:"BM Güvenlik Konseyi'nin 5 daimi üyesi; ABD, Rusya, Çin, Fransa ve Birleşik Krallık'tır. Bu ülkeler veto hakkına sahiptir. Ayrıca 2 yıllık süreyle seçilen 10 geçici üye de bulunmaktadır."},
  {q:"Türkiye kaç ilden oluşmaktadır?",opts:["73","79","81","83"],ans:2,exp:"Türkiye 81 ilden oluşmaktadır. Coğrafi açıdan 7 bölgeye ayrılmış olup her ilin kendine bağlı ilçe ve köyleri bulunmaktadır. Yüzölçümü yaklaşık 783.562 km²'dir."},
  {q:"Avrupa Birliği'nin toplam üye sayısı kaçtır? (2024 itibarıyla)",opts:["25","27","28","30"],ans:1,exp:"İngiltere'nin 2020'de AB'den ayrılmasından (Brexit) sonra Avrupa Birliği 27 üye devletten oluşmaktadır. Türkiye 1987'de üyelik başvurusunda bulunmuş; müzakereler hâlâ resmi olarak sürmekle birlikte fiilen askıya alınmış durumdadır."},
  {q:"Türkiye hangi uluslararası örgütlerin üyesidir? (Aşağıdakilerden hangisi yanlıştır)",opts:["NATO","Avrupa Konseyi","AGİT","Avrupa Birliği"],ans:3,exp:"Türkiye NATO, Avrupa Konseyi, AGİT ve G20 üyesidir; ancak Avrupa Birliği üyesi değildir. AB üyelik müzakereleri 2005'te başlamış fakat büyük ölçüde askıya alınmış durumdadır."},
  {q:"10 Aralık hangi önemli günü temsil etmektedir?",opts:["BM Kuruluş Günü","Dünya İnsan Hakları Günü","Avrupa Konseyi Günü","NATO Günü"],ans:1,exp:"10 Aralık, İnsan Hakları Evrensel Beyannamesi'nin 1948'de ilan edildiği gündür ve her yıl Dünya İnsan Hakları Günü olarak kutlanmaktadır. Aynı zamanda Nobel Barış Ödülü de bu tarihte verilmektedir."},
  {q:"Türk Silahlı Kuvvetleri'nin NATO'daki kara kuvvetleri büyüklüğü açısından sıralaması nedir?",opts:["1. büyük","2. büyük","3. büyük","4. büyük"],ans:1,exp:"Türkiye, NATO içinde ABD'den sonra kara kuvvetleri büyüklüğü bakımından ikinci sıradadır. TSK yaklaşık 355.000 aktif personeliyle ittifakın önemli savunma güçlerinden birini oluşturmaktadır."},
  {q:"Türkiye'nin başkenti ve en kalabalık ili hangileridir?",opts:["İstanbul – İstanbul","Ankara – Ankara","Ankara – İstanbul","İstanbul – Ankara"],ans:2,exp:"Türkiye'nin başkenti 13 Ekim 1923'ten bu yana Ankara'dır. Nüfus açısından en kalabalık il ise yaklaşık 15-16 milyon nüfusuyla İstanbul'dur. Ankara nüfus büyüklüğünde ülke genelinde ikinci sıradadır."},
  {q:"Avrupa İnsan Hakları Mahkemesi hangi uluslararası örgüt bünyesinde faaliyet göstermektedir?",opts:["Avrupa Birliği","BM","Avrupa Konseyi","AGİT"],ans:2,exp:"AİHM, Avrupa Konseyi bünyesinde kurulmuş ve faaliyet göstermektedir. AB ile ilgisi yoktur; Avrupa Konseyi'nin 46 üye devletinin vatandaşları AİHM'e başvurabilir."},
  {q:"2025 Dünya Atletizm Şampiyonası hangi şehirde gerçekleşti? (2025 PAEM)",opts:["Tokyo","Paris","Roma","Atina"],ans:0,exp:"2025 Dünya Atletizm Şampiyonası Tokyo'da gerçekleştirildi."},
  {q:"5. nesil yerli savaş uçağı KAAN ilk uçuşunu ne zaman yaptı? (2025 PAEM)",opts:["Ocak 2024","Şubat 2024","Mart 2024","Nisan 2024"],ans:1,exp:"KAAN, Şubat 2024'te ilk uçuşunu gerçekleştirdi."},
  {q:"MİT bünyesinde 6 Ocak 2024'te kurulan kurum hangisidir? (2025 PAEM)",opts:["Millî Savunma Üniversitesi","Millî İstihbarat Akademisi","Güvenlik Bilimleri Fakültesi","Jandarma Güvenlik Akademisi"],ans:1,exp:"Millî İstihbarat Akademisi MİT bünyesinde 6 Ocak 2024'te kuruldu."}

  ,
  {q:"Türkiye'nin NATO'ya üyelik yılı nedir?",opts:["1949","1952","1955","1960"],ans:1,exp:"Türkiye NATO'ya 1952 yılında katıldı. Kurucu üyeler arasında yer almayan Türkiye, Yunanistan ile birlikte 1952'de ittifaka dahil oldu. Türkiye, NATO'nun ikinci büyük ordusuna sahip ülkesidir."},
  {q:"Türkiye'nin para birimi nedir ve Merkez Bankası nerede bulunur?",opts:["Lira — İstanbul","Türk Lirası — Ankara","Kuruş — Ankara","Türk Lirası — İstanbul"],ans:1,exp:"Türkiye'nin para birimi Türk Lirası (TL)'dir. Türkiye Cumhuriyet Merkez Bankası Ankara'da bulunmaktadır. Merkez Bankası 1930 yılında kurulmuş olup para politikasını yürütür."},
  {q:"BM Güvenlik Konseyi'nin kaç daimi üyesi vardır ve bunlar hangi ülkelerdir?",opts:["3 üye — ABD, Rusya, Çin","5 üye — ABD, İngiltere, Fransa, Rusya, Çin","5 üye — ABD, İngiltere, Almanya, Rusya, Çin","7 üye — G7 ülkeleri"],ans:1,exp:"BM Güvenlik Konseyi'nde 5 daimi üye (P5) bulunur: ABD, İngiltere, Fransa, Rusya ve Çin. Her biri veto hakkına sahiptir. 10 geçici üye ise 2 yıllık dönemler için seçilir. BM'nin toplam 15 üyeli Güvenlik Konseyi uluslararası barış ve güvenlikten sorumludur."},
  {q:"Türkiye'nin yüzölçümü bakımından dünyadaki sırası ve kıta konumu nedir?",opts:["36. büyük — Yalnızca Asya","37. büyük — Yalnızca Avrupa","36. büyük — Hem Asya hem Avrupa (Anadolu + Trakya)","40. büyük — Orta Doğu"],ans:2,exp:"Türkiye yaklaşık 783.000 km² yüzölçümüyle dünyanın 36. büyük ülkesidir. Topraklarının yaklaşık %97'si Anadolu (Asya), %3'ü ise Trakya (Avrupa) kıtasındadır. Bu konumu Türkiye'yi köprü ülke yapan özelliklerden biridir."},
  {q:"Türkiye'nin Avrupa Birliği ile ilişkisi nasıl tanımlanır?",opts:["Tam üye","Aday ülke (müzakereler askıya alınmış durumda)","Ortaklık üyesi","Müzakere süreci tamamlandı, üyelik bekleniyor"],ans:1,exp:"Türkiye 1987'de AB üyeliği için başvurdu, 1999'da aday ülke statüsü kazandı, 2005'te müzakereler başladı. Ancak çeşitli siyasi sorunlar nedeniyle müzakereler büyük ölçüde askıya alınmış durumdadır. Türkiye 1996'dan bu yana AB ile Gümrük Birliği üyesidir."},
  {q:"Türkiye'de kaç il bulunmaktadır?",opts:["73","78","81","85"],ans:2,exp:"Türkiye'de 81 il bulunmaktadır. Son eklenen il Düzce'dir (1999). Her il bir valinin yönetiminde olup ilçelere bölünmüştür. Türkiye'nin toplam ilçe sayısı 922'dir."},
  {q:"Türkiye'de zorunlu eğitim kaç yıldır?",opts:["8 yıl","10 yıl","12 yıl","14 yıl"],ans:2,exp:"Türkiye'de zorunlu eğitim 12 yıldır (4+4+4 sistemi): 4 yıl ilkokul, 4 yıl ortaokul, 4 yıl lise. 2012 yılında yapılan düzenlemeyle 8 yıldan 12 yıla çıkarılmıştır."},
  {q:"İnsan Hakları Evrensel Beyannamesi'nin kabul edildiği 10 Aralık hangi özel gün olarak kutlanır?",opts:["Dünya Barış Günü","Dünya İnsan Hakları Günü","BM Kuruluş Yıldönümü","Uluslararası Adalet Günü"],ans:1,exp:"10 Aralık 1948'de İHEB'in kabul edildiği gün, her yıl Dünya İnsan Hakları Günü olarak kutlanmaktadır. BM bu tarihi insan haklarının evrensel değerlerini hatırlatmak amacıyla seçmiştir."},
  {q:"Türkiye'de Anayasa Mahkemesi'ne bireysel başvuru hakkı ne zaman başladı?",opts:["1982","2001","2010","2012"],ans:3,exp:"Anayasa Mahkemesi'ne bireysel başvuru (anayasal şikâyet) hakkı 23 Eylül 2012'den itibaren uygulamaya girdi. 2010 anayasa referandumuyla getirilen bu düzenleme, iç hukukta AİHM'e gidilmeden önce temel hak ihlallerinin giderilmesini amaçlar."},
  {q:"Türkiye'de seçim yaşı ve milletvekili seçilme yaşı nedir?",opts:["18 — 18","18 — 25","18 — 30","21 — 25"],ans:0,exp:"Türkiye'de seçme ve seçilme yaşı her ikisi de 18'dir. 2017 Anayasa değişikliğiyle milletvekili seçilme yaşı 25'ten 18'e indirildi. Cumhurbaşkanı olabilmek için ise 40 yaşını doldurmuş olmak gerekir."},
  {q:"Türkiye Cumhuriyeti'nde hangi dil resmi dil statüsündedir?",opts:["Türkçe ve Kürtçe","Yalnızca Türkçe","Türkçe ve Arapça","Türkçe, Kürtçe ve Ermenice"],ans:1,exp:"Anayasa m.3: Türkiye Devletinin dili Türkçe'dir. Türkçe tek resmi devlet dilidir. Bu hüküm değiştirilemez maddeler arasındadır."},
  {q:"Türkiye'nin en uzun nehri hangisidir?",opts:["Fırat","Dicle","Kızılırmak","Sakarya"],ans:2,exp:"Kızılırmak, yaklaşık 1355 km ile Türkiye'nin en uzun nehridir ve tamamen Türkiye sınırları içinde akar. Fırat ise Türkiye'den geçen en uzun nehirdir ancak Suriye ve Irak'a da uzanır."},
  {q:"Türkiye'nin güneyinde hangi deniz bulunmaktadır?",opts:["Karadeniz","Ege Denizi","Akdeniz","Marmara Denizi"],ans:2,exp:"Türkiye güneyinde Akdeniz, kuzeyinde Karadeniz, batısında Ege Denizi ve kuzeybatısında Marmara Denizi ile çevrilidir. Türkiye üç tarafı denizlerle çevrili bir yarımada konumundadır."},
  {q:"INTERPOL'ün merkezi nerededir ve Türkiye üye midir?",opts:["New York — Evet","Cenevre — Hayır","Lyon — Evet","Brüksel — Evet"],ans:2,exp:"INTERPOL'ün (Uluslararası Kriminal Polis Örgütü) genel merkezi Lyon, Fransa'dadır. Türkiye, INTERPOL'ün üyesidir. Emniyet Genel Müdürlüğü bünyesindeki INTERPOL Türkiye Millî Merkez Bürosu uluslararası polis işbirliğini koordine eder."},
  // --- Güncel Bilgiler Ek Sorular (21.03.2026) ---
  {q:"TOGG T10F'in seri üretimi hangi yılda başlamıştır?",opts:["2021","2022","2023","2024"],ans:2,exp:"Türkiye'nin yerli ve milli elektrikli otomobil markası TOGG, T10F modelinin seri üretimine 2023 yılında Bursa Gemlik'teki fabrikasında başlamıştır. TOGG; Türkiye Varlık Fonu öncülüğünde 5 büyük Türk firmasının kurduğu bir girişimdir."},
  {q:"Cumhurbaşkanlığı Hükümet Sistemi'ne geçişin fiilen uygulandığı ilk seçim hangisidir?",opts:["7 Haziran 2015","1 Kasım 2015","24 Haziran 2018","14 Mayıs 2023"],ans:2,exp:"2017 anayasa referandumuyla kabul edilen Cumhurbaşkanlığı Hükümet Sistemi, 24 Haziran 2018 seçimleriyle birlikte fiilen uygulanmaya başlanmıştır. Bu sistemle Başbakanlık makamı kaldırılmış; yürütme yetkisi doğrudan Cumhurbaşkanı'nda toplanmıştır."},
  {q:"Türkiye'nin S-400 alımı nedeniyle F-35 programından çıkarılmasının temel gerekçesi nedir?",opts:["Savunma bütçe kısıtlamaları","S-400 sisteminin NATO sistemleriyle uyumsuzluğu ve CAATSA yaptırımları","Suriye'deki askerî operasyonlar","Yunanistan ile diplomatik anlaşmazlık"],ans:1,exp:"Türkiye'nin Rusya'dan S-400 hava savunma sistemi satın alması, ABD'nin Türkiye'yi F-35 programından çıkarmasına yol açmıştır (2019). CAATSA (Yaptırımlarla Amerika'nın Düşmanlarına Karşı Koyma Yasası) kapsamında değerlendirilen bu adım, NATO ittifakı içinde ciddi bir gerilim noktasıdır."},
  {q:"6 Şubat 2023 Kahramanmaraş merkezli depremde kaç il etkilenmiştir ve koordinasyon hangi kurum tarafından yürütülmüştür?",opts:["7 il — Kızılay","9 il — AFAD","11 il — AFAD","13 il — Emniyet"],ans:2,exp:"6 Şubat 2023'teki 7.7 ve 7.6 büyüklüğündeki çifte deprem; Kahramanmaraş merkez olmak üzere Hatay, Gaziantep, Adıyaman, Malatya ve diğerleri dahil 11 ili etkilemiştir. Tüm arama-kurtarma ve koordinasyon süreci AFAD (Afet ve Acil Durum Yönetimi Başkanlığı) tarafından yönetilmiştir."},
  // --- Güncel Bilgiler Transkript Ek Sorular (Ağu–Oca 2025-2026) ---
  {q:"Kuzey Tunçelli 2025 Dünya Gençler Yüzme Şampiyonası'nda hangi başarıyı elde etti?",opts:["Dünya ikincisi oldu","Altın madalya kazanarak dünya rekoru kırdı","Bronz madalya kazandı","Avrupa rekoru kırdı"],ans:1,exp:"Milli yüzücü Kuzey Tunçelli, 2025 Dünya Gençler Yüzme Şampiyonası'nda altın madalya kazanarak aynı zamanda dünya rekoru kırdı. Türkiye'nin yüzmede önemli bir başarısıdır."},
  {q:"2026 yılında AB Konseyi Dönem Başkanlığı'nı sırasıyla hangi ülkeler üstlendi?",opts:["İspanya – Portekiz","GKRY (ilk 6 ay) – İrlanda (son 6 ay)","Polonya – Danimarka","Macaristan – Avusturya"],ans:1,exp:"2026 yılında AB Konseyi Dönem Başkanlığı'nı ilk yarıda (Ocak–Haziran) Güney Kıbrıs Rum Yönetimi (GKRY), ikinci yarıda (Temmuz–Aralık) ise İrlanda üstlendi."},
  {q:"Ankara 2026 yılında hangi unvana layık görüldü?",opts:["Avrupa Kültür Başkenti","İslam Dünyası Kültür Başkenti","Türk Dünyası Turizm Başkenti","UNESCO Yaratıcı Şehir"],ans:2,exp:"Türk Devletleri Teşkilatı tarafından Ankara, 2026 Türk Dünyası Turizm Başkenti ilan edildi. Bu unvan Türk dünyası arasında kültürel ve turizm bağlarını güçlendirmeyi hedeflemektedir."},
  {q:"Türk Silahlı Kuvvetleri'nde Genelkurmay Başkanlığı görevini üstlenen isim kimdir? (2025)",opts:["Yaşar Güler","Metin Tokel","Selçuk Bayraktaroğlu","Hulusi Akar"],ans:2,exp:"2025 yılındaki atamalarla Selçuk Bayraktaroğlu Genelkurmay Başkanlığı görevine getirildi. Kara Kuvvetleri Komutanlığı'na ise Metin Tokel atandı."},
  {q:"Bengü Avcı 'Ocean Seven' unvanını elde eden ilk Türk yüzücü olarak hangi başarıyı kazandı?",opts:["Dünyanın 7 büyük boğazını geçti","Olimpiyatlarda altın madalya kazandı","Açık deniz maratonunda dünya rekoru kırdı","Avrupa Yüzme Şampiyonası'nı kazandı"],ans:0,exp:"Bengü Avcı, açık su yüzmesinin en prestijli zorluğu olan 'Ocean Seven' serisini (dünyanın 7 büyük boğazı/kanalı) tamamlayan ilk Türk yüzücü oldu. Bu başarı onu dünya yüzme tarihine yazdırdı."},
  {q:"Türkiye'nin yerli ve milli ana muharebe tankı Altay'ın seri üretim süreci hangi yılda başladı?",opts:["2021","2023","2024","2025"],ans:3,exp:"Altay tankının seri üretimi 2025 yılında başladı. Yerli savunma sanayii alanında Türkiye'nin önemli bir dönüm noktası olarak değerlendirilmektedir."},
  {q:"Toprak Razgatlıoğlu 2025 Dünya Superbike Şampiyonası'nı kazanarak kaç kez dünya şampiyonu olmuştur? Lakabı nedir?",opts:["2 kez — 'Türk Kartalı'","3 kez — 'El Turko'","2 kez — 'El Turko'","3 kez — 'Anadolu Aslanı'"],ans:1,exp:"Toprak Razgatlıoğlu, 2021, 2024 ve 2025 Dünya Superbike Şampiyonlukları'yla 3 kez dünya şampiyonu olmuştur. Lakabı 'El Turko'dur. Türk motorsporunun dünya arenasındaki en büyük başarılarından birini temsil etmektedir."},
  {q:"RTÜK Başkanlığı görevine 2025 yılında kim atandı?",opts:["Ebubekir Şahin","Mehmet Daniş","İlhan Taşçı","Serhat Kaleli"],ans:1,exp:"Ebubekir Şahin'in RTÜK Başkanlığı görevinden ayrılmasının ardından 2025 yılında Mehmet Daniş bu göreve atandı. Ebubekir Şahin ise Türk Telekom Yönetim Kurulu'na geçti."},
  {q:"2025 Nobel Barış Ödülü kime verildi?",opts:["Greta Thunberg","Volodimir Zelenski","María Corina Machado","António Guterres"],ans:2,exp:"2025 Nobel Barış Ödülü, Venezuela'da demokratik hareketin öncü ismi María Corina Machado'ya verildi. Machado, Venezuela'da Maduro rejimine karşı sürdürdüğü mücadelesiyle tanınmaktadır. Bu ayrı bir ödüldür; Atatürk Barış Ödülü ise Guterres'e verilmiştir."},
  {q:"2025 Nobel Edebiyat Ödülü hangi yazara verildi?",opts:["Orhan Pamuk","László Krasznahorkai","Haruki Murakami","Annie Ernaux"],ans:1,exp:"2025 Nobel Edebiyat Ödülü, Macar yazar László Krasznahorkai'ye verildi. Türkiye ve diğer ülkelerde çeşitli edebiyat çevrelerinde tanınan Krasznahorkai, Macar edebiyatının önemli temsilcilerinden biridir."},
  {q:"BM İklim Zirvesi COP30 hangi ülke ve şehirde düzenlenecektir?",opts:["Almanya – Berlin","Türkiye – İstanbul","Brezilya – Belém","Hindistan – Mumbai"],ans:2,exp:"BM İklim Değişikliği Çerçeve Sözleşmesi kapsamındaki 30. Taraflar Konferansı (COP30), Brezilya'nın Belém şehrinde düzenlenecektir. Amazon Ormanları'nın kalbinde yer alan bu şehirde iklim gündeminin öne çıkması beklenmektedir."},
  {q:"Bayraktar Kızılelma ile ilgili hangisi doğrudur?",opts:["Türkiye'nin ilk insanlı savaş uçağıdır","Görüş ötesi füzeyle jet hedef vuran ilk insansız uçaktır ve testleri Sinop'ta yapıldı","Kara muharebe aracıdır","NATO tarafından ortaklaşa geliştirilmiştir"],ans:1,exp:"Bayraktar Kızılelma, Türkiye'nin ilk insansız savaş uçağıdır. Görüş ötesi hava-hava füzesiyle jet uçağını başarıyla vuran dünya tarihindeki ilk insansız uçak olma özelliğini taşımaktadır. Test uçuşları Sinop açıklarında gerçekleştirilmiştir."},
  {q:"Yavaş Şehir (Cittaslow) ağına 2025'te katılan 28. Türk yerleşim yeri hangisidir?",opts:["Muğla'nın Datça ilçesi","Konya'nın Beyşehir ilçesi","Antalya'nın Demre ilçesi","Isparta'nın Eğirdir ilçesi"],ans:2,exp:"Antalya'nın Demre ilçesi, 2025 yılında Cittaslow (Yavaş Şehirler) ağına katılarak Türkiye'nin 28. Cittaslow üyesi oldu. Demre; tarihi, kültürü ve doğasıyla bu unvana layık görüldü."},
  {q:"TDK tarafından 2025 yılının kelimesi seçilen sözcük hangisidir?",opts:["yapay zeka","ekran bağımlılığı","dijital vicdan","nefret söylemi"],ans:2,exp:"Türk Dil Kurumu (TDK), 2025 yılının kelimesini 'dijital vicdan' olarak belirledi. Dijital ortamlarda etik sorumluluk bilincine dikkat çeken bu seçim, günümüz teknoloji çağını yansıtmaktadır."},
  {q:"UNESCO 2025 yılında Türkiye'den somut olmayan kültürel miras listesine hangi unsurları ekledi?",opts:["Ebru sanatı, meddahlık, Nevruz","Antep işi nakışı, Yurt, Kopuz","Karagöz, zeybek, Türk kahvesi","Mevlevi sema, marş, hat sanatı"],ans:1,exp:"UNESCO 2025 yılında Türkiye'den 'Antep işi nakışı', 'Yurt (keçe çadır)' ve 'Kopuz (ata müzik aleti)' unsurlarını Somut Olmayan Kültürel Miras Listesi'ne ekledi. Bu unsurlar Türk kültürünün köklü geleneklerini temsil etmektedir."},
  {q:"2025 yılında yayımlanan dünya turizm sıralamasında Antalya kaçıncı sıraya yerleşerek hangi şehirleri geride bıraktı?",opts:["3. sıra — Tokyo ve Paris","5. sıra — Los Angeles ve Dubai","7. sıra — Londra ve Roma","2. sıra — New York ve Barcelona"],ans:1,exp:"Antalya, 2025 yılında açıklanan dünyada en çok ziyaret edilen 10 turizm destinasyonu listesinde 5. sıraya yerleşerek Los Angeles ve Dubai'yi geride bıraktı. Türkiye turizmi açısından tarihi bir başarıdır."},
  {q:"Erzurum'un Uzundere ilçesinde yer alan Tortum Gölü ve Şelalesi nasıl bir statüye kavuşturuldu?",opts:["1. Derece Doğal Sit Alanı","UNESCO Dünya Mirası","Milli Park","Kesin Korunacak Hassas Alan"],ans:3,exp:"Cumhurbaşkanlığı kararnamesiyle Tortum Gölü ve Şelalesi, 'Kesin Korunacak Hassas Alan' ilan edildi. Erzurum'un Uzundere ilçesi sınırları içinde yer alan bu alan Türkiye'nin önemli doğal değerlerinden biridir."},
  {q:"Zeynep Sönmez 2026 Avustralya Açık'ta hangi tarihi başarıyı elde etti?",opts:["Yarı finale yükseldi","Finali kazandı","İkinci tura yükselen ilk Türk kadın tenisçi oldu","Çeyrek finale yükseldi"],ans:2,exp:"Zeynep Sönmez, 2026 Avustralya Açık tenis turnuvasında ikinci tura yükselerek bu başarıyı elde eden ilk Türk kadın tenisçi unvanını kazandı. Türk tenisinin yükselen değeri olarak öne çıkmaktadır."},
  {q:"TRT Genç kanalının açılışında hangi robot öne çıktı ve açılışı kim gerçekleştirdi?",opts:["İHA robotu — Bakan açtı","Robo Genç — Cumhurbaşkanı açtı","ATAK robotu — TRT Genel Müdürü açtı","Yapay zeka asistanı — Bakanlar Kurulu açtı"],ans:1,exp:"TRT Genç kanalının açılışı Cumhurbaşkanı'nın katılımıyla gerçekleştirildi. Türk mühendislerce geliştirilen 'Robo Genç' adlı robot, açılış kumandayı Cumhurbaşkanı'na bizzat getirerek törende dikkat çekti."},
  {q:"Venezuela Devlet Başkanı Nicolás Maduro'nun ABD tarafından yakalanması ne zaman gerçekleşti?",opts:["15 Kasım 2025","3 Ocak 2026","20 Şubat 2026","10 Aralık 2025"],ans:1,exp:"3 Ocak 2026 sabahında ABD güçleri gerçekleştirdiği ani bir operasyonla Venezuela Devlet Başkanı Nicolás Maduro'yu yakalayarak ABD'ye götürdü. Bu gelişme uluslararası kamuoyunda geniş yankı uyandırdı."}],
tck:[
  {q:"TCK'ya göre kasten öldürmenin temel cezası nedir?",opts:["10-15 yıl hapis","Ağırlaştırılmış müebbet","Müebbet hapis","20-25 yıl hapis"],ans:2,exp:"TCK m.81: Bir insanı kasten öldüren kişi müebbet hapis cezasıyla cezalandırılır. Nitelikli haller (m.82) ağırlaştırılmış müebbet; taksirle öldürme ise m.85 kapsamındadır."},
  {q:"TCK'da 'olası kast' nasıl tanımlanmaktadır?",opts:["Sonucu bilerek ve isteyerek gerçekleştirme","Muhtemel sonucu öngörüp kabullenerek hareket etme","Dikkatsizlik sonucu meydana gelen zarar","Kasıtsız hareket"],ans:1,exp:"TCK m.21/2: Olası kastta fail, suçun kanuni tanımındaki unsurların gerçekleşmesini muhtemel görmesine rağmen, fiili işlemeye devam eder. Doğrudan kasta kıyasla ceza 1/3'e kadar indirilebilir."},
  {q:"Suça teşebbüste ceza nasıl belirlenir?",opts:["Tam ceza verilir","Hiç ceza verilmez","İndirimli ceza verilir","Savcı takdir eder"],ans:2,exp:"TCK m.35/2: Suça teşebbüste ağırlaştırılmış müebbet yerine 13-20 yıl, müebbet yerine 9-15 yıl, diğer suçlarda ise suça göre 1/4 ile 3/4 oranında indirilmiş ceza uygulanır."},
  {q:"Meşru müdafaada sınır aşımı bilinçli taksirle gerçekleşirse ne olur?",opts:["Tam ceza verilir","Ceza indirilir","Ceza verilmez","Sanık beraat eder"],ans:1,exp:"TCK m.27: Meşru müdafaada sınırın taksirle aşılması halinde, taksirli suç olarak sorumlu tutulur ve ceza indirilir. Korku, panik veya heyecan nedeniyle sınır aşımında ise ceza verilmeyebilir."},
  {q:"TCK m.30'a göre 'hata' düzenlemesi neyi kapsar?",opts:["Sadece maddi hataları","Sadece hukuki hataları","Suçun unsurlarında yanılmayı kapsayan kastı etkileyen hataları","Yalnızca kasıt hatalarını"],ans:2,exp:"TCK m.30: Suçun unsurları bakımından yanılma kastı ortadan kaldırır. Kişi, fiilin bir unsurunda hata yaparsa o unsura ilişkin kast bulunmaz. Bu düzenleme hem maddi hem hukuki unsur hatalarını kapsar."},
  {q:"'Zorunluluk hâli' (TCK m.25/2) hangi durumlarda uygulanır?",opts:["Her suçta uygulanır","Saldırı olmaksızın bir zararı önlemek için zorunlu eylem","Meşru müdafaa koşulları varken","Sadece mülk korumasında"],ans:1,exp:"TCK m.25/2: Zorunluluk hâli; kendisinin veya başkasının yaşam, beden tamlığı ya da cinsel dokunulmazlığına yönelik bir tehlikeyi başka türlü bertaraf etme imkânı bulunmayan durumlarda ağır ve muhakkak tehlike karşısında başvurulan haldir."},
  {q:"TCK'da kişiyi hürriyetinden yoksun kılma suçu hangi maddeде düzenlenmiştir?",opts:["m.99","m.105","m.109","m.117"],ans:2,exp:"TCK m.109: Bir kimseyi hukuka aykırı olarak bir yere gitmek veya bir yerde kalmak zorunda bırakan kişi 1 yıldan 5 yıla kadar hapis cezasıyla cezalandırılır. Nitelikli haller daha ağır ceza öngörür."},
  {q:"'İştirak' kapsamında müşterek faillik ne anlama gelir?",opts:["Tek kişinin suçu işlemesi","Birden fazla kişinin ortak kastla suçu birlikte gerçekleştirmesi","Bir kişinin diğerini suça azmettirmesi","Suçtan sonra yardım etmek"],ans:1,exp:"TCK m.37: Müşterek faillikte birden fazla kişi ortak bir kastla suçun icrasında birlikte yer alır; her biri tam faille aynı ceza sorumluluğunu taşır. Bu, azmettirme veya yardım etmeden farklıdır."},
  {q:"TCK'ya göre ceza sorumluluğu kaç yaşında başlar?",opts:["10","12","15","18"],ans:1,exp:"TCK m.31: 12 yaşını doldurmamış çocuklar hakkında ceza kovuşturması yapılamaz. 12-14 yaş arası çocuklarda ise algılama yeteneği değerlendirilerek sorumluluk belirlenir; tam sorumluluk 18 yaşında başlar."},
  {q:"Rüşvet suçunda TCK uyarınca hem veren hem alan cezalandırılır mı?",opts:["Sadece alan cezalandırılır","Sadece veren cezalandırılır","Her ikisi de cezalandırılır","Hiçbiri cezalandırılmaz"],ans:2,exp:"TCK m.252 (rüşvet alma) ve m.252/8 (rüşvet verme): Her iki taraf da ayrı ayrı cezalandırılır. Rüşvet alma 4 yıldan 12 yıla; rüşvet verme ise 4 yıldan 12 yıla kadar hapis cezasını gerektirir."},
  {q:"TCK'da 'kast' nasıl tanımlanmıştır? (2025 PAEM)",opts:["Suç amacı olmaksızın eylem","Dikkat ve özen yükümlülüğüne aykırılık","Neticenin istenmemesine rağmen eylem","Suçun unsurlarının bilerek ve istenerek gerçekleştirilmesi"],ans:3,exp:"TCK m.21/1: Kast; suçun kanuni tanımındaki unsurların bilerek ve istenerek gerçekleştirilmesidir."},
  {q:"TCK'ya göre çocuk hangi yaşa kadar olan kişidir? (2025 PAEM)",opts:["12 yaşını doldurmamış","14 yaşını doldurmamış","15 yaşını doldurmamış","18 yaşını doldurmamış"],ans:3,exp:"TCK m.6: Çocuk, henüz 18 yaşını doldurmamış kişidir."},
  {q:"Meşru savunmada hangisi YANLIŞTIR? (2025 PAEM)",opts:["Saldırı hakka yönelik olmalıdır","Saldırı silahla yapılmış olmalıdır","Savunma saldırana karşı olmalıdır","Savunma zorunlu olmalıdır"],ans:1,exp:"TCK m.25: Saldırının silahla yapılması meşru müdafaa için şart değildir."},
  {q:"'Suç İşlemek Amacıyla Örgüt Kurma' için örgüt en az kaç üyeli olmalıdır? (2025 PAEM)",opts:["2","3","5","7"],ans:1,exp:"TCK m.220: Suç örgütü için en az 3 üye gerekir."}

  ,
  // --- Ceza Hukuku Video 1'den eklenen sorular ---
  {q:"5237 sayılı TCK kaç tarihinde yürürlüğe girmiştir?",opts:["1 Ocak 2004","1 Haziran 2005","26 Eylül 2004","1 Ocak 2006"],ans:1,exp:"5237 sayılı Türk Ceza Kanunu 26 Eylül 2004'te TBMM'de kabul edilmiş, 1 Haziran 2005 tarihinde yürürlüğe girmiştir. Öncesinde 1926'dan beri 765 sayılı eski TCK yürürlükteydi. Bu tarihlerin ikisi de sınavlarda sorulmaktadır."},
  {q:"5237 sayılı TCK'nın genel hükümleri kaçıncı maddeler arasında yer alır?",opts:["m.1-50","m.1-75","m.1-100","m.1-150"],ans:1,exp:"5237 sayılı TCK toplam 345 maddeden oluşur. m.1-75 arası genel hükümleri, m.76-345 arası ise özel hükümleri (suç tipleri) düzenler. PAEM ve kurum sınavlarında ağırlıklı olarak genel hükümlerden soru gelir."},
  {q:"Yeni TCK (5237) ile 'eksik teşebbüs / tam teşebbüs' ayrımı hakkında doğru olan hangisidir?",opts:["Bu ayrım korunmuş ve detaylandırılmıştır","Bu ayrım kaldırılmış; tek tip teşebbüs benimsenmiştir","Eksik teşebbüs suç sayılmaz, yalnızca tam teşebbüs suçtur","Bu ayrım sadece şiddet suçlarına uygulanır"],ans:1,exp:"5237 sayılı TCK ile eski kanundaki eksik teşebbüs/tam teşebbüs ayrımı tamamen kaldırılmış, tek tip teşebbüs sistemi benimsenmiştir. Teşebbüs var ya da yok; kısmi/tam ayrımı artık söz konusu değildir."},
  {q:"Kabahatler hangi kanunda düzenlenmektedir ve yaptırımı ne türdendir?",opts:["TCK'da — hapis cezası","TCK'da — para cezası","5326 sayılı Kabahatler Kanunu'nda — idari yaptırım","CMK'da — güvenlik tedbiri"],ans:2,exp:"Yeni TCK ile cürüm/kabahat ayrımı kaldırılmış; kabahatler 5326 sayılı Kabahatler Kanunu'nda ayrıca düzenlenmiştir. Kabahatlerin yaptırımı idari yaptırım niteliğinde olup genellikle para cezasıdır. Kapalı alanda sigara içmek, gürültü yapmak, duvara afiş asmak kabahat örnekleridir."},
  {q:"TCK kapsamında tüzel kişiler hakkında hangi yaptırım uygulanabilir?",opts:["Hapis cezası","Adli para cezası","Yalnızca güvenlik tedbirleri","Hem hapis hem para cezası"],ans:2,exp:"TCK m.20: Ceza sorumluluğu şahsidir; tüzel kişiler hakkında ceza (hapis/para) uygulanamaz. Ancak tüzel kişiler hakkında güvenlik tedbiri niteliğindeki yaptırımlar uygulanabilir (ruhsat iptali, müsadere vb.)."},
  {q:"5237 sayılı TCK'da hangi ceza türü öngörülmemiştir?",opts:["Ağırlaştırılmış müebbet hapis","Adli para cezası","Ağır para cezası","Süreli hapis"],ans:2,exp:"5237 sayılı TCK ile ağır para cezası/hafif para cezası ayrımı kaldırılmış; bunun yerine tek tip adli para cezası getirilmiştir. Aynı şekilde ağır hapis/hafif hapis ayrımı da kaldırılmış ve süreli hapis cezası sistemi benimsenmiştir."}
  ,
  // --- Ceza Hukuku Video 2'den eklenen sorular (Anayasa m.38) ---
  {q:"Suç işlendikten sonra yeni çıkan kanun faili daha ağır cezalandırıyorsa ne olur?",opts:["Yeni (ağır) kanun uygulanır","Eski (hafif) kanun uygulanır","Hakim iki kanun arasında seçim yapar","Her ikisi de uygulanır"],ans:1,exp:"Anayasa m.38 ve TCK m.7: Aleyhe (aleyhte) kanun geçmişe yürümez; suçun işlendiği tarihteki kanun uygulanır. Buna karşın lehe (lehte) kanun geriye yürür — sonradan çıkan yeni kanun faili daha az cezalandırıyorsa kovuşturma veya infaz aşamasında dahi uygulanır."},
  {q:"Anayasa m.38'e göre suç ve cezalara ilişkin hangisi doğrudur?",opts:["Ceza ve güvenlik tedbirleri CBK ile de koyulabilir","Ceza ve güvenlik tedbirleri yalnızca kanunla koyulabilir","Güvenlik tedbirleri yönetmelikle de düzenlenebilir","Cumhurbaşkanı kararıyla güvenlik tedbiri uygulanabilir"],ans:1,exp:"Anayasa m.38/3: Ceza ve ceza yerine geçen güvenlik tedbirleri ancak kanunla konulabilir. CBK, yönetmelik veya idari kararla ceza veya güvenlik tedbiri öngörülemez. Bu ilke kanunilik ilkesinin bir gereğidir."},
  {q:"Genel müsadere neden yasaktır?",opts:["Anayasa müsadereyi tamamen yasaklamıştır","Suçla bağlantısı olmayan mal varlığına el konulması orantısız olduğundan","Müsadere yalnızca sanıklar için uygulanır","Mahkumiyet kesinleşene kadar müsadere uygulanamaz"],ans:1,exp:"Anayasa m.38: Genel müsadere yasaktır. Suçla bağlantılı eşya (eşya müsaderesi) ve suçtan elde edilen kazanç (kazanç müsaderesi) alınabilir; ancak suçla ilgisi olmayan tüm mal varlığına el konulması genel müsaderedir ve yasaktır."},
  {q:"'Susma hakkı' ve 'yakınları aleyhine delil göstermeme hakkı' anayasanın hangi maddesinde yer alır?",opts:["m.17","m.20","m.36","m.38"],ans:3,exp:"Anayasa m.38: 'Hiç kimse kendisini ve kanunda gösterilen yakınlarını suçlayan beyanda bulunmaya veya delil göstermeye zorlanamaz.' Bu hüküm susma hakkı ve yakınları aleyhine delil göstermeme hakkını güvence altına alır."},
  {q:"Hukuka aykırı yollarla elde edilen delil hakkında anayasa ne öngörür?",opts:["Mahkeme takdirle değerlendirebilir","Delil olarak kabul edilemez","Savcı onayıyla kullanılabilir","Yalnızca ağır suçlarda kullanılabilir"],ans:1,exp:"Anayasa m.38/6: 'Kanuna aykırı olarak elde edilmiş bulgular delil olarak kabul edilemez.' Bu 'zehirli ağacın meyvesi' doktrinidir — hukuka aykırı delil ve bu delilden ulaşılan diğer deliller de kullanılamaz."},
  {q:"İdare, kişi hürriyetini kısıtlayan bir yaptırım uygulayabilir mi?",opts:["Evet, idare para veya hapis cezası verebilir","Hayır, idare kişi hürriyetini kısıtlayan ceza veremez; ancak silahlı kuvvetlerin iç düzeni için istisna var","Evet, 3 günü aşmayan gözaltı idare tarafından verilebilir","Hayır, idare hiçbir ceza yetkisine sahip değildir"],ans:1,exp:"Anayasa m.38: İdare kişi hürriyetini kısıtlayıcı sonuç doğuran bir müeyyide uygulayamaz. Ancak Türk Silahlı Kuvvetlerinin iç düzeni bakımından bu hükme istisna getirilebilir. İdari para cezası idare tarafından verilebilir; fakat hapis türü özgürlük kısıtlayıcı cezalar veremez."},
  {q:"Aşağıdakilerden hangisi Anayasa m.38'de düzenlenmemiştir?",opts:["Ceza sorumluluğunun şahsiliği","Masumiyet karinesi","Lehe kanunun geçmişe yürümesi","Vatandaşın suç nedeniyle iadesi yasağı"],ans:2,exp:"Ceza sorumluluğunun şahsiliği (m.38), masumiyet karinesi (m.38) ve vatandaşın iadesi yasağı (m.38) doğrudan Anayasa m.38'de düzenlenmiştir. Lehe kanunun geçmişe yürümesi de m.38/1'den kaynaklanır. Bu dört ilkenin tümü m.38'de yer almaktadır — seçenekler yanıltıcı biçimde kurulmuş sorularda dikkat etmek gerekir."},
  // --- Ceza Hukuku Video 3'ten eklenen sorular (Kanunilik, Belirlilik, Kıyas, Tanımlar) ---
  {q:"TCK m.2/3'e göre 'kıyas yasağı' ne anlama gelir?",opts:["Suç ve ceza hükümleri benzer durumlara kıyasla genişletilemez","Hâkim iki farklı cezayı karşılaştırabilir","Kanun maddeleri birbiriyle kıyaslanarak uygulanır","Kıyas yalnızca ağır suçlarda yasaktır"],ans:0,exp:"TCK m.2/3: Kanunların suç ve ceza içeren hükümleri, kıyasa yol açacak biçimde geniş yorumlanamaz. Kanunda açıkça suç sayılmayan bir fiil, benzer bir suça kıyasla cezalandırılamaz. Bu ilke kanunilik ilkesinin zorunlu bir sonucudur."},
  {q:"Ceza hukuku ile medeni hukuk arasında 'kanun boşluğu' konusundaki temel fark nedir?",opts:["Her ikisinde de hâkim boşluğu dolduramaz","Medeni hukukta hâkim boşluğu doldurabilir; ceza hukukunda dolduramaz","Ceza hukukunda hâkim kanun yaratabilir","Arada fark yoktur, aynı kurallar geçerlidir"],ans:1,exp:"Türk Medeni Kanunu m.1: Hâkim kanun boşluğunda örf-âdet ve hakkaniyete göre hukuk yaratabilir. Ceza hukukunda ise kanunilik ilkesi gereği hâkim kesinlikle hukuk yaratamaz. Kanunda suç olarak tanımlanmayan eylem suç değildir."},
  {q:"TCK m.6'ya göre 'gece vakti' ne zaman başlar?",opts:["Güneş battığı anda","Güneş battıktan 30 dakika sonra","Güneş battıktan 1 saat sonra","Saat 21:00'den itibaren"],ans:2,exp:"TCK m.6/1-e: Gece vakti, güneşin batmasından 1 saat sonra başlayıp, güneşin doğmasından 1 saat önceye kadar devam eden zaman dilimidir. Güneşin batmasıyla değil, 1 saat sonrasıyla başlar — sınavda sıklıkla tuzak sorulur."},
  {q:"TCK m.6'ya göre 'kamu görevlisi' tanımı için hangisi doğrudur?",opts:["Yalnızca 657 sayılı Kanun'a tabi memurlardır","Yalnızca devlet memurları ve sözleşmeli personeldir","Kamusal faaliyete atama, seçilme veya herhangi bir surette katılan kişidir","Sadece güvenlik görevlileridir"],ans:2,exp:"TCK m.6/1-c: Kamu görevlisi, kamusal faaliyetin yürütülmesine atama veya seçilme ya da herhangi bir surette sürekli, süreli veya geçici olarak katılan kişidir. Bu tanım memurlardan çok daha geniştir; seçilmiş milletvekilleri, muhtar, bilirkişi ve noter de kamu görevlisi sayılır."},
  {q:"TCK'da aşağıdakilerden hangisi 'silah' sayılır?",opts:["Yalnızca ateşli silahlar","Ateşli silahlar ve bıçaklar","Ateşli silahlar, patlayıcılar, yakıcı/boğucu/zehirleyici maddeler ve nükleer/biyolojik/kimyasal silahlar dahil geniş bir liste","Yalnızca ruhsatlı silahlar"],ans:2,exp:"TCK m.6/1-f: Silah kavramı çok geniştir. Ateşli silahlar, patlayıcı maddeler, saldırı ve savunma amacıyla yapılmış araçlar, yakıcı, aşındırıcı, boğucu, zehirleyici, süründürücü maddeler ve nükleer/radyoaktif/biyolojik/kimyasal silahlar dahildir."},
  {q:"TCK m.3'e göre 'adalet ilkesi' neyi gerektirir?",opts:["Her suça aynı cezanın verilmesini","Fiilin ağırlığıyla orantılı ceza ve güvenlik tedbirine hükmedilmesini","Hâkimin takdir yetkisinin sınırsız olmasını","Mağdurun istediği cezanın verilmesini"],ans:1,exp:"TCK m.3/1: Suç işleyen kişi hakkında işlenen fiilin ağırlığıyla orantılı ceza ve güvenlik tedbirine hükmedilir. Bu orantılılık ilkesidir — hırsızlığa müebbet veya cinayete hafif ceza adalet ilkesine aykırıdır."},
  {q:"TCK m.3/2'ye göre ceza kanunu uygulamasında aşağıdakilerden hangisi yapılamaz?",opts:["Lehe yorum","Kişiler arasında ırk, dil, din, cinsiyet gibi nedenlerle ayrım","Sanık lehine şüpheden yararlanma","İndirimli ceza uygulanması"],ans:1,exp:"TCK m.3/2: Ceza kanununun uygulanmasında kişiler arasında ırk, dil, din, mezhep, milliyet, renk, cinsiyet, siyasal veya diğer düşünce ya da inanç farklılıkları nedeniyle ayırım yapılamaz ve hiçbir kimseye ayrıcalık tanınamaz."},
  {q:"'Belirlilik ilkesi' neyi gerektirir?",opts:["Suç ve cezanın kanunda açık, anlaşılır ve öngörülebilir biçimde düzenlenmesini","Hâkime geniş takdir yetkisi verilmesini","Cezanın her durumda sabit olmasını","Suçun tanımının yönetmelikle yapılabilmesini"],ans:0,exp:"Belirlilik ilkesi kanunilik ilkesinin alt ilkesidir. Kanun, suçu ve cezayı öyle açık ve belirli düzenlemelidir ki vatandaş hangi davranışının suç olduğunu ve ne ceza alacağını önceden bilebilsin. Muğlak, belirsiz ifadeler kanunilik ilkesine aykırıdır."},
  {q:"TCK m.6'ya göre 'çocuk' kimdir?",opts:["12 yaşını doldurmamış kişi","15 yaşını doldurmamış kişi","18 yaşını doldurmamış kişi","Ceza sorumluluğu olmayan kişi"],ans:2,exp:"TCK m.6/1-b: Çocuk, henüz 18 yaşını doldurmamış kişidir. Bu tanım ceza sorumluluğu yaşından (12) farklıdır. 12-17 yaş arası çocuklar cezai sorumluluk taşıyabilir ama yine 'çocuk' statüsündedir."},
  {q:"Vatandaşın yabancı ülkeye iadesi yasağının tek istisnası nedir?",opts:["Terör suçları","Ağır ceza gerektiren suçlar","Uluslararası Ceza Mahkemesi (UCM) yükümlülükleri","Karşılıklılık (mütekabiliyet) ilkesi geçerliyse"],ans:2,exp:"Anayasa m.38 ve TCK m.18: Vatandaş suç sebebiyle yabancı bir ülkeye verilemez. Tek istisna Uluslararası Ceza Mahkemesi'ne (UCM) teslim yükümlülükleridir. Terör dahil başka hiçbir suç türü için istisna yoktur."},
  {q:"TCK m.6'ya göre 'itiyadi suçlu' (suçu meslek edinen) tanımı için kaç suç gerekir?",opts:["Bir yıl içinde aynı suçu 2 kez işleyen","Bir yıl içinde aynı suçu ikiden fazla işleyen","Farklı suçları 3'ten fazla işleyen","5 yılda 10'dan fazla suç işleyen"],ans:1,exp:"TCK m.6/1-ı: Kasıtlı bir suçun temel şeklini ya da daha ağır cezayı gerektiren nitelikli hallerini bir yıl içinde ve farklı zamanlarda ikiden fazla işleyen kişi, itiyadi suçlu sayılır."},
  {q:"'Aleyhe geniş yorum yasağı' ceza hukukunda ne anlama gelir?",opts:["Kanunun dar yorumlanması zorunludur","Sanık aleyhine genişletici yorum yapılamaz","Hâkim hiçbir yorum yapamaz","Sadece savcı yorum yapabilir"],ans:1,exp:"Ceza hukukunda kanunilik ilkesi gereği suç ve ceza hükümleri sanık aleyhine genişletici biçimde yorumlanamaz. Lehe yorum mümkündür ancak aleyhe geniş yorum kesinlikle yasaktır. Örnek: 'motorlu taşıt' ibaresini bisiklete uygulamak aleyhe geniş yorumdur."},
  {q:"Aşağıdakilerden hangisi TCK m.6'daki 'silah' tanımı kapsamında DEĞİLDİR?",opts:["Patlayıcı maddeler","Zehirleyici maddeler","Ruhsatsız taşınan tabanca","Yumruk (beden gücü)"],ans:3,exp:"TCK m.6/1-f'deki silah tanımı ateşli silahları, patlayıcıları, saldırı/savunma araçlarını, yakıcı/boğucu/zehirleyici maddeleri ve nükleer/biyolojik/kimyasal silahları kapsar. Beden gücü (yumruk) bu tanımda yer almaz — silah nitelikli hale etki eder, yumruk etmez."},
  {q:"TCK'nın ceza hukukundaki yeri için hangisi doğrudur?",opts:["Özel hukuk dalıdır","Kamu hukuku dalıdır","Hem özel hem kamu hukukundadır","Uluslararası hukuk dalıdır"],ans:1,exp:"Ceza hukuku kamu hukuku dalıdır. Devlet ile birey arasındaki ilişkiyi düzenler. Devlet cezalandırma yetkisini (ceza hakkı) kamu adına kullanır. Özel hukuk ise eşit taraflar arası ilişkileri düzenler."},
  {q:"'Tekerrür' (TCK m.58) ne anlama gelir?",opts:["İlk kez suç işleme","Daha önce mahkum olan kişinin yeniden suç işlemesi","Aynı suçu aynı gün işleme","Suça teşebbüs etme"],ans:1,exp:"TCK m.58: Tekerrür; önceden işlenen bir suçtan dolayı verilen hüküm kesinleştikten sonra yeni bir suçun işlenmesidir. Mükerrir (tekerrüre düşen) hakkında ceza artırımı ve mükerrirlere özgü infaz rejimi uygulanır."},
  // --- TCK Ek Sorular ---
  {q:"TCK m.43'e göre 'zincirleme suç' hangi koşullarda oluşur?",opts:["Farklı kişilere karşı farklı zamanlarda aynı suçu işleme","Aynı suç işleme kararıyla aynı kişiye farklı zamanlarda aynı suçu işleme","Birden fazla kişiyle birlikte suç işleme","Aynı fiille birden fazla kişiye zarar verme"],ans:1,exp:"TCK m.43/1: Bir suç işleme kararının icrası kapsamında, değişik zamanlarda aynı kişiye karşı aynı suçun birden fazla işlenmesi halinde bir cezaya hükmedilir; bu ceza dörtte birden dörtte üçe kadar artırılır. 'Aynı karar + aynı kişi + aynı suç' üç şart birlikte aranır. Cinsel suçlarda farklı mağdurlara karşı da zincirleme hükümler uygulanır."},
  {q:"'Fikri içtima' (TCK m.44) ne anlama gelir ve nasıl cezalandırılır?",opts:["Birden fazla kişinin tek suç işlemesi; ortalama ceza verilir","Tek bir fiilin birden fazla farklı suçu oluşturması; en ağır suçun cezasıyla cezalandırılır","Aynı suçun birden fazla kez işlenmesi; zincirleme hükümleri uygulanır","Suça teşebbüs eden kişilerin cezalandırılması"],ans:1,exp:"TCK m.44: Tek bir fiille birden fazla farklı suç oluşması hâlinde, bu suçlardan en ağır cezayı gerektireni için hüküm kurulur. Zincirleme suçtan farkı: Zincirleme'de aynı suç birden fazla kez işlenir; fikri içtimada ise tek eylemle birden fazla ayrı suç oluşur (örn. trafik kazasıyla hem yaralama hem mala zarar verme)."},
  {q:"TCK'ya göre 15-17 yaş grubundaki çocuk ağırlaştırılmış müebbet gerektiren suçu işlerse kaç yıl hapis cezası verilir?",opts:["9-11 yıl","12-15 yıl","9-15 yıl","Müebbet ceza indirimi uygulanmaz"],ans:1,exp:"TCK m.31/3: Fiil tarihinde 15-17 yaş grubunda olan çocuklar için ağırlaştırılmış müebbet yerine 12 yıldan 15 yıla, müebbet yerine 9 yıldan 11 yıla kadar hapis verilir. Diğer suçlarda ise cezanın yarısına kadar indirim yapılır. 12-14 yaş grubunda süreler daha kısadır (haksız tahrik yoksa)."},
  {q:"TCK m.85'e göre taksirle öldürme suçunun temel cezası nedir?",opts:["1-3 yıl hapis","2-6 yıl hapis","3-8 yıl hapis","5-10 yıl hapis"],ans:1,exp:"TCK m.85/1: Taksirle bir insanın ölümüne neden olan kişi 2 yıldan 6 yıla kadar hapis cezasıyla cezalandırılır. Birden fazla kişinin ölümüne ya da ölüm ile birlikte başkalarının yaralanmasına neden olunması nitelikli hâl sayılır (m.85/2: 2-15 yıl hapis). Olası kastla öldürmede ise m.81 uygulanır."},
  {q:"TCK'ya göre suça hazırlık hareketleri cezalandırılır mı?",opts:["Evet, her hazırlık hareketi teşebbüs gibi cezalandırılır","Hayır, icra hareketine başlanmadıkça hazırlık hareketleri kural olarak cezasızdır","Evet, ancak teşebbüs cezasının yarısı verilir","Savcı takdirine bırakılmıştır"],ans:1,exp:"TCK m.35: Teşebbüs, kişinin suçu işlemeye doğrudan doğruya icra hareketlerine başlaması ve elinde olmayan nedenlerle tamamlayamamasıyla oluşur. İcra hareketinin öncesindeki hazırlık hareketleri kural olarak cezalandırılmaz. Hazırlık ile icra hareketi arasındaki sınır somut/soyut tehlike kriterine göre belirlenir."},
  {q:"Azmettiren ve yardım eden (TCK m.38-39) hakkında ceza uygulaması nasıldır?",opts:["Her ikisi de asıl faille aynı cezayı alır","Azmettiren asıl faille aynı ceza alır; yardım eden indirimi ceza alır","Her ikisi de yarı ceza alır","Azmettiren indirimli, yardım eden asıl faille aynı ceza alır"],ans:1,exp:"TCK m.38: Başkasını suç işlemeye azmettiren kişi, o suç için kanunda öngörülen cezanın aynısı ile cezalandırılır. TCK m.39: Suçun işlenmesine yardım eden (yardım eden fail) ise cezanın 1/2'sine kadar veya ağırlaştırılmış müebbet yerine 15-20 yıl, müebbet yerine 10-15 yıl hapis cezasına hükmedilir. 'Azmettiren = aynı ceza, yardım eden = indirimli ceza' formülü sınavlarda çok sık sorulur."},
  // --- TCK Özel Hükümler (21.03.2026) ---
  {q:"TCK m.86/1'e göre kasten yaralama suçunun temel cezası nedir?",opts:["6 ay – 2 yıl hapis","1 yıl – 3 yıl hapis","2 yıl – 5 yıl hapis","3 ay – 1 yıl hapis"],ans:1,exp:"TCK m.86/1: Kasten başkasının vücuduna acı veren veya sağlığının ya da algılama yeteneğinin bozulmasına neden olan kişi 1 yıldan 3 yıla kadar hapis cezasıyla cezalandırılır. Basit tıbbi müdahaleyle giderilebilecek yaralama halinde bu suç şikâyete bağlı olup ceza daha alt sınırda belirlenebilir."},
  {q:"TCK m.87/4'e göre kasten yaralamanın ölüme neden olması halinde ceza nedir?",opts:["5-10 yıl hapis","8-12 yıl hapis","10-15 yıl hapis","Müebbet hapis"],ans:1,exp:"TCK m.87/4: Kasten yaralamanın ölüme neden olması halinde 8 yıldan 12 yıla kadar hapis cezasına hükmedilir. Doğrudan öldürme kastının bulunmadığı, ölümün taksirle gerçekleştiği bu hal taksirle öldürmeden (m.85) daha ağır; kasten öldürmeden (m.81: müebbet) ise daha hafif cezayı gerektirir."},
  {q:"TCK m.29'a göre haksız tahrik halinde cezada ne kadarlık indirim yapılır?",opts:["1/4 ile 3/4 oranında indirim","1/3 ile 1/2 oranında indirim","1/2 ile 2/3 oranında indirim","Hâkimin takdirine bırakılmıştır"],ans:0,exp:"TCK m.29: Haksız bir fiilin meydana getirdiği hiddet veya şiddetli elem etkisiyle suç işleyen kimsenin cezasında 1/4'ten 3/4'e kadar indirim yapılır. Tahrikin ağırlığına göre alt ya da üst sınıra yaklaşılır; sınavda 'haksız tahrik kaç oran' sorusu sıkça çıkar."},
  {q:"TCK m.141/1'e göre hırsızlık suçunun temel cezası nedir?",opts:["6 ay – 2 yıl hapis","1 yıl – 3 yıl hapis","2 yıl – 5 yıl hapis","3 ay – 1 yıl hapis"],ans:1,exp:"TCK m.141/1: Zilyedinin rızası olmadan başkasına ait taşınır bir malı, kendisine veya başkasına yarar sağlamak maksadıyla bulunduğu yerden alan kişiye 1 yıldan 3 yıla kadar hapis cezası verilir. Malın değerinin az olması hâkimin daha az ceza vermesini gerektiren bir hal sayılır."},
  {q:"TCK m.142/1'e göre nitelikli hırsızlığın temel cezası nedir?",opts:["1 yıl – 3 yıl hapis","2 yıl – 5 yıl hapis","2 yıl – 7 yıl hapis","5 yıl – 10 yıl hapis"],ans:2,exp:"TCK m.142/1: Hırsızlığın kilitli yerden, gece, konuttan, kamu binasından, toplu araçta veya bilişim sistemi kullanılarak işlenmesi gibi nitelikli hallerinde 2 yıldan 7 yıla kadar hapis cezası verilir. Bu maddede suçun işleniş koşulları nedeniyle ceza artırımı söz konusudur."},
  {q:"TCK m.157/1'e göre dolandırıcılık suçunun temel cezası nedir?",opts:["6 ay – 3 yıl hapis","1 yıl – 5 yıl hapis ve adlî para cezası","2 yıl – 7 yıl hapis","3 yıl – 10 yıl hapis"],ans:1,exp:"TCK m.157/1: Hileli davranışlarla bir kimseyi aldatan ve menfaat sağlayan kişiye 1 yıldan 5 yıla kadar hapis ve 5000 güne kadar adlî para cezası verilir. Nitelikli dolandırıcılık (m.158) çok daha ağır cezayı gerektirir — banka aracılığıyla, kamu görevlisi sıfatıyla gibi haller nitelikli sayılır."},
  {q:"TCK m.151/1'e göre mala zarar verme suçunun yaptırımı nedir?",opts:["4 ay – 3 yıl hapis veya adlî para cezası","6 ay – 3 yıl hapis","1 yıl – 4 yıl hapis","3 ay – 1 yıl hapis veya adlî para cezası"],ans:0,exp:"TCK m.151/1: Başkasının taşınır veya taşınmaz malını bozan, yok eden, kullanamazsa getiren veya kirleten kişi 4 aydan 3 yıla kadar hapis veya adlî para cezasıyla cezalandırılır. Bu suç şikâyete bağlıdır ve uzlaştırma kapsamındadır; uzlaşılması halinde kovuşturma düşer."},
  {q:"TCK m.54'e göre 'eşya müsaderesi' hangi durumlarda uygulanır?",opts:["Sanığın tüm malvarlığı müsadere edilir","Suçun işlenmesinde kullanılan, suça tahsis edilen veya suçtan meydana gelen eşya müsadere edilir","Yalnızca suçta kullanılan silahlar müsadere edilir","Yalnızca mahkûmiyet kararında uygulanır, beraatten sonra uygulanamaz"],ans:1,exp:"TCK m.54: Eşya müsaderesi; iyiniyetli 3. kişilere ait olmamak şartıyla suçun işlenmesinde kullanılan, suça tahsis edilen ya da suçtan meydana gelen eşyaya uygulanır. Genel müsadere (tüm malvarlığına el koyma) Anayasa m.38 gereğince kesinlikle yasaktır."},
  {q:"TCK m.53'e göre 'belli hakların kullanımından yoksun bırakma' hangi yaptırım türüdür?",opts:["Asıl ceza","Tedbir amaçlı tutuklama","Güvenlik tedbiri","Adlî para cezasının alternatifi"],ans:2,exp:"TCK m.53: Belli hakların kullanımından yoksun bırakma bir güvenlik tedbiridir; kasıtlı suç nedeniyle hapis cezasına mahkûmiyetin doğal sonucu olarak uygulanır. Kamu görevleri, seçme-seçilme, vakıf kurma gibi haklar ceza infaz edilene kadar kısıtlanır."},
  {q:"Konut dokunulmazlığını ihlal (TCK m.116) suçunun oluşması için temel unsur nedir?",opts:["Suç kastıyla girilmiş olması şarttır","Rızası olmaksızın konutuna girmek veya rıza ile girdikten sonra çıkmamak","Yalnızca gece saatlerinde gerçekleştirilmiş olmalıdır","Konut sahibine maddi zarar verilmiş olmalıdır"],ans:1,exp:"TCK m.116/1: Bir kimsenin konutuna, konutunun eklentilerine rızası olmaksızın giren veya rıza ile girdikten sonra çıkmayan kişi 1 yıldan 3 yıla kadar hapis cezasıyla cezalandırılır. Gece vakti ve silahla işlenmesi nitelikli hal sayılarak ceza artırılır."},
  // --- TCK Ek Sorular ---
  {q:"TCK m.105/1'e göre cinsel taciz suçunun temel cezası nedir?",opts:["3 aydan 2 yıla hapis veya adlî para cezası","1 yıldan 3 yıla hapis","2 yıldan 5 yıla hapis","6 aydan 3 yıla hapis"],ans:0,exp:"TCK m.105/1: Bir kimseyi cinsel amaçlı olarak taciz eden kişiye 3 aydan 2 yıla kadar hapis cezası veya adlî para cezası verilir. Hiyerarşi, hizmet ilişkisi, aynı işyeri, kamu görevlisi sıfatı gibi nitelikli hallerde ceza artırılır; mağdurun işten ayrılmak zorunda kalması hâlinde de ayrıca artırım söz konusudur."},
  {q:"TCK m.85/1'e göre taksirle bir insanın ölümüne neden olmanın temel cezası nedir?",opts:["6 aydan 3 yıla hapis","2 yıldan 6 yıla hapis","1 yıldan 5 yıla hapis","3 aydan 2 yıla hapis"],ans:1,exp:"TCK m.85/1: Taksirle bir insanın ölümüne neden olan kişi 2 yıldan 6 yıla kadar hapis cezasıyla cezalandırılır. Birden fazla kişinin ölümüne ya da bir kişinin ölümüyle birlikte başka kişilerin yaralanmasına neden olunması hâlinde ceza 2 yıldan 15 yıla kadar artırılır."},
  {q:"TCK m.204/1 ile m.204/2 arasındaki fark nedir?",opts:["m.204/1 resmi belgede, m.204/2 özel belgede sahteciliği düzenler","m.204/1 sıradan kişi tarafından, m.204/2 kamu görevlisi tarafından işlenen resmi belgede sahteciliği düzenler; ikincisinde ceza daha ağırdır","m.204/1 sahte belge düzenlemeyi, m.204/2 sahte belge kullanmayı düzenler","İkisi arasında ceza farkı yoktur"],ans:1,exp:"TCK m.204/1: Gerçeğe aykırı resmi belge düzenleyen veya kullanan kişiye 2 yıldan 5 yıla kadar hapis. m.204/2: Resmi belgede sahteciliği kamu görevlisi işlerse 3 yıldan 8 yıla kadar hapis cezası verilir. Kamu görevlisi niteliği cezayı artıran özel bir durumdur."},
  {q:"TCK m.207/1'e göre özel belgede sahtecilik suçunun cezası nedir?",opts:["3 aydan 1 yıla hapis","1 yıldan 3 yıla hapis","2 yıldan 5 yıla hapis","6 aya kadar hapis veya adlî para cezası"],ans:1,exp:"TCK m.207/1: Gerçeğe aykırı özel belge düzenleyen ya da bu tür belgeyi kullanan kişi 1 yıldan 3 yıla kadar hapis cezasıyla cezalandırılır. Özel belgede sahtecilik (m.207) resmi belgede sahteciliğe (m.204) göre daha hafif yaptırıma tabidir."},
  {q:"TCK m.134/1'e göre özel hayatın gizliliğini ihlal suçu hangi eylemle oluşur?",opts:["Yalnızca fotoğraf çekerek yayımlamakla oluşur","Kişinin özel yaşam alanındaki görüntü veya seslerini rızası olmadan kaydetmek ya da yayımlamakla oluşur","Yalnızca sosyal medyada paylaşımla oluşur","Kişi hakkında yazılı açıklama yapmakla oluşur"],ans:1,exp:"TCK m.134/1: Kişilerin özel yaşam alanındaki görüntü veya seslerini rızaları olmaksızın kaydeden kimseye 1 yıldan 3 yıla kadar hapis cezası verilir. Bu görüntü veya seslerin ifşa edilmesi (m.134/2) ise ayrıca cezayı gerektiren nitelikli bir hâldir."},
  {q:"TCK m.135/1'e göre kişisel verilerin hukuka aykırı olarak kaydedilmesinin yaptırımı nedir?",opts:["3 aydan 1 yıla hapis","1 yıldan 3 yıla hapis","2 yıldan 5 yıla hapis","Yalnızca adlî para cezası"],ans:1,exp:"TCK m.135/1: Hukuka aykırı olarak kişisel verileri kaydeden kimseye 1 yıldan 3 yıla kadar hapis cezası verilir. Siyasi, felsefi, dinî görüş, ırk, cinsel yaşam, sağlık gibi hassas kategorilerdeki verilerin kaydedilmesi nitelikli hal oluşturur."},
  {q:"TCK m.243/1'e göre bir bilişim sistemine hukuka aykırı olarak girmenin temel cezası nedir?",opts:["1 yıla kadar hapis veya adlî para cezası","2 yıldan 5 yıla hapis","6 aydan 2 yıla hapis","Yalnızca adlî para cezası"],ans:0,exp:"TCK m.243/1: Bir bilişim sisteminin bütününe veya bir kısmına hukuka aykırı olarak giren ya da orada kalmaya devam eden kimseye 1 yıla kadar hapis veya adlî para cezası verilir. Sistemde önemli bir değişikliğe ya da silmeye neden olunursa ceza 6 aydan 2 yıla kadar artırılır."},
  {q:"TCK m.244/1'e göre bilişim sistemini engelleme veya bozma suçunun temel cezası nedir?",opts:["6 aydan 2 yıla hapis","1 yıldan 5 yıla hapis","6 aya kadar hapis veya adlî para cezası","2 yıldan 6 yıla hapis"],ans:1,exp:"TCK m.244/1: Bir bilişim sisteminin işleyişini engelleyen, bozan, verileri bozan ya da yok eden kişiye 1 yıldan 5 yıla kadar hapis cezası verilir. Banka veya kredi kurumu ya da kamu kurumuna karşı işlenmesi nitelikli hal olup ceza artırılır."},
  {q:"TCK m.299/1'e göre Cumhurbaşkanına hakaret suçunun cezası ve kovuşturma koşulu nedir?",opts:["3 aydan 2 yıla hapis; şikâyet üzerine kovuşturulur","1 yıldan 4 yıla hapis; Adalet Bakanlığı'nın izniyle re'sen kovuşturulur","6 aydan 3 yıla hapis; şikâyetsiz re'sen kovuşturulur","1 yıldan 3 yıla hapis; Cumhurbaşkanı'nın şikâyetiyle kovuşturulur"],ans:1,exp:"TCK m.299/1: Cumhurbaşkanına hakaret eden kişi 1 yıldan 4 yıla kadar hapis cezasıyla cezalandırılır. Alenen işlenmesi cezayı artırır. Bu suç re'sen kovuşturulur; Adalet Bakanlığı izni zorunlu değildir. Soruşturmada savcının takdir yetkisi kullanılır."},
  {q:"TCK m.301/4'e göre 'Türk milletini aşağılama' suçuyla kovuşturma yapılabilmesi için zorunlu koşul nedir?",opts:["Cumhurbaşkanı'nın onayı","Adalet Bakanlığı'nın izni","Mağdurun şikâyeti","Savcının re'sen harekete geçmesi; izin gerekmez"],ans:1,exp:"TCK m.301/4 (2008 değişikliği): Türklüğü, Cumhuriyet'i veya devlet kurumlarını aşağılama suçuyla kovuşturma yapılabilmesi için Adalet Bakanlığı'nın izni zorunludur. Bu düzenleme ifade özgürlüğünü korumaya yönelik bir güvence işlevi görmektedir."},
  {q:"TCK m.86/3'e göre kasten yaralama suçunun nitelikli hallerinden biri aşağıdakilerden hangisidir?",opts:["Yalnızca gece vakti işlenmesi","Üstsoy, altsoy veya eşe karşı işlenmesi","Kapalı alanda işlenmesi","Mağdurun daha önce şikâyette bulunmuş olması"],ans:1,exp:"TCK m.86/3: Kasten yaralama; kamu görevlisine görevi sırasında, üstsoy/altsoy/eşe/kardeşe karşı, savunması güç kişiye karşı, silahla veya birden fazla kişiyle işlenirse nitelikli hal oluşur ve ceza 1/2 oranında artırılır."},
  {q:"TCK m.36'ya göre 'gönüllü vazgeçme'nin suça teşebbüs bakımından sonucu nedir?",opts:["Ceza 1/4 oranında indirilir","Fail o suçun teşebbüs hükümlerine göre cezalandırılmaz; ancak önceki tamamlanmış eylemler için ayrıca ceza verilebilir","Ceza yarı oranında indirilir","Kovuşturmaya yer olmadığına karar verilir"],ans:1,exp:"TCK m.36: Suçun icrasına başlayan fail kendi isteğiyle vazgeçerse ya da neticenin gerçekleşmesini engellerse teşebbüs hükümlerinden cezalandırılmaz. Gönüllü vazgeçme öncesi gerçekleştirilen ve başlı başına suç oluşturan eylemler cezasızlığa yol açmaz."},
  {q:"TCK m.29'a göre haksız tahrik indiriminin uygulanabilmesi için temel koşul nedir?",opts:["Failin suçu planlamadan ani bir kararla işlemesi","Haksız bir fiilin yarattığı hiddet veya şiddetli elem etkisiyle suç işlenmesi","Failin yaşının 25'in altında olması","Mağdurun kışkırtıcı davranışı kanıtlanmış olmalıdır"],ans:1,exp:"TCK m.29: Haksız bir fiilin meydana getirdiği hiddet veya şiddetli elemin etkisiyle suç işleyen faile indirimli ceza verilir. Ağırlaştırılmış müebbet yerine 18-24 yıl; müebbet yerine 12-18 yıl; diğerlerinde 1/4 ile 3/4 oranında indirim uygulanır."},
  {q:"TCK m.23'e göre 'neticesi sebebiyle ağırlaşmış suç' hangi koşulda oluşur?",opts:["Suçun birden fazla kişiyle işlenmesi hâlinde","Kastın ötesine geçen ağır neticenin gerçekleşmesi ve faile bu netice bakımından en azından taksirin yüklenebilmesi hâlinde","Failin sabıkasının bulunması hâlinde","Suçun gece işlenmesi hâlinde"],ans:1,exp:"TCK m.23: Failin kastının ötesine geçen bir netice meydana gelirse daha ağır ceza için bu netice bakımından en azından taksirin varlığı gerekir. Örneğin kasten yaralama sonucunda ölüm gerçekleşirse (m.87/4), failin ölüm sonucunu öngörmüş ya da taksirle meydana getirmiş olması aranır."},
  {q:"TCK m.278/1'e göre işlenmekte olan bir suçu bildirme yükümlülüğünü yerine getirmeyen kişinin yaptırımı nedir?",opts:["2 yıldan 4 yıla hapis","1 yıla kadar hapis cezası","Yalnızca adlî para cezası","Herhangi bir yaptırım öngörülmemiştir"],ans:1,exp:"TCK m.278/1: Yetkili makamlara bildirme imkânı bulunmasına rağmen işlenmekte olan suçu bildirmeyen kişiye 1 yıla kadar hapis cezası verilir. Kamu görevlilerinin yükümlülüğü daha ağırdır (m.279). Bu suç ihbar zorunluluğunu hukuki bir ödev hâline getirir."},
  {q:"TCK m.168/1'e göre etkin pişmanlık hükümlerinin uygulanabilmesi için hırsızlık suçunda ne gerekmektedir?",opts:["Suçun tespitinden önce yetkililere ihbar","Failin pişmanlığını beyan etmesi","Soruşturma başlamadan önce malı iade veya zararı gidermek","Mağdurla uzlaşma sağlanması"],ans:2,exp:"TCK m.168/1: Soruşturma başlamadan önce hırsızlık, mala zarar verme, güveni kötüye kullanma veya dolandırıcılık suçunun mağdurunun uğradığı zarar tamamen karşılanır ya da mal aynen iade edilirse ceza 2/3 oranında indirilir. Kovuşturma başladıktan sonra ama hüküm öncesi karşılanırsa 1/2 indirim uygulanır."},
  {q:"TCK m.25/2'ye göre zorunluluk hâlinde ceza verilebilmesi engellenebilmesi için hangi temel koşul aranır?",opts:["Failin tehlikeye bizzat yol açmamış olması","Fiilin orantılı olması ve başka türlü korunma olanağının bulunmaması","Yalnızca can tehlikesinde uygulanır","Tehlikenin kaçınılmaz olması şartı aranmaz"],ans:1,exp:"TCK m.25/2: Kendisine veya başkasına yönelik bir hakkı korumak amacıyla başka türlü korunma imkânı bulunmayan ve tehlikenin ağırlığı ile orantılı olan bir davranışla suç işleyen faile ceza verilmez. Orantılılık ve alternatif yolların yokluğu zorunluluk hâlinin temel şartlarıdır."}
],
cmk:[
  {q:"CMK m.90'a göre suçüstü hâlinde herkes yakalama yapabilir mi?",opts:["Evet, her durumda yapabilir","Evet, suçüstü hâlinde veya gecikmeksizin bildirim yapılamazsa","Hayır, sadece kolluk yapabilir","Hayır, hâkim kararı gerekir"],ans:1,exp:"CMK m.90: Suçüstü hâlinde veya kolluğa derhal bildirim yapılamayacak durumda herkes yakalama yapabilir. Yakalama sonrasında kişi derhâl kolluğa teslim edilmelidir."},
  {q:"Tutukluluk süresi ağır ceza mahkemesinin görevine giren suçlarda en fazla kaçtır?",opts:["6 ay","1 yıl","2 yıl","5 yıl"],ans:2,exp:"CMK m.102: Ağır ceza mahkemesinin görevine giren işlerde tutukluluk süresi en fazla 2 yıldır; zorunlu hallerde 3 yıla uzatılabilir. Örgüt suçlarında bu süreler farklı şekilde düzenlenmiştir."},
  {q:"Sanığın zorunlu müdafi ile temsil edileceği haller arasında hangisi yer almaz?",opts:["Alt sınırı 5 yıl ve üzeri hapis gerektiren suçlar","Yaşı küçük sanıklar","Sağır ve dilsiz sanıklar","Üst sınırı 6 aya kadar hapis gerektiren suçlar"],ans:3,exp:"CMK m.150: Zorunlu müdafilik; alt sınırı 5 yıl ve üzeri hapis gerektiren suçlarda, yaşı küçük ve engelli sanıklarda ve gözaltındaki sanıklarda uygulanır. Hafif suçlarda zorunlu müdafilik aranmaz."},
  {q:"Delil yasakları bakımından CMK'nın öngördüğü kural nedir?",opts:["Her delil kabul edilir","Hukuka aykırı deliller kesinlikle reddedilir","Hâkim takdir eder","Savcı karar verir"],ans:1,exp:"CMK m.206/2-a: Hukuka aykırı yollarla elde edilen deliller reddedilerek dosyadan çıkarılır. İşkence, baskı, kandırma ya da yasadışı dinleme yoluyla elde edilen deliller hükme esas alınamaz."},
  {q:"Uzlaştırma kurumu hangi suç türlerine uygulanır?",opts:["Tüm suçlara","Yalnızca cinsel suçlara","Kanunda sayılan belirli suçlara (şikayete bağlı ve basit suçlar)","Yalnızca ekonomik suçlara"],ans:2,exp:"Uzlaştırma; kasten yaralama, mala zarar verme, dolandırıcılık gibi kanunda öngörülen belirli suçlara uygulanır. Cinsel suçlar, ağır cezalı suçlar ve kamu görevlisi tarafından işlenen suçlar uzlaştırma kapsamı dışındadır."},
  {q:"Adli kontrol kararı kim tarafından verilir?",opts:["Cumhuriyet Savcısı","Sulh Ceza Hâkimi","Ağır Ceza Mahkemesi","Emniyet Müdürü"],ans:1,exp:"CMK m.110: Adli kontrol kararı sulh ceza hâkimi tarafından verilir. Adli kontrol; tutuklamaya alternatif olarak uygulanan ve kişi özgürlüğünü daha az kısıtlayan tedbirlerden oluşur."},
  {q:"'İfade alma' ile 'sorgu' arasındaki temel fark nedir?",opts:["İkisi aynıdır","İfade savcı/kolluk tarafından; sorgu hâkim tarafından alınır","Sorgu sadece tutukludan alınır","İfade yazılı; sorgu sözlü yapılır"],ans:1,exp:"İfade savcı veya kolluk tarafından alınan beyan; sorgu ise hâkim önünde alınan beyandır. Tutuklama kararı öncesinde hâkim sorgusu yapılmak zorundadır. Her iki aşamada da haklar bildirilmelidir."},
  {q:"Arama kararında bulunması zorunlu unsurlar nelerdir?",opts:["Sadece tarih","Tarih, mekân ve kapsam","Savcı imzası yeterlidir","Herhangi bir kısıtlama yoktur"],ans:1,exp:"CMK m.119: Arama kararında; aramanın yapılacağı yer ve kapsam, kararın tarihi ve gerekçesi açıkça belirtilmelidir. Eksik veya belirsiz kararla yapılan aramada elde edilen deliller hukuka aykırı sayılabilir."},
  {q:"İstinaf yoluna başvuru süresi kaç gündür?",opts:["7 gün","15 gün","30 gün","60 gün"],ans:1,exp:"CMK m.273: İstinaf yoluna başvuru süresi, hükmün sanığa tebliğinden itibaren 15 gündür. Bu süre hak düşürücüdür; süre geçtikten sonra başvurulması hâlinde talep reddedilir."},
  {q:"Ceza muhakemesinde 'ispat yükü' kime aittir?",opts:["Sanığa aittir","Savunma avukatına aittir","İddiayı ileri süren Cumhuriyet savcısına aittir","Mahkemeye aittir"],ans:2,exp:"Ceza muhakemesinde ispat yükü savcılıktadır; sanık kendini ispat etmek zorunda değildir. Masumiyet karinesi (in dubio pro reo): Şüphe durumunda sanık lehine yorum yapılır."},
  {q:"Toplu suçlarda gözaltı süresini uzatma yetkisi kime aittir? (2025 PAEM)",opts:["Mülki Amire","Hâkime","İlk 48 saatla sınırlıdır","Cumhuriyet savcısına (her seferinde 1 günü geçmemek üzere 3 güne kadar)"],ans:3,exp:"CMK m.91/3: Toplu suçlarda savcı yazılı emirle gözaltı süresini uzatabilir."},
  {q:"Aciliyet nedeniyle savcıya ulaşılamayan hırsızlıkta arama emri kime aittir? (2025 PAEM)",opts:["Hâkime","Mahkeme başkanına","Kolluk amirine","Kaymakama"],ans:2,exp:"CMK m.119/4: Savcıya ulaşılamazsa kolluk amiri arama kararı verebilir; 24 saat içinde savcıya sunulur."},
  {q:"CMK'da 'şüpheli' nasıl tanımlanmıştır? (2025 PAEM)",opts:["Kovuşturmada suç şüphesi altındaki kişi","Katılan veya suçtan zarar gören","Hükmün sonuçlarından etkilenecek kişi","Soruşturmada suç şüphesi altındaki kişi"],ans:3,exp:"CMK m.2/b: Şüpheli; soruşturma evresinde suç şüphesi altında bulunan kişidir."},
  {q:"CMK'ya göre sorgu yetkisi kime aittir? (2025 PAEM)",opts:["Mağdura","Müdafiye","Cumhuriyet savcısına","Hâkim veya mahkemeye"],ans:3,exp:"CMK: Sorgu yetkisi hâkim veya mahkemeye aittir; savcı ifade alır."},
  {q:"CMK'ya göre gözaltı süresi ne kadardır?",opts:["12 saat","24 saat","48 saat","72 saat"],ans:1,exp:"CMK m.91: Yakalanan kişi, serbest bırakılmazsa gözaltına alınır. Gözaltı süresi yakalama anından itibaren 24 saati geçemez. Toplu suçlarda savcı yazılı emirle bu süreyi uzatabilir."},
  {q:"Tutuklama kararı hangi mercii tarafından verilir?",opts:["Cumhuriyet savcısı","Emniyet müdürü","Sulh ceza hâkimi","Ağır ceza mahkemesi başkanı"],ans:2,exp:"CMK m.100: Tutuklama kararı ancak sulh ceza hâkimi tarafından verilebilir. Soruşturma evresinde savcının talebi üzerine, kovuşturma evresinde ise mahkeme tarafından re'sen ya da talep üzerine tutuklama kararı verilebilir."},
  {q:"Şüpheli veya sanığın susma hakkı hangi aşamalarda kullanılabilir?",opts:["Yalnızca duruşmada","Yalnızca gözaltında","İfade alma ve sorgu dahil her aşamada","Sadece avukat eşliğinde"],ans:2,exp:"CMK m.147: Şüpheli veya sanık, ifade alma veya sorgu öncesinde susma hakkı olduğu hususunda mutlaka bilgilendirilmelidir. Bu hak; soruşturmadan kovuşturmanın sonuna kadar her aşamada kullanılabilir."},
  {q:"Savcının soruşturma sonunda kovuşturma açmayı gerekli görmediğinde verdiği karar nedir?",opts:["Beraat kararı","Düşme kararı","Kovuşturmaya yer olmadığı kararı","Erteleme kararı"],ans:2,exp:"CMK m.172: Yeterli şüphe oluşturacak delil elde edilememesi veya kovuşturma şartının gerçekleşmemesi hâlinde savcı kovuşturmaya yer olmadığına dair karar verir. Bu karara karşı sulh ceza hâkimliğine itiraz edilebilir."},
  {q:"CMK m.216'ya göre sanığın 'son söz hakkı' hangi aşamada kullanılır?",opts:["İddianamenin okunmasından önce","Tanık dinlenmesinden sonra","Tüm delil ve mütalaalar bittikten sonra, karar öncesinde","Karar okunduktan sonra"],ans:2,exp:"CMK m.216: Son söz sanığa aittir. Tüm delil ve tanık incelemeleri ile mütalaa aşaması bittikten sonra, karar açıklanmadan hemen önce sanığa son söz hakkı tanınır. Bu usul kuralına uyulmaması bozma nedeni sayılabilir."},
  {q:"Elkoyma kararı kural olarak hangi mercii tarafından verilir?",opts:["Cumhuriyet savcısı","Sulh ceza hâkimi","Kolluk amiri","Kaymakam"],ans:1,exp:"CMK m.127: Elkoyma kararı kural olarak hâkim tarafından verilir. Gecikmesinde sakınca bulunan hâllerde Cumhuriyet savcısı, savcıya ulaşılamayan hâllerde ise kolluk amiri elkoyma yapabilir; bu kararın 24 saat içinde hâkim onayına sunulması gerekir."},
  {q:"İletişimin denetlenmesi (telefon dinleme) kararı hangi mercii tarafından verilir?",opts:["Emniyet müdürü","Cumhuriyet savcısı","Sulh ceza hâkimi","Anayasa Mahkemesi"],ans:2,exp:"CMK m.135: İletişimin denetlenmesi ancak sulh ceza hâkiminin kararıyla yapılabilir. Gecikmesinde sakınca bulunan hâllerde Cumhuriyet savcısı karar verebilir; bu kararın 24 saat içinde hâkim onayına sunulması şarttır, aksi hâlde tedbir kendiliğinden kalkar."},
  {q:"Tanığın CMK kapsamındaki temel yükümlülükleri nelerdir?",opts:["Yalnızca davete uymak","Davete uymak, yemin etmek, doğruyu söylemek","Sadece yemin etmek","İfade vermek zorunda değildir"],ans:1,exp:"CMK m.43-60: Tanık; çağrıldığında mahkemeye gelmek, usulüne uygun yemin etmek ve gerçeği söylemekle yükümlüdür. Yalan tanıklık suç teşkil eder (TCK m.272). Yakın akrabalar belirli koşullarda tanıklıktan çekinebilir."},
  {q:"Beden muayenesi ve moleküler genetik inceleme hangi kararla yapılabilir?",opts:["Savcının talebiyle doğrudan","Yalnızca mahkeme kararıyla","Hâkim kararıyla; gecikmesinde sakınca varsa savcı kararıyla","Emniyet müdürünün onayıyla"],ans:2,exp:"CMK m.75-76: Şüpheli veya sanığın beden muayenesi ve genetik incelemesi hâkim kararıyla yapılır. Gecikmesinde sakınca bulunan hâllerde Cumhuriyet savcısının kararıyla da yapılabilir; bu karar 24 saat içinde hâkim onayına sunulur."},
  {q:"Bilirkişi CMK'ya göre kim tarafından atanır?",opts:["Cumhuriyet savcısı","Mahkeme veya hâkim","Taraflar anlaşarak","Adalet Bakanlığı"],ans:1,exp:"CMK m.63: Çözümü uzmanlık gerektiren konularda mahkeme veya hâkim bilirkişi atayabilir. Taraflar kendi bilirkişilerini atayamaz; ancak bilirkişi seçimine itiraz hakkına sahiptir. Bilirkişi görüşü hâkimi bağlamaz."},
  {q:"Yeniden yargılama hangi hâllerde mümkündür?",opts:["Yalnızca beraat kararlarında","Yalnızca yeni delil ortaya çıktığında","AİHM ihlal kararı ve yeni delil gibi kanunda belirtilen hâllerde","Sadece sanığın başvurusuyla"],ans:2,exp:"CMK m.311-323: Kesinleşmiş mahkumiyet kararlarına karşı yeniden yargılama yoluna başvurulabilir. Temel nedenleri: sahte delil kullanımı, sonradan ortaya çıkan yeni delil ve AİHM'in ihlal tespiti. Bu başvuruda süre sınırı yoktur."},
  {q:"Duruşmanın aleni yapılması ilkesinin istisnası nedir?",opts:["Sanık talep ederse","Genel ahlak veya kamu güvenliği gerektiriyorsa","Tanıklar itiraz ederse","Savcı talep ederse"],ans:1,exp:"CMK m.182: Kural olarak duruşmalar alenidir. Ancak genel ahlak veya kamu güvenliği gerektirdiğinde mahkeme duruşmayı gizli yapabilir. Kapalı duruşma kararı gerekçeli olmalı ve duruşma tutanağına işlenmelidir."},
  {q:"CMK'ya göre temyiz başvuru süresi kaç gündür?",opts:["7 gün","10 gün","15 gün","30 gün"],ans:2,exp:"CMK m.291: Temyiz yoluna başvurma süresi, hükmün sanığa tefhim veya tebliğinden itibaren 15 gündür. İstinaf kararlarına karşı yapılan temyiz için de aynı 15 günlük süre uygulanır."},
  {q:"Zorunlu müdafi atanmasında avukatlık ücreti kim tarafından karşılanır?",opts:["Sanık her durumda öder","Devlet (Adalet Bakanlığı bütçesinden)","Barolar karşılar","Mağdur öder"],ans:1,exp:"CMK m.150-157: Atanan zorunlu müdafiin ücreti devlet tarafından Adalet Bakanlığı bütçesinden karşılanır. Ancak sanık mahkûm edilir ve ödeme gücüne sahip olduğu anlaşılırsa bu ücret sanıktan tahsil edilebilir."},
  {q:"Katılan (müdahil) kimdir ve davaya katılma ne zaman mümkündür?",opts:["Davayı açan savcı","Suçtan zarar gören ve kovuşturma evresinde davaya katılan kişi","Sanığın yakını","Bilirkişi"],ans:1,exp:"CMK m.237: Mağdur veya suçtan zarar gören kişi ya da mirasçıları kovuşturma evresinde davaya katılabilir. Soruşturma evresinde katılma mümkün değildir; iddianamenin kabulünden sonra, hüküm verilinceye kadar katılma talebinde bulunulabilir."},
  {q:"Gizli soruşturmacı görevlendirmesi CMK'da hangi suçlar için mümkündür?",opts:["Tüm suçlar için","Yalnızca terör suçları için","Kanunda sayılan katalog suçlar için","Yalnızca uyuşturucu suçları için"],ans:2,exp:"CMK m.139: Gizli soruşturmacı; uyuşturucu ticareti, silah kaçakçılığı, terör ve organize suç gibi kanunda öngörülen katalog (ağır) suçlarda görevlendirilebilir. Her suç için kullanılamaz; hâkim kararı zorunludur."},
  // --- CMK Transkript Ek Sorular (21.03.2026) ---
  {q:"CMK m.2'ye göre 'toplu suç' için kaç veya daha fazla kişi aranmaktadır?",opts:["2","3","4","5"],ans:1,exp:"CMK m.2: Aralarında iştirak iradesi bulunmasa bile 3 veya daha fazla kişi tarafından işlenen suç toplu suç sayılır. 2 kişiyle işlenen suç toplu suç değildir."},
  {q:"CMK'ya göre suçun işlendiği yer belli değilse yetkili mahkeme nasıl belirlenir?",opts:["Her zaman Ankara mahkemesi yetkilidir","Şüphelinin yakalandığı yer, yoksa yerleşim yeri mahkemesi","Suçtan zarar görenin oturduğu yer mahkemesi","İlk soruşturma işleminin yapıldığı yer mahkemesi"],ans:1,exp:"CMK m.13: Suçun işlendiği yer belli değilse şüpheli veya sanığın yakalandığı yer mahkemesi yetkilidir. Yakalanmamışsa yerleşim yeri, o da yoksa Türkiye'deki son adresi, o da belirsizse ilk usul işleminin yapıldığı yer mahkemesi yetkili olur."},
  {q:"CMK m.39'a göre gün ile belirlenen süreler ne zaman işlemeye başlar?",opts:["Kararın verildiği gün","Tebligatın yapıldığı gün","Tebligatın yapıldığının ertesi günü","Kararın kesinleştiği gün"],ans:2,exp:"CMK m.39: Gün ile belirlenen süreler tebligatın yapıldığının ertesi günü işlemeye başlar. Tebliğ günü süreye dahil edilmez."},
  {q:"CMK'ya göre sürenin son günü resmi tatile rastlarsa süre ne zaman biter?",opts:["Tatil başlamadan önceki iş günü biter","Tatil gününün sonu biter","Tatilin ertesi günü mesai bitimiyle sona erer","Süre otomatik olarak uzamaz, tatilde de işler"],ans:2,exp:"CMK m.39: Son gün tatile rastlarsa süre tatili izleyen ilk iş günü mesai saati bitiminde sona erer. Bu kural gün, hafta ve ay cinsinden belirlenen süreler için geçerlidir."},
  {q:"CMK m.45'e göre tanıklıktan çekinme hakkına sahip olmayan kimdir?",opts:["Şüphelinin nişanlısı","Şüphelinin ikinci derece kayın hısımı","Şüphelinin iş arkadaşı","Şüphelinin eşi (evlilik sona erse bile)"],ans:2,exp:"CMK m.45: Tanıklıktan çekinme hakkı; nişanlı, eş (evlilik sona erse bile), üstsoy-altsoy kan/kayın hısımları (3. derece dahil kan, 2. derece dahil kayın) ve evlatlık bağı olanlara tanınmıştır. İş arkadaşına bu hak tanınmamıştır."},
  {q:"CMK m.50'ye göre aşağıdakilerden hangisi yeminsiz dinlenir?",opts:["30 yaşındaki iki suç tanığı","15 yaşını doldurmamış tanık","Mesleki sır sahibi hekim","Avukat olan tanık"],ans:1,exp:"CMK m.50: 15 yaşını doldurmamış olanlar, ayırt etme gücü olmayanlar ve suça iştirak edenler/suçluyu kayıranlar yeminsiz dinlenir. Hekim ve avukat çekinme hakkını kullanmadığında yemin ederek dinlenir."},
  {q:"Bilirkişi incelemesinin süresi kaç ay olup en fazla ne kadar uzatılabilir?",opts:["1 ay, 1 ay uzatılabilir","2 ay, 1 ay uzatılabilir","3 ay, 3 ay uzatılabilir","6 ay, uzatılamaz"],ans:2,exp:"CMK m.66: Bilirkişi incelemesi en çok 3 ay için verilebilir. Özel sebeplerle zorunlu kılındığında bu süre hâkim/mahkemenin gerekçeli kararıyla en çok 3 ay daha uzatılabilir. Toplam azami 6 ay."},
  {q:"CMK m.74'e göre gözlem altına alınma kararını soruşturma evresinde kim verir?",opts:["Cumhuriyet savcısı","Asliye Ceza Hâkimi","Sulh Ceza Hâkimi","Ağır Ceza Mahkemesi"],ans:2,exp:"CMK m.74: Soruşturma evresinde Sulh Ceza Hâkimi, kovuşturma evresinde ise mahkeme gözlem altına alınma kararı verir. Gözlem süresi her seferinde 3 haftayı, toplamda 3 ayı geçemez."},
  {q:"CMK m.75'e göre iç beden muayenesi hangi durumda yapılamaz?",opts:["Şüpheli yabancı uyruklu ise","Suçun üst sınırı 2 yıldan az hapis cezasını gerektiriyorsa","Müdafi hazır değilse","Gece saatlerinde ise"],ans:1,exp:"CMK m.75: Üst sınırı 2 yıldan daha az hapis cezasını gerektiren suçlarda kişi üzerinde iç beden muayenesi yapılamaz ve vücuttan kan gibi biyolojik örnekler alınamaz."},
  {q:"CMK m.79'a göre moleküler genetik inceleme (DNA testi) yapılmasına kim karar verebilir?",opts:["Cumhuriyet savcısı ve hâkim","Yalnızca hâkim","Mahkeme ve Cumhuriyet savcısı","Sadece Ağır Ceza Mahkemesi"],ans:1,exp:"CMK m.79: Moleküler genetik inceleme yapılmasına sadece hâkim karar verebilir. Cumhuriyet savcısı veya mahkeme tek başına bu karara veremez. Bu kural genetik incelemelerin güvencesidir."},
  {q:"Otopsi kimler tarafından yapılır ve kaç kişi gerekir? (CMK m.87)",opts:["Bir adli tıp uzmanı tarafından","İki hekim (biri adli tıp veya patoloji uzmanı) tarafından","Üç hekim tarafından","Savcı ve bir hekim tarafından"],ans:1,exp:"CMK m.87: Otopsi Cumhuriyet savcısının huzurunda, biri adli tıp veya patoloji uzmanı olmak üzere iki hekim tarafından yapılır. Otopsi zorunlu olarak baş, göğüs ve karın açılmasını gerektirir."},
  {q:"CMK m.135 uyarınca iletişim denetleme kararı normal suçlarda en fazla kaç ay için verilebilir?",opts:["1 ay","2 ay","3 ay","6 ay"],ans:1,exp:"CMK m.135: İletişimin denetlenmesi kararı en çok 2 ay için verilir; bu süre 1 ay daha uzatılabilir. Örgüt faaliyeti çerçevesinde işlenen suçlarda ek olarak her defasında 1 ay olmak üzere toplam 3 ay daha uzatılabilir."},
  {q:"CMK m.140'a göre teknik araçlarla izleme kararı en fazla kaç haftalık süre için verilebilir?",opts:["1 hafta","2 hafta","3 hafta","4 hafta"],ans:2,exp:"CMK m.140: Teknik araçlarla izleme kararı en çok 3 hafta için verilebilir. Bu süre 1 hafta daha uzatılabilir. Örgüt suçlarında her defasında 1 haftayı aşmamak üzere toplam 4 hafta daha uzatılabilir."},
  {q:"CMK m.141-142 uyarınca haksız tutuklama nedeniyle tazminat başvurusu hangi süre içinde yapılmalıdır?",opts:["1 ay (tebliğden)","3 ay (tebliğden) ve her hâlde 1 yıl içinde","6 ay (tebliğden)","Süre kısıtlaması yoktur"],ans:1,exp:"CMK m.142: Tazminat istemi; karar veya hükümlerin kesinleştiğinin tebliğinden itibaren 3 ay ve her hâlde 1 yıl içinde yapılmalıdır. Başvuru, zarara uğrayanın oturduğu yer Ağır Ceza Mahkemesi'ne yapılır."},
  {q:"CMK m.148'e göre müdafi hazır bulunmaksızın kollukça alınan ifade hakkında aşağıdakilerden hangisi doğrudur?",opts:["Her zaman geçerlidir","Hâkim önünde sanık tarafından doğrulanmadıkça hükme esas alınamaz","Sadece yazılı ise geçerlidir","Rıza ile alınmışsa geçerlidir"],ans:1,exp:"CMK m.148: Müdafi hazır bulunmaksızın kollukça alınan ifade; hâkim veya mahkeme huzurunda şüpheli veya sanık tarafından doğrulanmadıkça hükme esas alınamaz. Bu kural savunma hakkının güvencesidir."},
  {q:"CMK m.231 uyarınca HAGB kararı için sanığın denetim altında tutulduğu süre kaç yıldır?",opts:["2 yıl","3 yıl","5 yıl","10 yıl"],ans:2,exp:"CMK m.231: HAGB kararı verilen sanık 5 yıl süreyle denetim süresine tabi tutulur. Bu süre içinde kasıtlı yeni bir suç işlenmezse dava düşer; işlenirse hüküm açıklanır."},
  {q:"Basit yargılama usulünde (CMK m.251) mahkûmiyet kararı verildiğinde ceza ne kadar indirilir?",opts:["1/8 oranında","1/4 oranında","1/3 oranında","1/2 oranında"],ans:1,exp:"CMK m.251: Basit yargılama usulünde (üst sınırı 2 yıl veya daha az hapis gerektiren suçlar) mahkûmiyet kararı verildiğinde sonuç ceza 1/4 oranında indirilir. Ayrıca savcı görüşü alınmaksızın ve duruşma yapılmaksızın karar verilebilir."},
  {q:"CMK m.253'e göre uzlaştırmacının dosyayı teslim aldıktan sonra işlemleri tamamlamak için ne kadar süresi vardır?",opts:["15 gün","30 gün (2 kez 20'şer gün uzatılabilir)","45 gün","60 gün"],ans:1,exp:"CMK m.253: Uzlaştırmacı, dosya belgeleri kendisine verildikten itibaren en geç 30 gün içinde uzlaştırma işlemlerini tamamlar. Uzlaştırma bürosu bu süreyi her defasında 20 günü geçmemek üzere en fazla iki kez uzatabilir."},
  {q:"CMK'ya göre sanığın sorgusu sırasında müdafi hazır bulunabilir mi?",opts:["Hayır, sorguda müdafi bulunamaz","Evet, sanığın talebi olmasa dahi müdafi hazır bulunabilir","Yalnızca tutuklu sanıkta müdafi bulunabilir","Sadece ağır ceza davalarında mümkündür"],ans:1,exp:"CMK m.149: Şüpheli veya sanık, soruşturma ve kovuşturmanın her aşamasında müdafiden yararlanabilir. Müdafi sorgu ve ifade alma sırasında hazır bulunma hakkına sahiptir; bu hak sanığın talebine bağlı değildir."},
  {q:"CMK'ya göre savcının iddianame düzenlemesi için yeterli şüphe eşiği nedir?",opts:["Makul şüphe","Kuvvetli şüphe","Yeterli şüphe","Kesin kanıt"],ans:2,exp:"CMK m.170: Cumhuriyet savcısı, soruşturma sonunda fiilin suç oluşturduğuna dair yeterli şüpheye ulaşırsa iddianame düzenler. Bu eşik, tutuklama için aranan 'kuvvetli şüphe'den daha düşük; 'makul şüphe'den daha yüksektir."}
],
analitik:[
  {q:"Bir işyerinde 4 kişi 6 günde bir işi bitiriyor. Aynı işi 3 günde bitirmek için kaç kişi gerekir?",opts:["6","8","10","12"],ans:1,exp:"Toplam iş = 4 × 6 = 24 kişi-gün. 3 günde bitirmek için: 24 ÷ 3 = 8 kişi gerekir. Bu ters orantı problemidir: süre azaldıkça kişi sayısı artar."},
  {q:"'Tüm A'lar B'dir. Bazı B'ler C'dir.' Bu önermelerden çıkarılabilecek kesin sonuç nedir?",opts:["Tüm A'lar C'dir","Bazı A'lar C'dir","Hiçbir A, C değildir","Kesin bir sonuç çıkarılamaz"],ans:3,exp:"Tüm A'lar B'dir ama sadece bazı B'ler C'dir. A'ların hangi kısmının B'nin C olan kısmıyla örtüştüğü bilinemez. Bu nedenle A ile C arasında kesin bir ilişki kurulamaz."},
  {q:"2, 6, 18, 54, ? — Dizi tamamlandığında boşluğa ne gelmelidir?",opts:["108","126","162","216"],ans:2,exp:"Her sayı bir öncekinin 3 katıdır: 2×3=6, 6×3=18, 18×3=54, 54×3=162. Bu sabit oranlı geometrik bir dizidir."},
  {q:"'Post hoc ergo propter hoc' yanılgısı neyi ifade eder?",opts:["Çok fazla sebep ileri sürme","Sonradan gelen şeyin öncekinin nedeni olduğunu varsayma","Kişiye saldırarak argümanı çürütme","Genel kuraldan özel durum çıkarma"],ans:1,exp:"Bu Latin ifadesi 'Bundan sonra geldi, öyleyse bunun sebebiyle geldi' anlamına gelir. Ardışıklıktan nedensellik çıkarmak temel bir mantık hatasıdır. Örnek: 'Horoz öttükten sonra güneş doğdu, demek ki horoz öttürdü.'"},
  {q:"Bir trenin 200 metre uzunluğu vardır ve saatte 60 km hızla gitmektedir. 800 metre uzunluğundaki bir tüneli geçmesi kaç saniye sürer?",opts:["36","60","72","80"],ans:2,exp:"Tren tüneli geçmek için kendi boyu + tünel boyu = 200 + 800 = 1000 metre gitmeli. Hız = 60 km/s = 1000/60 m/s ≈ 16.67 m/s. Süre = 1000 ÷ 16.67 ≈ 60 saniye. Not: Seçenekler için 60 km/s → 50/3 m/s; 1000/(50/3)=60s. En yakın: 60. Doğru: 60s (B şıkkı = 60)."},
  {q:"Mantıksal çıkarım türlerinden 'abüdksiyon' (abduction) neyi ifade eder?",opts:["Genel öncülden özel sonuç","Gözlemden genel sonuç","Gözlemlenen bir sonucu en iyi açıklayan hipotezi öne sürme","İki analoji arasında bağlantı kurma"],ans:2,exp:"Abdüksiyon (en iyi açıklamaya çıkarım): Mevcut verileri en iyi açıklayan hipotezi seçme yöntemidir. Tümdengelim ve tümevarımdan farklı olarak olasılıklı bir hipotez önerir; bilimsel keşifte yaygın kullanılır."},
  {q:"'Saman Adam' (Straw Man) yanılgısı nedir?",opts:["Kişinin zayıf yönlerini kullanma","Rakibin argümanını çarpıtarak daha kolay çürütülecek versiyonuna saldırma","Çok fazla kaynak gösterme","Duygusal argüman kullanma"],ans:1,exp:"Saman Adam yanılgısı: Rakibin asıl iddiasını çarpıtarak daha kolay çürütülebilecek bir versiyonunu oluşturup ona saldırmaktır. Bu, dürüst tartışmayı engeller ve yanıltıcıdır."},
  {q:"Bir sınıfta 30 öğrencinin %40'ı kız. Kız öğrenci sayısı kaçtır?",opts:["10","12","14","15"],ans:1,exp:"30 × 0,40 = 12 kız öğrenci. Yüzde problemlerinde: Toplam × Oran = İstenen miktar formülü uygulanır."},
  {q:"'Ad hominem' yanılgısı ne anlama gelir?",opts:["Argümana değil, argümanı öne sürene saldırma","Çok fazla örnek verme","Konudan sapma","Otorite gösterme"],ans:0,exp:"Ad hominem (kişiye karşı): Argümanın içeriğini ele almak yerine argümanı öne süren kişiyi (karakterini, geçmişini vb.) hedef alarak argümanı çürütmeye çalışmaktır. Mantık tartışmalarında en yaygın yanılgılardan biridir."},
  {q:"A şehrinden B şehrine giden bir araç saatte 80 km, dönerken saatte 120 km gidiyor. Ortalama hız kaçtır?",opts:["96 km/s","100 km/s","104 km/s","110 km/s"],ans:0,exp:"Eşit mesafe için harmonik ortalama kullanılır: 2/(1/80+1/120) = 2/(3/240+2/240) = 2×240/5 = 96 km/s. Aritmetik ortalama (100) yanlış sonuç verir; eşit süre değil eşit mesafe söz konusu olduğunda harmonik ortalama uygulanır."},
  {q:"80km/s araç A→B, 120km/s araç B→A, mesafe 1000km. Karşılaşmadan sonra yavaş araç %25 hız artırırsa B'ye kaç saatte ulaşır? (2025 PAEM)",opts:["4","5","6","7"],ans:2,exp:"Karşılaşma: 400km gider, B'ye 600km kaldı. Yeni hız: 100km/s. Süre=600/100=6 saat."},
  {q:"4 yanlış=1 doğru götüren 40 soruda 25 doğru, başarı %60 ise kaç boş? (2025 PAEM)",opts:["8","9","10","11"],ans:3,exp:"Net=25-y/4=24 → y=4. Boş=40-25-4=11."},
  {q:"Her saatte 15dk geri kalan saat 08:00'da ayarlandı. 22:00'de kaçı gösterir? (2025 PAEM)",opts:["18:15","18:30","19:10","19:25"],ans:1,exp:"14 saat × 15dk = 210dk = 3s30dk kayıp. 22:00-3:30=18:30."}

  ,
  {q:"Bir sayı dizisinde: 2, 4, 8, 16, 32, ... bir sonraki sayı nedir?",opts:["48","56","64","72"],ans:2,exp:"Her sayı bir öncekinin 2 katıdır (geometrik dizi). 32 × 2 = 64."},
  {q:"Ali, Veli'den büyük. Veli, Ayşe'den küçük. Buna göre hangisi doğrudur?",opts:["Ali en büyüktür","Ayşe en büyüktür","Veli en büyüktür","Kesin bir sonuca varılamaz"],ans:1,exp:"Ali > Veli ve Veli < Ayşe → Ayşe > Veli ve Ali > Veli. Ayşe ile Ali arasındaki ilişki bilinmiyor; ancak 'Ayşe en büyüktür' seçeneği Ali > Veli ve Ayşe > Veli koşuluyla mümkün olan tek kesin çıkarımdır."},
  {q:"3 saatte 18 km yol alan bir araç, aynı hızla 5 saatte kaç km yol alır?",opts:["24 km","30 km","36 km","42 km"],ans:1,exp:"Hız = 18 ÷ 3 = 6 km/saat. 5 saatte: 6 × 5 = 30 km."},
  {q:"Bir sınıfta 30 öğrencinin %40'ı kız, kalanı erkektir. Erkek öğrenci sayısı kaçtır?",opts:["10","12","18","20"],ans:2,exp:"Kız sayısı: 30 × 0,40 = 12. Erkek sayısı: 30 - 12 = 18."},
  {q:"KPSS → LQTT, ABCD → ? (Her harf bir sonraki harfe kaydırılıyor)",opts:["BCDE","ABCE","BCDF","CDEG"],ans:0,exp:"Her harf alfabede bir sonraki harfe kaydırılır: A→B, B→C, C→D, D→E. Yani ABCD → BCDE."},
  {q:"Ahmet, Mehmet'in amcasının oğludur. Mehmet, Ahmet'in nesi olur?",opts:["Amcası","Yeğeni","Kuzeni","Kardeşi"],ans:2,exp:"Ahmet, Mehmet'in amcasının oğludur → Ahmet ve Mehmet birbirinin kuzenidir. Kuzen ilişkisi karşılıklıdır."},
  {q:"5 elemanlı bir kümenin kaç farklı 2 elemanlı alt kümesi vardır?",opts:["5","8","10","15"],ans:2,exp:"C(5,2) = 5! ÷ (2! × 3!) = (5 × 4) ÷ 2 = 10."},
  {q:"Bir depo 6 saatte doluyor, başka bir musluk aynı depoyu 3 saatte boşaltıyor. İkisi aynı anda çalışırsa depo ne zaman dolar?",opts:["Hiç dolmaz, sürekli boşalır","12 saatte","9 saatte","6 saatte"],ans:0,exp:"Doldurma hızı: 1/6 depo/saat. Boşaltma hızı: 1/3 depo/saat. Net: 1/6 - 1/3 = -1/6 → depo her saat 1/6 boşalıyor. Dolayısıyla depo hiç dolmaz, boşalmaya devam eder."},
  {q:"Tüm kediler hayvandır. Bazı hayvanlar uçar. Bu iki önermeye göre aşağıdakilerden hangisi kesinlikle doğrudur?",opts:["Bazı kediler uçar","Hiçbir kedi uçmaz","Tüm kediler hayvandır","Tüm hayvanlar kedidir"],ans:2,exp:"İlk önerme kesin: 'Tüm kediler hayvandır.' Diğer çıkarımlar verilmeyen bilgilerden yapılır. 'Bazı kediler uçar' mümkün ama kesin değil; 'hiçbir kedi uçmaz' da kesin değil."},
  {q:"3, 7, 13, 21, 31, ... dizisinde bir sonraki sayı nedir?",opts:["41","43","45","47"],ans:1,exp:"Farklar: 4, 6, 8, 10, ... (her seferinde 2 artıyor). 31 + 12 = 43."},
  {q:"Bir çanta 200 TL'ye alınıp %25 kâr ile satılıyor. Satış fiyatı kaçtır?",opts:["225 TL","240 TL","250 TL","260 TL"],ans:2,exp:"Kâr: 200 × 0,25 = 50 TL. Satış fiyatı: 200 + 50 = 250 TL."},
  {q:"'Tüm A'lar B'dir. Hiçbir B, C değildir.' Buna göre hangisi kesinlikle doğrudur?",opts:["Bazı A'lar C'dir","Hiçbir A, C değildir","Tüm C'ler A'dır","Bazı C'ler B'dir"],ans:1,exp:"Tüm A'lar B'dir + Hiçbir B, C değildir → Hiçbir A, C değildir. Bu zorunlu sonuçtur."},
  {q:"Bir işi 4 kişi 6 günde bitiriyor. Aynı işi 3 kişi kaç günde bitirir?",opts:["5 gün","7 gün","8 gün","9 gün"],ans:2,exp:"Toplam iş = 4 × 6 = 24 kişi-gün. 3 kişi için: 24 ÷ 3 = 8 gün."},
  {q:"Bir düzgün altıgenin iç açılarının toplamı kaç derecedir?",opts:["540°","600°","720°","900°"],ans:2,exp:"n kenarlı çokgenin iç açıları toplamı = (n-2) × 180°. Altıgen (n=6): (6-2) × 180 = 4 × 180 = 720°."},
  {q:"'Bazı polisler hakimdir. Tüm hakimler hukukçudur.' Buna göre hangisi kesinlikle doğrudur?",opts:["Tüm polisler hukukçudur","Bazı polisler hukukçudur","Hiçbir polis hukukçu değildir","Tüm hukukçular polisdir"],ans:1,exp:"'Bazı polisler hakimdir' + 'Tüm hakimler hukukçudur' → Hakim olan polisler aynı zamanda hukukçudur → 'Bazı polisler hukukçudur' kesin doğrudur."},
  // ── YAŞ PROBLEMLERİ ──
  {q:"Babanın yaşı oğlunun yaşının 4 katıdır. 6 yıl sonra baba, oğlunun 3 katı yaşında olacaktır. Oğlun şimdiki yaşı kaçtır?",opts:["6","8","10","12"],ans:3,exp:"Oğul=x, Baba=4x. 6 yıl sonra: 4x+6 = 3(x+6) → 4x+6 = 3x+18 → x=12. Kontrol: Baba=48; 48+6=54, 3×(12+6)=54 ✓."},
  {q:"Annenin yaşı kızının yaşının 3 katıdır. 8 yıl önce anne kızının 5 katı yaşındaydı. Annenin şimdiki yaşı kaçtır?",opts:["36","42","48","54"],ans:2,exp:"Kız=x, Anne=3x. 8 yıl önce: 3x-8 = 5(x-8) → 3x-8 = 5x-40 → 2x=32 → x=16. Anne = 3×16 = 48. Kontrol: 8 yıl önce anne=40, kız=8; 40=5×8 ✓."},
  {q:"Bir babanın yaşı oğlunun yaşının 3 katından 5 fazladır. 10 yıl sonra baba oğlunun 2 katı yaşında olacak. Oğlun şimdiki yaşı kaçtır?",opts:["5","8","10","12"],ans:0,exp:"Oğul=x, Baba=3x+5. 10 yıl sonra: 3x+15 = 2(x+10) → 3x+15 = 2x+20 → x=5. Kontrol: Baba=20; 10 yıl sonra baba=30, oğul=15; 30=2×15 ✓."},
  // ── KESİR VE ARDIŞIK SAYILAR ──
  {q:"Ardışık üç çift sayının toplamı 54'tür. En büyük sayı kaçtır?",opts:["16","18","20","22"],ans:2,exp:"Ardışık çift sayılar: n, n+2, n+4. Toplam: 3n+6=54 → 3n=48 → n=16. En büyük: n+4 = 16+4 = 20."},
  {q:"Ardışık üç tek sayının ortancası 15'tir. Bu sayıların çarpımı kaçtır?",opts:["2730","3315","3465","3640"],ans:1,exp:"Ortanca 15 ise sayılar: 13, 15, 17. Çarpım = 13 × 15 × 17 = 195 × 17 = 3315."},
  {q:"Bir sayının 2/5'i 24'tür. Bu sayının 3/4'ü kaçtır?",opts:["36","45","48","54"],ans:1,exp:"Sayı = 24 ÷ (2/5) = 24 × 5/2 = 60. Sayının 3/4'ü = 60 × 3/4 = 45."},
  {q:"Bir sınıfın 3/8'i kız, geri kalanı erkektir. Erkek sayısı kız sayısından 10 fazlaysa sınıfta kaç öğrenci vardır?",opts:["32","36","40","48"],ans:2,exp:"Kız = 3/8 × T, Erkek = 5/8 × T. Fark: 5/8T - 3/8T = 2T/8 = T/4 = 10 → T = 40."},
  // ── SAATLER VE TAKVİM ──
  {q:"Bir saat günde 4 dakika ileri gidiyor. Pazartesi 09:00'da doğru ayarlanan saat, Cuma 09:00'da kaçı gösterir?",opts:["09:12","09:16","09:20","09:24"],ans:1,exp:"Pazartesi'den Cuma'ya 4 gün geçer (Salı, Çarşamba, Perşembe, Cuma). Kazanç: 4 × 4 = 16 dakika. 09:00 + 16 dk = 09:16."},
  {q:"2 Mart bir Salı ise 2 Nisan aynı yılda hangi güne gelir?",opts:["Salı","Çarşamba","Perşembe","Cuma"],ans:3,exp:"Mart 31 gündür. 2 Mart'tan 2 Nisan'a 31 gün geçer. 31 = 4×7 + 3 → 3 gün ileri kayar. Salı + 3 = Cuma."},
  {q:"Saat 15:00'da saat ve dakika akrebi arasındaki açı kaç derecedir?",opts:["60°","90°","120°","180°"],ans:1,exp:"Saat akrebi her saat 30° hareket eder. 15:00'da saat akrebi 3 saatte 90°'de. Dakika akrebi tam 12'de = 0°. Aralarındaki açı = 90°."},
  // ── VENN / KÜME ──
  {q:"40 kişilik grupta 25 kişi Türkçe, 20 kişi İngilizce biliyor. Her iki dili de bilenler kaç kişidir?",opts:["3","5","7","9"],ans:1,exp:"|T ∪ İ| = |T| + |İ| - |T ∩ İ|. Tüm grup = 40, yani 40 = 25 + 20 - x → x = 5. Her iki dili bilen 5 kişidir."},
  {q:"60 kişilik sınıfta 35 kişi matematik, 28 kişi fizik seviyor. Her ikisini de seven 13 kişi ise hiçbirini sevmeyen kaç kişidir?",opts:["8","10","12","14"],ans:1,exp:"|M ∪ F| = 35 + 28 - 13 = 50. Hiçbirini sevmeyen = 60 - 50 = 10."},
  {q:"100 kişilik ankette A ürününü kullanan 60, B ürününü kullanan 45, her ikisini kullanan 20 kişidir. Hiçbirini kullanmayan kaç kişidir?",opts:["10","15","20","25"],ans:1,exp:"|A ∪ B| = 60 + 45 - 20 = 85. Hiçbirini kullanmayan = 100 - 85 = 15."},
  // ── HARF-SAYI KODLAMA ──
  {q:"A=1, B=2, ... Z=26 sisteminde MASA → 13-1-19-1 ise KALE → ?",opts:["11-1-12-5","10-1-11-4","12-2-13-6","11-2-12-6"],ans:0,exp:"Her harf sıra numarasına karşılık gelir: K=11, A=1, L=12, E=5. KALE → 11-1-12-5."},
  {q:"A=1, B=2, ... Z=26 sisteminde POLİS kelimesinin harf değerleri toplamı kaçtır?",opts:["67","71","75","79"],ans:1,exp:"P=16, O=15, L=12, I=9, S=19. Toplam = 16+15+12+9+19 = 71."},
  {q:"Bir şifreleme sisteminde A=2, B=4, C=6 ... (her harf sıra numarasının 2 katı). POLİS kelimesindeki harf değerleri toplamı kaçtır?",opts:["132","142","152","162"],ans:1,exp:"Latin alfabesinde: P=16→32, O=15→30, L=12→24, I=9→18, S=19→38. Toplam = 32+30+24+18+38 = 142."},
  // ── SAYMA VE OLASILIK ──
  {q:"4 farklı renkte boya ile 3 renk seçerek farklı sıralarda boyama yapılacak. Kaç farklı düzenleme mümkündür?",opts:["12","18","24","36"],ans:2,exp:"P(4,3) = 4! ÷ (4-3)! = 4×3×2 = 24. 4 renkten 3 tanesini sıralı seçme: 24 farklı düzenleme."},
  {q:"Bir zar iki kez atılıyor. Her iki atışta da çift sayı gelme olasılığı kaçtır?",opts:["1/2","1/3","1/4","1/6"],ans:2,exp:"Tek atışta çift (2,4,6) gelme olasılığı = 3/6 = 1/2. İki bağımsız atışta: 1/2 × 1/2 = 1/4."},
  {q:"5 kişilik komitede 3 erkek 2 kadın var. Başkan erkek, yardımcı kadın olacak şekilde kaç farklı seçim yapılabilir?",opts:["4","6","8","10"],ans:1,exp:"Başkan için 3 erkek, yardımcı için 2 kadın seçilir: 3 × 2 = 6 farklı kombinasyon."},
  {q:"Bir torba 3 kırmızı, 2 mavi top içeriyor. Rastgele çekilen 1 topun mavi olma olasılığı kaçtır?",opts:["1/5","2/5","3/5","1/2"],ans:1,exp:"Toplam top: 3+2=5. Mavi top sayısı: 2. P(mavi) = 2/5."},
  {q:"15 kişilik bir gruptan 2 kişilik bir komite kaç farklı şekilde oluşturulabilir?",opts:["90","105","120","210"],ans:1,exp:"C(15,2) = 15! ÷ (2! × 13!) = (15 × 14) ÷ 2 = 105. Sıra önemli olmadığı için kombinasyon kullanılır."},
  {q:"'Eğer hava yağmurlu ise şemsiye alırım. Şemsiye almadım.' Bu çıkarımın sonucu nedir?",opts:["Hava yağmurludur","Hava yağmurlu değildir","Şemsiye almak zorunda değildim","Hiçbir sonuç çıkarılamaz"],ans:1,exp:"Modus tollens: 'Eğer P ise Q. Q değil → P değil.' Şemsiye almadım (Q değil) → Hava yağmurlu değil (P değil). Geçerli bir mantıksal çıkarımdır."}],
};

// ════════════════════════════════════════════════
//  FLASH KARTLAR
// ════════════════════════════════════════════════